      )}

      {showPasswordInput && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center bg-slate-900/60 backdrop-blur-md p-4">
           <div className="bg-white w-full max-w-sm p-8 rounded-3xl border border-slate-200 shadow-2xl animate-in zoom-in duration-200">
              <h4 className="text-sm font-black text-slate-800 uppercase tracking-tighter mb-4">Secure Batch Entry</h4>
              <p className="text-[10px] font-medium text-slate-400 uppercase tracking-widest mb-6">Processing {pendingFiles.length} file(s). Enter PDF Password if applicable.</p>
              <input type="password" autoFocus className="w-full p-4 bg-slate-50 border border-slate-200 rounded-xl outline-none font-black text-lg mb-6" value={pdfPassword} onChange={e => setPdfPassword(e.target.value)} onKeyPress={e => e.key === 'Enter' && startAIParsing()} />
              <div className="flex gap-3">
                 <button onClick={() => { setShowPasswordInput(false); setPendingFiles([]); }} className="flex-1 py-4 bg-slate-100 text-slate-500 font-black text-[10px] uppercase rounded-xl">Cancel</button>
                 <button onClick={startAIParsing} className="flex-[2] py-4 bg-indigo-600 text-white font-black text-[10px] uppercase rounded-xl shadow-lg">Run Analysis</button>
              </div>
           </div>
        </div>
      )}

      {isScanning && (
        <div className="fixed inset-0 z-[70] flex flex-col items-center justify-center bg-indigo-900/95 backdrop-blur-3xl text-white">
           <div className="w-24 h-24 border-4 border-indigo-400/30 border-t-indigo-400 rounded-full animate-spin mb-10"></div>
           <h2 className="text-2xl font-black tracking-tighter uppercase mb-2">Full Document Audit</h2>
           <p className="text-[10px] font-black text-indigo-300 uppercase tracking-[0.3em]">Examing every page of {pendingFiles.length} document(s)...</p>
           <p className="text-[8px] mt-4 opacity-50 uppercase tracking-widest">Estimated time: {scanTimeLeft}s</p>
        </div>
      )}

      {confirmDeleteTx && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/60 backdrop-blur-sm p-4">
           <div className="bg-white w-full max-w-sm rounded-[2rem] p-8 border border-slate-200 shadow-2xl animate-in zoom-in duration-200">
             <div className="text-center mb-8">
               <div className="w-16 h-16 bg-rose-50 text-rose-500 rounded-full flex items-center justify-center text-3xl mx-auto mb-6">⚠️</div>
               <h4 className="text-lg font-black text-slate-800 uppercase tracking-tighter">Purge Record?</h4>
               <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mt-2">This action is irreversible and affects capital calculation</p>
             </div>
             <div className="flex gap-3">
               <button onClick={() => setConfirmDeleteTx(null)} className="flex-1 py-4 bg-slate-100 text-slate-600 font-bold text-[10px] uppercase rounded-2xl">Cancel</button>
               <button onClick={() => { deleteTransaction(confirmDeleteTx.id); setConfirmDeleteTx(null); }} className="flex-[2] py-4 bg-rose-600 text-white font-black text-[10px] uppercase rounded-2xl shadow-xl shadow-rose-100">Delete Permanently</button>
             </div>
           </div>
        </div>
      )}
    </div>
  );
};

export default Transactions;

import React, { useState, useMemo } from 'react';
import { useFinance } from '../store/FinanceContext';
import { calculateNetWorth } from '../utils/calculations';
import { formatCurrency } from '../utils/formatters';
import { AccountClassification } from '../types';
import { TransactionHistoryModal } from './Accounts';

type Period = 'current_month' | 'last_90_days' | 'ytd' | 'all_time' | 'custom';

interface HoldingItem {
  isin: string;
  name: string;
  value: number;
  units: number;
  count: number;
}

const Statements: React.FC = () => {
  const { state, filteredState, activeMemberIds } = useFinance();
  const [activePeriod, setActivePeriod] = useState<Period>('all_time');

  // Custom Date States for Calendar Selection
  const [customStart, setCustomStart] = useState(new Date(new Date().getFullYear(), new Date().getMonth(), 1).toISOString().split('T')[0]);
  const [customEnd, setCustomEnd] = useState(new Date().toISOString().split('T')[0]);

  const [expandedHeads, setExpandedHeads] = useState<string[]>(['Current Asset', 'Equity']);
  const [expandedHoldings, setExpandedHoldings] = useState<string[]>([]);
  const [selectedAccountForHistory, setSelectedAccountForHistory] = useState<any>(null);
  const currency = filteredState.profile.currency;

  const filteredTransactions = useMemo(() => {
    const txs = filteredState.transactions || [];
    const now = new Date();

    if (activePeriod === 'current_month') {
      const start = new Date(now.getFullYear(), now.getMonth(), 1);
      return txs.filter(t => new Date(t.date) >= start);
    }
    if (activePeriod === 'last_90_days') {
      const start = new Date();
      start.setDate(now.getDate() - 90);
      return txs.filter(t => new Date(t.date) >= start);
    }
    if (activePeriod === 'ytd') {
      const start = new Date(now.getFullYear(), 0, 1);
      return txs.filter(t => new Date(t.date) >= start);
    }
    if (activePeriod === 'custom') {
      const start = new Date(customStart);
      const end = new Date(customEnd);
      end.setHours(23, 59, 59, 999);
      return txs.filter(t => {
        const d = new Date(t.date);
        return d >= start && d <= end;
      });
    }
    return txs;
  }, [filteredState.transactions, activePeriod, customStart, customEnd]);

  const periodIncome = filteredTransactions.filter(t => t.type === 'Income').reduce((acc, t) => acc + t.amount, 0);
  const periodExpense = filteredTransactions.filter(t => t.type === 'Expense').reduce((acc, t) => acc + t.amount, 0);
  const netSurplus = periodIncome - periodExpense;

  const { netWorth } = calculateNetWorth(filteredState);

  const isAllView = activeMemberIds.includes('all');
  const isMeView = activeMemberIds.length === 0;
  const isConsolidatedView = isAllView || activeMemberIds.length > 1;

  const capitalDisplay = isAllView ? state.capital : (isMeView ? state.capital : 0);
  const retainedEarnings = netWorth - capitalDisplay;

  // Balance Sheet Data Structuring with Auto-Reclassification and Stock Clubbing
  const heads = useMemo(() => {
    const data: Record<AccountClassification, { total: number, items: { id: string, name: string, value: number, source: string, originalAccount?: any, details?: string, holdings?: HoldingItem[] }[] }> = {
      'Current Asset': { total: 0, items: [] },
      'Non-Current Asset': { total: 0, items: [] },
      'Current Liability': { total: 0, items: [] },
      'Non-Current Liability': { total: 0, items: [] },
      'Equity': { total: 0, items: [] }
    };

    const now = new Date();

    // Intermediate storage for stocks to club them by ISIN
    const stocksByClassification: Record<string, Record<string, HoldingItem>> = {
      'Current Asset': {},
      'Non-Current Asset': {}
    };

    const processAccount = (id: string, name: string, balance: number, classification: AccountClassification, source: string, originalAccount: any) => {
      let cls = classification;
      let val = balance;
      const isAssetType = cls === 'Current Asset' || cls === 'Non-Current Asset';
      const isLiabilityType = cls === 'Current Liability' || cls === 'Non-Current Liability';

      // Find purchase date for assets to classify Current vs Non-Current
      let entryDate = now;
      const tx = state.transactions.find(t => t.id === id);
      if (tx) {
        entryDate = new Date(tx.date);
      }

      if (isAssetType && source !== 'Bank' && source !== 'Wallet') {
        const diffTime = Math.abs(now.getTime() - entryDate.getTime());
        const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
        cls = diffDays > 365 ? 'Non-Current Asset' : 'Current Asset';
      }

      if (val < 0 && isAssetType) {
        cls = 'Current Liability';
        val = Math.abs(val);
      } else if (val < 0 && isLiabilityType) {
        cls = 'Current Asset';
        val = Math.abs(val);
      }

      // Logic to club stock investments
      const isStock = tx && tx.nature === 'Investment in stocks';
      if (isStock && (cls === 'Current Asset' || cls === 'Non-Current Asset')) {
        const key = tx.isin || tx.stockName || tx.description || 'Unknown';
        if (!stocksByClassification[cls][key]) {
          stocksByClassification[cls][key] = {
            isin: tx.isin || '',
            name: tx.stockName || tx.description,
            value: 0,
            units: 0,
            count: 0
          };
        }
        stocksByClassification[cls][key].value += val;
        stocksByClassification[cls][key].units += (tx.units || 0);
        stocksByClassification[cls][key].count += 1;
      } else {
        data[cls].total += val;
        data[cls].items.push({ id, name, value: val, source, originalAccount });
      }
    };

    filteredState.banks.forEach(b => processAccount(b.id, b.name, b.balance, b.classification || 'Current Asset', 'Bank', b));
    filteredState.wallets.forEach(w => processAccount(w.id, w.name, w.balance, w.classification || 'Current Asset', 'Wallet', w));
    filteredState.cards.forEach(c => processAccount(c.id, c.lenderName, c.balance, c.classification || 'Current Liability', 'Credit', c));
    filteredState.assets.forEach(a => processAccount(a.id, a.name, a.value, a.classification || (a.type === 'Receivable' ? 'Current Asset' : 'Non-Current Asset'), 'Manual Asset', a));
    filteredState.liabilities.forEach(l => processAccount(l.id, l.name, l.amount, l.classification || (l.type === 'Payable' ? 'Current Liability' : 'Non-Current Liability'), 'Manual Debt', l));

    // Add clubbed stocks to the final data
    (['Current Asset', 'Non-Current Asset'] as const).forEach(cls => {
      const holdingsList = Object.values(stocksByClassification[cls]);
      if (holdingsList.length > 0) {
        const totalValue = holdingsList.reduce((acc, h) => acc + h.value, 0);
        const totalUnits = holdingsList.reduce((acc, h) => acc + h.units, 0);
        const totalTrades = holdingsList.reduce((acc, h) => acc + h.count, 0);

        data[cls].total += totalValue;
        data[cls].items.push({ 
          id: `clubbed_stocks_${cls}`, 
          name: 'Equity Investments', 
          value: totalValue, 
          source: 'Brokerage',
          details: `${totalUnits.toLocaleString()} Shares across ${totalTrades} trades`,
          holdings: holdingsList
        });
      }
    });

    data['Equity'].total = capitalDisplay + retainedEarnings;
    data['Equity'].items.push({ id: 'owner_cap', name: 'Owner Capital', value: capitalDisplay, source: 'Equity' });
    data['Equity'].items.push({ id: 'retained_earning', name: 'Retained Earnings', value: retainedEarnings, source: 'Equity' });

    return data;
  }, [filteredState, state.transactions, capitalDisplay, retainedEarnings]);

  const toggleHead = (head: string) => {
    setExpandedHeads(prev => prev.includes(head) ? prev.filter(h => h !== head) : [...prev, head]);
  };

  const toggleHoldings = (id: string) => {
    setExpandedHoldings(prev => prev.includes(id) ? prev.filter(h => h !== id) : [...prev, id]);
  };

  const totalAssetsValue = heads['Current Asset'].total + heads['Non-Current Asset'].total;
  const totalLiabilitiesAndEquityValue = heads['Current Liability'].total + heads['Non-Current Liability'].total + heads['Equity'].total;
  const liquidityRatio = heads['Current Liability'].total > 0 ? (heads['Current Asset'].total / heads['Current Liability'].total).toFixed(2) : '∞';

  const assetHeader = isMeView ? "Total Assets" : (isConsolidatedView ? "Consolidated Assets" : "Assigned Assets");
  const liabilityHeader = isMeView ? "Total Equity and Liabilities" : (isConsolidatedView ? "Consolidated Equity and Liabilities" : "Total Claims & Equity");

  return (
    <div className="space-y-8 md:space-y-12 animate-in fade-in duration-700 pb-20 -mx-3 md:mx-0">
      {/* Header & Period Selection */}
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-end gap-6 px-4 md:px-0">
        <div>
          <div className="flex items-center gap-3 mb-1">
            <h2 className="text-xl md:text-3xl font-black text-slate-800 tracking-tight uppercase">Audit Statements</h2>
            <span className="px-2 py-0.5 bg-indigo-50 text-indigo-600 text-[8px] md:text-[10px] font-black rounded uppercase tracking-widest border border-indigo-100">Live Reports</span>
          </div>
          <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">
            {isMeView ? 'Personal Position (Mine)' : isConsolidatedView ? 'Consolidated Family View' : 'Partial Selection'}
          </p>
        </div>

        <div className="flex flex-col md:flex-row items-stretch md:items-center gap-4 w-full md:w-auto">
          {activePeriod === 'custom' && (
            <div className="flex items-center gap-2 bg-white p-2 border border-slate-200 rounded-2xl shadow-sm animate-in slide-in-from-right-4">
              <input type="date" value={customStart} onChange={e => setCustomStart(e.target.value)} className="bg-transparent border-0 text-[10px] font-black uppercase outline-none" />
              <span className="text-[10px] font-black text-slate-300 px-1">➜</span>
              <input type="date" value={customEnd} onChange={e => setCustomEnd(e.target.value)} className="bg-transparent border-0 text-[10px] font-black uppercase outline-none" />
            </div>
          )}
          <div className="flex flex-wrap items-center gap-1 bg-white p-1 border border-slate-200 rounded-full shadow-sm">
            {[
              { id: 'current_month', label: 'Month' },
              { id: 'last_90_days', label: 'Quarter' },
              { id: 'ytd', label: 'YTD' },
              { id: 'all_time', label: 'All' },
              { id: 'custom', label: '📅' }
            ].map(p => (
              <button
                key={p.id}
                onClick={() => setActivePeriod(p.id as Period)}
                className={`px-4 py-1.5 rounded-full text-[9px] md:text-xs font-black uppercase transition-all ${
                  activePeriod === p.id ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:text-slate-800'
                }`}
              >
                {p.label}
              </button>
            ))}
          </div>
        </div>
      </div>

      {/* P&L Account */}
      <section className="bg-white border-y md:border md:rounded-[2.5rem] border-slate-200 overflow-hidden shadow-sm">
        <div className="bg-slate-900 px-6 md:px-10 py-10 md:py-12 text-white">
          <div className="flex flex-col md:flex-row justify-between items-center gap-8">
            <div className="text-center md:text-left">
              <h3 className="text-sm md:text-lg font-black tracking-widest uppercase mb-1">Profit & Loss Account</h3>
              <p className="text-slate-500 text-[9px] font-black uppercase tracking-widest italic">Performance Summary for Period</p>
            </div>
            <div className="text-center md:text-right">
              <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1">Net Flow Balance</p>
              <p className={`text-4xl md:text-6xl font-black tracking-tighter ${netSurplus >= 0 ? 'text-emerald-400' : 'text-rose-400'}`}>
                {formatCurrency(netSurplus, currency)}
              </p>
            </div>
          </div>

          <div className="grid grid-cols-2 gap-8 mt-12 pt-10 border-t border-white/10">
            <div className="text-center md:text-left">
              <p className="text-[9px] font-black text-slate-500 uppercase tracking-widest mb-2">Total Income (Inflow)</p>
              <p className="text-2xl font-black text-emerald-400">{formatCurrency(periodIncome, currency)}</p>
            </div>
            <div className="text-center md:text-right">
              <p className="text-[9px] font-black text-slate-500 uppercase tracking-widest mb-2">Total Expense (Outflow)</p>
              <p className="text-2xl font-black text-rose-400">{formatCurrency(periodExpense, currency)}</p>
            </div>
          </div>
        </div>
      </section>

      {/* Balance Sheet */}
      <section className="bg-white border-y md:border md:rounded-[2.5rem] border-slate-200 overflow-hidden shadow-sm">
        <div className="bg-slate-50 px-6 md:px-10 py-10 text-slate-800 border-b border-slate-200">
          <div className="flex flex-col md:flex-row justify-between items-center gap-6">
            <div className="text-center md:text-left">
              <h3 className="text-sm md:text-lg font-black tracking-widest uppercase mb-1">Balance Sheet</h3>
              <p className="text-slate-400 text-[10px] font-black uppercase tracking-widest">Financial Health Snapshot</p>
            </div>
            <div className="text-center md:text-right">
              <div className="flex items-center justify-center md:justify-end gap-3 mb-2">
                  <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Current Ratio</span>
                  <span className={`px-2 py-1 rounded text-[10px] font-black ${Number(liquidityRatio) > 1.2 ? 'bg-emerald-100 text-emerald-600' : 'bg-rose-100 text-rose-600'}`}>{liquidityRatio}</span>
              </div>
              <p className="text-4xl md:text-6xl font-black tracking-tighter text-indigo-600">{formatCurrency(netWorth, currency)}</p>
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-2">{isMeView ? 'Personal Net Worth' : 'Consolidated Net Worth'}</p>
            </div>
          </div>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-2 divide-y lg:divide-y-0 lg:divide-x divide-slate-100">
          {/* ASSETS */}
          <div className="p-6 md:p-12 space-y-8">
            <div className="flex justify-between items-center mb-4">
              <h4 className="text-xs font-black text-slate-800 uppercase tracking-widest">{assetHeader}</h4>
              <span className="text-[10px] font-black text-indigo-600 bg-indigo-50 px-3 py-1 rounded-full">TOTAL: {formatCurrency(totalAssetsValue, currency)}</span>
            </div>

            <div className="space-y-4">
              {(['Current Asset', 'Non-Current Asset'] as const).map(head => (
                <div key={head} className="border border-slate-100 rounded-3xl overflow-hidden bg-white shadow-sm transition-all duration-300">
                  <button onClick={() => toggleHead(head)} className="w-full flex justify-between items-center p-6 hover:bg-slate-50 transition-colors">
                    <div className="flex items-center gap-3">
                      <div className={`w-2 h-2 rounded-full ${head === 'Current Asset' ? 'bg-indigo-600' : 'bg-slate-400'}`}></div>
                      <span className="text-[11px] font-black text-slate-800 uppercase tracking-widest">{head}</span>
                    </div>
                    <div className="flex items-center gap-4">
                      <span className="text-xs font-black text-slate-800">{formatCurrency(heads[head].total, currency)}</span>
                      <span className={`text-[10px] transition-transform duration-300 ${expandedHeads.includes(head) ? 'rotate-180' : ''}`}>▼</span>
                    </div>
                  </button>
                  {expandedHeads.includes(head) && (
                    <div className="px-6 pb-6 pt-2 space-y-1 bg-slate-50/40">
                      {heads[head].items.map((item) => (
                        <React.Fragment key={item.id}>
                          <button 
                            onClick={() => {
                              if (item.holdings) toggleHoldings(item.id);
                              else if (item.originalAccount) setSelectedAccountForHistory(item.originalAccount);
                            }} 
                            className={`w-full flex justify-between items-center p-3.5 rounded-xl transition-all border border-transparent ${item.originalAccount || item.holdings ? 'hover:bg-white hover:border-slate-200 hover:shadow-sm cursor-pointer' : 'cursor-default'}`}
                          >
                            <div className="text-left flex items-center gap-2">
                              {item.holdings && (
                                <span className={`text-[8px] transition-transform ${expandedHoldings.includes(item.id) ? 'rotate-180' : 'rotate-90'}`}>▲</span>
                              )}
                              <div>
                                <p className="text-[11px] font-bold text-slate-800 uppercase">
                                  {item.name}
                                  {item.holdings && <span className="ml-2 text-[8px] text-indigo-400 font-black tracking-tighter">(DRILLED DOWN)</span>}
                                </p>
                                <p className="text-[8px] font-black text-slate-300 uppercase tracking-widest">
                                    {item.details ? item.details : item.source}
                                </p>
                              </div>
                            </div>
                            <span className="text-[11px] font-black text-slate-600">{formatCurrency(item.value, currency)}</span>
                          </button>

                          {/* DRILL DOWN CONTENT */}
                          {item.holdings && expandedHoldings.includes(item.id) && (
                            <div className="ml-6 space-y-1 border-l-2 border-indigo-100 pl-4 py-2 animate-in slide-in-from-top-2">
                              {item.holdings.map((holding, hIdx) => (
                                <div key={hIdx} className="flex justify-between items-center p-3 bg-indigo-50/20 border border-indigo-50 rounded-xl">
                                  <div>
                                    <p className="text-[10px] font-black text-slate-700 uppercase leading-none">{holding.name}</p>
                                    <div className="flex items-center gap-2 mt-1">
                                      <span className="text-[7px] font-black text-indigo-400 uppercase tracking-widest">{holding.isin}</span>
                                      <span className="w-1 h-1 bg-slate-200 rounded-full"></span>
                                      <span className="text-[7px] font-black text-slate-400 uppercase">{holding.units.toLocaleString()} Units</span>
                                    </div>
                                  </div>
                                  <span className="text-[10px] font-black text-slate-600">{formatCurrency(holding.value, currency)}</span>
                                </div>
                              ))}
                            </div>
                          )}
                        </React.Fragment>
                      ))}
                    </div>
                  )}
                </div>
              ))}
            </div>

            <div className="p-8 bg-slate-50 rounded-[2rem] border border-dashed border-slate-200 flex justify-between items-center mt-12">
               <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Aggregate Assets</p>
               <p className="text-2xl font-black text-slate-800 tracking-tighter">{formatCurrency(totalAssetsValue, currency)}</p>
            </div>
          </div>

          {/* LIABILITIES & EQUITY */}
          <div className="p-6 md:p-12 space-y-8 bg-slate-50/10">
            <div className="flex justify-between items-center mb-4">
              <h4 className="text-xs font-black text-slate-800 uppercase tracking-widest">{liabilityHeader}</h4>
              <span className="text-[10px] font-black text-rose-600 bg-rose-50 px-3 py-1 rounded-full">TOTAL: {formatCurrency(totalLiabilitiesAndEquityValue, currency)}</span>
            </div>

            <div className="space-y-4">
              {(['Current Liability', 'Non-Current Liability', 'Equity'] as const).map(head => (
                <div key={head} className="border border-slate-100 rounded-3xl overflow-hidden bg-white shadow-sm transition-all duration-300">
                  <button onClick={() => toggleHead(head)} className="w-full flex justify-between items-center p-6 hover:bg-slate-50 transition-colors">
                    <div className="flex items-center gap-3">
                      <div className={`w-2 h-2 rounded-full ${head === 'Equity' ? 'bg-emerald-500' : 'bg-rose-400'}`}></div>
                      <span className="text-[11px] font-black text-slate-800 uppercase tracking-widest">{head}</span>
                    </div>
                    <div className="flex items-center gap-4">
                      <span className="text-xs font-black text-slate-800">{formatCurrency(heads[head].total, currency)}</span>
                      <span className={`text-[10px] transition-transform duration-300 ${expandedHeads.includes(head) ? 'rotate-180' : ''}`}>▼</span>
                    </div>
                  </button>
                  {expandedHeads.includes(head) && (
                    <div className="px-6 pb-6 pt-2 space-y-1 bg-slate-50/40">
                      {heads[head].items.map((item) => (
                        <button key={item.id} onClick={() => item.originalAccount && setSelectedAccountForHistory(item.originalAccount)} className={`w-full flex justify-between items-center p-3.5 rounded-xl transition-all border border-transparent ${item.originalAccount ? 'hover:bg-white hover:border-slate-200 hover:shadow-sm cursor-pointer' : 'cursor-default'}`}>
                          <div className="text-left">
                            <p className="text-[11px] font-bold text-slate-800 uppercase">{item.name}</p>
                            <p className="text-[8px] font-black text-slate-300 uppercase tracking-widest">{item.source}</p>
                          </div>
                          <span className="text-[11px] font-black text-slate-600">{formatCurrency(item.value, currency)}</span>
                        </button>
                      ))}
                    </div>
                  )}
                </div>
              ))}
            </div>

            <div className="p-8 bg-slate-900 rounded-[2rem] shadow-xl flex justify-between items-center mt-12 text-white">
               <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Aggregate Liabilities & Equity</p>
               <p className="text-2xl font-black text-white tracking-tighter">{formatCurrency(totalLiabilitiesAndEquityValue, currency)}</p>
            </div>
          </div>
        </div>
      </section>

      {/* Audit Modal */}
      {selectedAccountForHistory && (
        <TransactionHistoryModal 
          account={selectedAccountForHistory} 
          currency={currency} 
          onClose={() => setSelectedAccountForHistory(null)} 
        />
      )}
    </div>
  );
};

export default Statements;

import { GoogleGenAI, Type } from "@google/genai";
import React, { useEffect, useMemo, useRef, useState } from 'react';
import * as XLSX from 'xlsx';
import { useFinance } from '../store/FinanceContext';
import { Transaction, TransactionType } from '../types';
import { formatCurrency } from '../utils/formatters';

type SplitType = 'equal' | 'exact' | 'percentage' | 'shares';

interface Participant {
  id: string; 
  name: string;
  mobile: string;
  value: string; 
  result: number; 
  isSelf: boolean;
}

interface ExtractedTrade {
  scrip: string;
  type: 'BUY' | 'SELL';
  grossValue: number;
  netTotal: number;
  units: number;
  date: string;
  isin: string;
  stt: number;
  allocatedCharges: number;
}

const Transactions: React.FC = () => {
  const { filteredState, state, addTransaction, updateTransaction, deleteTransaction, addTransactionNature, addWallet } = useFinance();
  const familyMembers = state.profile?.familyMembers || [];
  const natures = state.transactionNatures || [];
  const [showModal, setShowModal] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [confirmDeleteTx, setConfirmDeleteTx] = useState<Transaction | null>(null);
  const [isScanning, setIsScanning] = useState(false);
  const [isIsinResolving, setIsIsinResolving] = useState(false);
  const [scanTimeLeft, setScanTimeLeft] = useState(25);
  const [pdfPassword, setPdfPassword] = useState('');
  const [showPasswordInput, setShowPasswordInput] = useState(false);
  const [pendingFiles, setPendingFiles] = useState<File[]>([]);
  const [importOwnerId, setImportOwnerId] = useState<string>('');
  const [importAccountId, setImportAccountId] = useState<string>('');

  const [scanResult, setScanResult] = useState<{ 
    date: string; 
    trades: ExtractedTrade[];
    otherCharges: number;
  } | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const currency = state.profile.currency;

  const initialFormState = {
    type: 'Expense' as TransactionType,
    amount: '', 
    nature: natures[0] || '',
    description: '',
    accountId: '',
    date: new Date().toISOString().split('T')[0],
    isShared: false,
    includeSelf: true,
    numberOfPeople: 2,
    splitType: 'equal' as SplitType,
    participants: [] as Participant[],
    ownerId: '',
    isin: '',
    stockName: '',
    units: '',
    billingPeriod: ''
  };

  const [formData, setFormData] = useState(initialFormState);

  const allAccounts = useMemo(() => {
    const banks = (state.banks || []).map(b => ({ id: b.id, name: b.name, type: 'bank' as const, ownerId: b.ownerId }));
    const cards = (state.cards || []).map(c => ({ id: c.id, name: c.lenderName, type: 'card' as const, ownerId: c.ownerId }));
    const liabilities = (state.liabilities || []).filter(l => l.type === 'Debt').map(l => ({ id: l.id, name: l.name, type: 'liability' as const, ownerId: l.ownerId }));
    const wallets = (state.wallets || []).map(w => ({ id: w.id, name: w.name, type: 'wallet' as const, ownerId: w.ownerId }));
    return [...banks, ...cards, ...wallets, ...liabilities];
  }, [state.banks, state.cards, state.wallets, state.liabilities]);

  // Set default account for import whenever scan result or owner changes
  useEffect(() => {
    if (scanResult) {
      const zerodha = allAccounts.find(a => a.name.toLowerCase().includes('zerodha') && (a.ownerId === importOwnerId || !a.ownerId));
      if (zerodha) {
        setImportAccountId(zerodha.id);
      } else {
        const firstBank = allAccounts.find(a => a.type === 'bank' && (a.ownerId === importOwnerId || !a.ownerId));
        if (firstBank) setImportAccountId(firstBank.id);
      }
    }
  }, [scanResult, importOwnerId, allAccounts]);

  useEffect(() => {
    if (!natures.includes('Investment in stocks')) {
      addTransactionNature('Investment in stocks');
    }
    if (!natures.includes('Other Charges')) {
      addTransactionNature('Other Charges');
    }
    const zerodhaExists = allAccounts.some(a => a.name.toLowerCase().includes('zerodha'));
    if (!zerodhaExists) {
      addWallet({
        id: 'zerodha-account-auto',
        name: 'Zerodha',
        balance: 0,
        ownerId: ''
      });
    }
  }, [allAccounts]);

  const handleIsinLookup = async (isin: string) => {
    setIsIsinResolving(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Identify the security/stock name for the following ISIN identifier: ${isin}. Return ONLY the official short name of the security. No preamble.`
      });
      const resolvedName = response.text?.trim() || 'Unknown Security';
      setFormData(prev => ({ 
        ...prev, 
        stockName: resolvedName,
        description: prev.description || resolvedName
      }));
    } catch (err) {
      console.error("ISIN Resolution failed:", err);
    } finally {
      setIsIsinResolving(false);
    }
  };

  useEffect(() => {
    const timer = setTimeout(() => {
      if (formData.isin && formData.isin.length === 12 && !formData.stockName) {
        handleIsinLookup(formData.isin);
      }
    }, 500);
    return () => clearTimeout(timer);
  }, [formData.isin]);

  const downloadExcelTemplate = () => {
    const headers = [
      "ISIN", "Date of transaction", "Quantity", "Buy/Sell", "Total Buy/Sell Value", "Total Charges excluding STT", "STT", "Net Payable/ Receivable"
    ];
    const data = [
      headers,
      ["INE002A01018", new Date().toISOString().split('T')[0], 10, "BUY", 10000, 20, 10.5, -10030.5],
      ["INE002A01018", new Date().toISOString().split('T')[0], 5, "SELL", -5500, 15, 5.25, 5479.75]
    ];
    const ws = XLSX.utils.aoa_to_sheet(data);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Import_Template");
    XLSX.writeFile(wb, "MyFin_Broker_Import_Template.xlsx");
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(e.target.files || []) as File[];
    if (files.length === 0) return;

    const excelFiles = files.filter(f => f.name.endsWith('.xlsx') || f.name.endsWith('.xls'));
    const docFiles = files.filter(f => !f.name.endsWith('.xlsx') && !f.name.endsWith('.xls'));

    if (excelFiles.length > 0) {
      handleExcelImport(excelFiles[0]);
    }

    if (docFiles.length > 0) {
      setPendingFiles(docFiles);
      setShowPasswordInput(true);
    }

    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const handleExcelImport = (file: File) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const data = new Uint8Array(e.target?.result as ArrayBuffer);
        const workbook = XLSX.read(data, { type: 'array', cellDates: true });
        const firstSheetName = workbook.SheetNames[0];
        const worksheet = workbook.Sheets[firstSheetName];
        const rows: any[] = XLSX.utils.sheet_to_json(worksheet);

        if (rows.length === 0) {
          alert("Excel file is empty.");
          return;
        }

        let totalOtherCharges = 0;
        let totalGrossValueAbs = 0;
        let lastDate = new Date().toISOString().split('T')[0];

        const cleanedRows = rows.map(r => {
          const newRow: any = {};
          Object.keys(r).forEach(k => newRow[k.trim()] = r[k]);
          return newRow;
        });

        cleanedRows.forEach((row: any) => {
          const grossValue = Math.abs(Number(row['Total Buy/Sell Value'] || 0));
          const chargesExclSTT = Math.abs(Number(row['Total Charges excluding STT'] || 0));
          totalOtherCharges += chargesExclSTT;
          totalGrossValueAbs += grossValue;
        });

        const trades: ExtractedTrade[] = [];
        cleanedRows.forEach((row: any) => {
          const isin = row['ISIN'] || 'UNKNOWN_ISIN';
          let txDateRaw = row['Date of transaction'];
          let formattedDate = lastDate;
          if (txDateRaw) {
            const d = new Date(txDateRaw);
            if (!isNaN(d.getTime())) formattedDate = d.toISOString().split('T')[0];
          }
          lastDate = formattedDate;

          const qty = Number(row['Quantity'] || 0);
          const type = String(row['Buy/Sell'] || 'BUY').toUpperCase();
          const grossValue = Math.abs(Number(row['Total Buy/Sell Value'] || 0));
          const stt = Math.abs(Number(row['STT'] || 0));
          const netSettlement = Number(row['Net Payable/ Receivable'] || 0);

          const proportion = totalGrossValueAbs > 0 ? (grossValue / totalGrossValueAbs) : 0;
          const allocatedOtherCharges = proportion * totalOtherCharges;
          const finalCostBasis = Math.abs(netSettlement) || (grossValue + stt + allocatedOtherCharges);

          trades.push({
            scrip: isin, 
            type: type === 'BUY' ? 'BUY' : 'SELL',
            grossValue: grossValue,
            netTotal: finalCostBasis,
            units: qty,
            date: formattedDate,
            isin: isin,
            stt: stt,
            allocatedCharges: allocatedOtherCharges
          });
        });

        setScanResult({ date: lastDate, trades, otherCharges: totalOtherCharges });
      } catch (err) {
        console.error(err);
        alert("Failed to parse Excel file.");
      }
    };
    reader.readAsArrayBuffer(file);
  };

  const startAIParsing = async () => {
    if (pendingFiles.length === 0) return;
    setShowPasswordInput(false);
    setIsScanning(true);
    setScanTimeLeft(30);

    try {
      const fileParts = await Promise.all(pendingFiles.map(async (file) => {
        return new Promise<any>((resolve) => {
          const reader = new FileReader();
          reader.onloadend = () => {
            const base64Data = (reader.result as string).split(',')[1];
            resolve({ inlineData: { data: base64Data, mimeType: file.type } });
          };
          reader.readAsDataURL(file);
        });
      }));

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const responseSchema = {
        type: Type.OBJECT,
        properties: {
          date: { type: Type.STRING, description: "The settlement date or document date in YYYY-MM-DD format." },
          otherCharges: { type: Type.NUMBER, description: "Total sum of all brokerage, exchange fees, and other charges across all pages, excluding STT." },
          trades: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                isin: { type: Type.STRING, description: "12-character ISIN." },
                scrip: { type: Type.STRING, description: "Name of security." },
                type: { type: Type.STRING, description: "BUY or SELL" },
                units: { type: Type.NUMBER, description: "Quantity of shares." },
                grossValue: { type: Type.NUMBER, description: "Gross amount before charges." },
                stt: { type: Type.NUMBER, description: "Securities Transaction Tax for this trade." },
                netSettlement: { type: Type.NUMBER, description: "Final net amount for this specific trade line." }
              },
              required: ["isin", "type", "units", "grossValue", "netSettlement"]
            }
          }
        },
        required: ["date", "trades", "otherCharges"]
      };

      const response = await ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: {
          parts: [
            ...fileParts,
            { text: `CRITICAL: You are an expert forensic accountant. Analyze the provided Broker Contract Note / Portfolio Ledger.

            This document contains ${pendingFiles.length} file(s). Some files may have multiple pages.
            INSTRUCTION: 
            1. Examine EVERY SINGLE PAGE and EVERY TABLE in the document(s).
            2. Extract ALL unique stock market trade entries found across all pages.
            3. For each trade, identify: ISIN, Security Name (Scrip), Buy/Sell Direction, Quantity, Gross Value, STT, and Net Settlement.
            4. Calculate 'otherCharges' by summing up all Brokerage, GST, Exchange Transaction Charges, SEBI fees, and Stamp Duty found in the document summary, EXCLUDING STT.
            5. If multiple pages have separate summaries, aggregate them.
            6. Return the full consolidated set of trades in the provided JSON schema.` }
          ]
        },
        config: { 
          responseMimeType: "application/json",
          responseSchema: responseSchema,
          thinkingConfig: { thinkingBudget: 24000 }
        }
      });

      const resultText = response.text;
      if (!resultText) throw new Error("Empty AI response");

      const result = JSON.parse(resultText.trim());
      if (result && result.trades && Array.isArray(result.trades) && result.trades.length > 0) {
        const totalGross = result.trades.reduce((acc: number, t: any) => acc + (Math.abs(t.grossValue) || 0), 1);
        const mappedTrades = result.trades.map((t: any) => {
           const prop = Math.abs(t.grossValue) / totalGross;
           const alloc = prop * (Math.abs(result.otherCharges) || 0);
           return {
             scrip: t.scrip || t.isin || 'Unknown',
             type: (String(t.type).toUpperCase().includes('SELL')) ? 'SELL' : 'BUY',
             isin: t.isin || '',
             units: Math.abs(t.units) || 0,
             grossValue: Math.abs(t.grossValue) || 0,
             stt: Math.abs(t.stt) || 0,
             date: t.date || result.date || new Date().toISOString().split('T')[0],
             netTotal: Math.abs(t.netSettlement) || ((Math.abs(t.grossValue) || 0) + (Math.abs(t.stt) || 0) + alloc),
             allocatedCharges: alloc
           };
        });
        setScanResult({ 
          date: result.date || new Date().toISOString().split('T')[0], 
          trades: mappedTrades, 
          otherCharges: Math.abs(result.otherCharges) || 0 
        });
      } else {
        alert("The AI Analyser could not find any trades. Please ensure every page of the document is captured clearly.");
      }
    } catch (err) {
      console.error("Multi-page Analysis Error:", err);
      alert("Error processing document pages. Please verify the file content and try again.");
    } finally {
      setIsScanning(false);
      setPdfPassword('');
      setPendingFiles([]);
      if (fileInputRef.current) fileInputRef.current.value = '';
    }
  };

  const commitScannedTrade = () => {
    if (!scanResult) return;
    try {
      const selectedAccount = allAccounts.find(a => a.id === importAccountId) || { id: 'fallback', type: 'wallet' };

      scanResult.trades.forEach(t => {
        addTransaction({
          id: Math.random().toString(36).substr(2, 9),
          type: t.type === 'BUY' ? 'Asset' : 'Income', 
          amount: t.netTotal,
          nature: 'Investment in stocks',
          description: `${t.type} ${t.scrip}`,
          accountId: (selectedAccount as any).id,
          accountType: (selectedAccount as any).type || 'wallet',
          date: t.date || scanResult.date,
          ownerId: importOwnerId, 
          isin: t.isin,
          units: t.units,
          stt: t.stt,
          brokerage: t.allocatedCharges
        });
      });
      setScanResult(null);
    } catch (err) {
      console.error(err);
      alert("Failed to commit transactions to the vault.");
    }
  };

  const tradeSummaryPerScrip = useMemo(() => {
    if (!scanResult) return [];
    const summary: Record<string, { isin: string, scrip: string, bought: number, sold: number }> = {};
    scanResult.trades.forEach(t => {
      const key = t.isin || t.scrip;
      if (!summary[key]) summary[key] = { isin: t.isin, scrip: t.scrip, bought: 0, sold: 0 };
      if (t.type === 'BUY') summary[key].bought += t.units;
      else summary[key].sold += t.units;
    });
    return Object.values(summary);
  }, [scanResult]);

  const getHoldingDelta = (isin: string) => {
    const existing = state.transactions.filter(t => t.isin === isin && t.nature === 'Investment in stocks');
    const existingHolding = existing.reduce((acc, t) => {
      return t.type === 'Asset' ? acc + (t.units || 0) : acc - (t.units || 0);
    }, 0);
    return existingHolding;
  };

  const handleOpenModal = (type: TransactionType) => {
    setEditingId(null);
    setFormData({ ...initialFormState, type, nature: natures[0] || '' });
    setShowModal(true);
  };

  const handleEditClick = (t: Transaction) => {
    setEditingId(t.id);
    setFormData({
      ...initialFormState,
      type: t.type, amount: String(t.amount), nature: t.nature, description: t.description,
      accountId: t.accountId, date: t.date, ownerId: t.ownerId || '', isin: t.isin || '',
      stockName: t.stockName || '', units: t.units ? String(t.units) : '', billingPeriod: t.billingPeriod || ''
    });
    setShowModal(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.nature) return;
    const account = allAccounts.find(a => a.id === formData.accountId);
    if (!account) return alert("Select target account.");

    const transactionData: Transaction = {
      id: editingId || Math.random().toString(36).substr(2, 9),
      type: formData.type, amount: Number(formData.amount), nature: formData.nature,
      description: formData.description, accountId: formData.accountId, accountType: account.type as any,
      date: formData.date, ownerId: formData.ownerId, isin: formData.isin, stockName: formData.stockName,
      units: formData.units ? Number(formData.units) : undefined, billingPeriod: formData.billingPeriod
    };
    if (editingId) updateTransaction(transactionData);
    else addTransaction(transactionData);
    setShowModal(false);
  };

  const getOwnerName = (id?: string) => {
    if (!id) return 'Me';
    const member = familyMembers.find(m => m.id === id);
    return member ? member.name : 'Me';
  };

  const transactionList = filteredState.transactions || [];

  return (
    <div className="space-y-6 md:space-y-10 animate-in fade-in duration-500 pb-20">
      <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-6">
        <div>
          <h3 className="text-xl md:text-2xl font-black text-slate-800 tracking-tight uppercase">Audit Ledger</h3>
          <p className="text-[10px] text-slate-400 font-black uppercase tracking-[0.2em] mt-2">Verified Transaction History</p>
        </div>
        <div className="grid grid-cols-2 md:grid-cols-3 lg:flex lg:flex-wrap items-center gap-2 md:gap-3">
          <input type="file" ref={fileInputRef} className="hidden" accept="image/*,.pdf,.xlsx,.xls" multiple onChange={handleFileUpload} />

          <div className="flex flex-col gap-1 items-stretch col-span-2 md:col-span-1">
            <button 
              onClick={() => fileInputRef.current?.click()}
              className="px-4 lg:px-6 py-3 lg:py-4 bg-slate-900 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest flex items-center justify-center gap-2 hover:bg-slate-800 transition-all shadow-xl active:scale-95"
            >
              <span>📄</span> Multi-Page Analyser
            </button>
            <button onClick={downloadExcelTemplate} className="text-[8px] font-black text-indigo-500 uppercase tracking-widest hover:underline px-2 text-center">Download Template</button>
          </div>

          <button onClick={() => handleOpenModal('Income')} className="px-4 py-3 lg:py-4 bg-emerald-50 text-emerald-600 border border-emerald-100 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all">Income</button>
          <button onClick={() => handleOpenModal('Expense')} className="px-4 py-3 lg:py-4 bg-rose-50 text-rose-500 border border-rose-100 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all">Expense</button>
          <button onClick={() => handleOpenModal('Asset')} className="px-4 py-3 lg:py-4 bg-white text-indigo-600 border border-indigo-100 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all">Asset</button>
          <button onClick={() => handleOpenModal('Liability')} className="px-4 py-3 lg:py-4 bg-indigo-600 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-lg transition-all">Debt</button>
        </div>
      </div>

      {scanResult && (
        <div className="bg-indigo-900 text-white p-6 md:p-10 rounded-[2.5rem] shadow-2xl animate-in slide-in-from-top-10 duration-500 relative overflow-hidden">
          <div className="absolute top-0 right-0 p-8 text-8xl opacity-10 font-black">IMPORT</div>
          <div className="relative z-10">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-6 border-b border-white/10 pb-4 gap-4">
               <h4 className="text-sm font-black uppercase tracking-widest flex items-center gap-3">
                 <span className="text-2xl">📋</span> Analysed Holding Impact
               </h4>
               <div className="flex flex-wrap items-center gap-3">
                  <div className="flex items-center gap-3 bg-white/10 p-2 rounded-xl border border-white/10">
                    <span className="text-[9px] font-black text-indigo-200 uppercase tracking-widest">Target Owner:</span>
                    <select 
                      className="bg-transparent text-[10px] font-black text-white outline-none appearance-none cursor-pointer"
                      value={importOwnerId}
                      onChange={(e) => setImportOwnerId(e.target.value)}
                    >
                      <option value="" className="text-slate-800">Me (Primary) </option>
                      {familyMembers.map(m => <option key={m.id} value={m.id} className="text-slate-800">{m.name}</option>)}
                    </select>
                  </div>

                  <div className="flex items-center gap-3 bg-white/10 p-2 rounded-xl border border-white/10">
                    <span className="text-[9px] font-black text-indigo-200 uppercase tracking-widest">Settlement:</span>
                    <select 
                      className="bg-transparent text-[10px] font-black text-white outline-none appearance-none cursor-pointer"
                      value={importAccountId}
                      onChange={(e) => setImportAccountId(e.target.value)}
                    >
                      <optgroup label="Primary Protocols" className="text-slate-400 italic">
                        {allAccounts
                          .filter(a => (a.ownerId || '') === (importOwnerId || '') && a.name.toLowerCase().includes('zerodha'))
                          .map(acc => <option key={acc.id} value={acc.id} className="text-slate-800 font-black">📈 Zerodha Account</option>)}
                        {allAccounts
                          .filter(a => (a.ownerId || '') === (importOwnerId || '') && a.type === 'bank')
                          .slice(0, 1)
                          .map(acc => <option key={acc.id} value={acc.id} className="text-slate-800 font-black">🏦 Capital Account ({acc.name})</option>)}
                      </optgroup>
                      <optgroup label="Other Instruments" className="text-slate-400 italic">
                        {allAccounts
                          .filter(a => (a.ownerId || '') === (importOwnerId || '') && !a.name.toLowerCase().includes('zerodha'))
                          .map(acc => <option key={acc.id} value={acc.id} className="text-slate-800">{acc.name}</option>)}
                      </optgroup>
                    </select>
                  </div>
               </div>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-10">
              <div className="space-y-6">
                <div className="bg-white/5 p-6 rounded-3xl border border-white/10">
                   <p className="text-[10px] font-black text-indigo-300 uppercase tracking-widest mb-4">Stock Holding Matrix (Aggregated)</p>
                   <div className="space-y-4">
                      {tradeSummaryPerScrip.map((s, i) => {
                        const prevHolding = getHoldingDelta(s.isin);
                        const netDelta = s.bought - s.sold;
                        const finalHolding = prevHolding + netDelta;
                        return (
                          <div key={i} className="flex flex-col p-4 bg-indigo-800/40 rounded-2xl border border-white/5">
                             <div className="flex justify-between items-center mb-2">
                                <span className="text-xs font-black uppercase tracking-tight truncate max-w-[150px]">{s.isin || s.scrip}</span>
                                <span className="text-[10px] font-black text-indigo-200">Final Holding: {finalHolding.toLocaleString()}</span>
                             </div>
                             <div className="grid grid-cols-3 gap-2">
                                <div className="text-center p-2 bg-emerald-500/10 rounded-xl">
