                  <td className="px-8 py-6 text-center flex items-center justify-center gap-2 md:opacity-0 md:group-hover:opacity-100 transition-all">
                    <button onClick={() => handleEditClick(t)} className="p-2.5 bg-slate-50 hover:bg-white hover:shadow-md text-slate-400 hover:text-indigo-600 rounded-xl">✎</button>
                    <button onClick={() => setConfirmDeleteTx(t)} className="p-2.5 bg-slate-50 hover:bg-white hover:shadow-md text-slate-400 hover:text-rose-500 rounded-xl">✕</button>
