      {showModal && (
        <div className="fixed inset-0 z-50 flex justify-center items-center bg-slate-900/60 backdrop-blur-xl p-4 overflow-y-auto">
          <div className="bg-white w-full max-w-2xl rounded-[3rem] p-8 md:p-12 border border-slate-200 shadow-2xl animate-in zoom-in-95 duration-200 relative max-h-[90dvh] overflow-y-auto custom-scrollbar">
            <div className="flex justify-between items-center mb-10 border-b border-slate-100 pb-6">
              <div>
                <h3 className="text-xl font-black text-slate-800 uppercase tracking-tighter">{formData.type} Record</h3>
                <p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest mt-1">Manual Reconciliation Entry</p>
              </div>
              <button onClick={() => setShowModal(false)} className="text-slate-200 hover:text-slate-800 font-black p-2 text-2xl transition-colors">✕</button>
