            <form onSubmit={handleSubmit} className="space-y-8">
              {formData.type === 'Asset' && (
                <div className="space-y-6 bg-indigo-50/30 p-8 rounded-[2rem] border border-indigo-100 animate-in slide-in-from-top-4">
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
