                      <label className="text-[9px] font-black text-indigo-400 uppercase tracking-widest block ml-2">ISIN Protocol Key</label>
                      <input className="w-full p-4 bg-white border border-indigo-100 rounded-2xl outline-none font-black text-xs uppercase tracking-widest focus:ring-4 focus:ring-indigo-500/10 transition-all" placeholder="e.g. INE002A01018" maxLength={12} value={formData.isin} onChange={e => setFormData({ ...formData, isin: e.target.value.toUpperCase() })} />
                    </div>
                    <div className="space-y-2">
                      <label className="text-[9px] font-black text-indigo-400 uppercase tracking-widest block ml-2">Official Security Name</label>
                      <div className="relative">
                        <input className={`w-full p-4 bg-white border border-indigo-100 rounded-2xl outline-none font-black text-xs focus:ring-4 focus:ring-indigo-500/10 transition-all ${isIsinResolving ? 'animate-pulse text-indigo-300' : ''}`} placeholder={isIsinResolving ? "Querying AI Vault..." : "Identifying..."} value={formData.stockName} onChange={e => setFormData({ ...formData, stockName: e.target.value })} />
                        {isIsinResolving && <span className="absolute right-4 top-1/2 -translate-y-1/2 animate-spin text-indigo-500 text-lg">⚙️</span>}
                      </div>
                    </div>
                  </div>
                  {formData.isin && (
                    <div className="space-y-2 animate-in fade-in slide-in-from-left-4 duration-500">
                      <label className="text-[9px] font-black text-indigo-600 uppercase tracking-widest block ml-2">Number of Units / Quantity</label>
                      <input type="number" step="any" className="w-full p-4 bg-white border border-indigo-200 rounded-2xl outline-none font-black text-xl text-indigo-600 shadow-sm focus:ring-4 focus:ring-indigo-500/10 transition-all" placeholder="0.00" value={formData.units} onChange={e => setFormData({ ...formData, units: e.target.value })} />
                    </div>
