import React, { createContext, useContext, useState, useEffect, ReactNode, useMemo } from 'react';
import { FinancialState, UserProfile, BankAccount, CreditCard, Wallet, IncomeStream, Expense, Asset, Liability, Transaction, FamilyMember, Notification } from '../types';
import { supabase } from '../lib/supabase';

interface FinanceContextType {
  state: FinancialState;
  filteredState: FinancialState;
  isAuthenticated: boolean;
  activeMemberIds: string[];
  isCloudSyncing: boolean;
  setActiveMemberIds: (ids: string[]) => void;
  setAuthenticated: (value: boolean) => void;
  updateProfile: (profile: UserProfile) => void;
  addFamilyMember: (member: FamilyMember) => Promise<{ success: boolean; syncedCount: number; error?: string }>;
  removeFamilyMember: (id: string) => void;
  toggleFamilyMemberTxPermission: (id: string) => void;
  addBank: (bank: BankAccount) => void;
  updateBank: (bank: BankAccount) => void;
  deleteBank: (id: string) => void;
  addCard: (card: CreditCard) => void;
  updateCard: (card: CreditCard) => void;
  deleteCard: (id: string) => void;
  addWallet: (wallet: Wallet) => void;
  updateWallet: (wallet: Wallet) => void;
  deleteWallet: (id: string) => void;
  addIncome: (income: IncomeStream) => void;
  addExpense: (expense: Expense) => void;
  addAsset: (asset: Asset) => void;
  updateAsset: (asset: Asset) => void;
  deleteAsset: (id: string) => void;
  addLiability: (liability: Liability) => void;
  updateLiability: (liability: Liability) => void;
  deleteLiability: (id: string) => void;
  addTransaction: (transaction: Transaction) => void;
  updateTransaction: (transaction: Transaction) => void;
  deleteTransaction: (id: string) => void;
  addTransactionNature: (nature: string) => void;
  deleteTransactionNature: (nature: string) => void;
  clearNotifications: () => void;
  markNotificationRead: (id: string) => void;
  simulateSync: () => Promise<void>;
  resetBoarding: () => Promise<void>;
  loadStateFromCloud: (mobile: string) => Promise<boolean>;
  importState: (newState: FinancialState) => void;
}

const GLOBAL_SESSION_KEY = 'myfin_active_session';
const STATE_PREFIX = 'myfin_state_';

const initialState: FinancialState = {
  profile: { 
    name: '', 
    designation: '', 
    age: 0, 
    city: '', 
    country: 'India', 
    currency: 'INR', 
    mobileNumber: '',
    isBoarded: false, 
    familyMembers: [],
    cloudDatabaseName: 'Default_Vault'
  },
  banks: [],
  cards: [],
  wallets: [], 
  incomes: [],
  expenses: [],
  assets: [],
  liabilities: [],
  transactions: [],
  notifications: [],
  transactionNatures: ['Salary', 'Grocery', 'Rent', 'Investment', 'Loan Repayment', 'Medical', 'Dining', 'Travel', 'Utilities', 'Investment in stocks', 'Other Charges', 'Securities transaction tax'],
  capital: 0
};

const FinanceContext = createContext<FinanceContextType | undefined>(undefined);

export const useFinance = () => {
  const context = useContext(FinanceContext);
  if (!context) throw new Error('useFinance must be used within a FinanceProvider');
  return context;
};

export const FinanceProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [isAuthenticated, setAuthenticated] = useState(false);
  const [activeMemberIds, setActiveMemberIds] = useState<string[]>([]);
  const [isCloudSyncing, setIsCloudSyncing] = useState(false);
  const [activeMobile, setActiveMobile] = useState<string | null>(() => localStorage.getItem(GLOBAL_SESSION_KEY));

  const [state, setState] = useState<FinancialState>(() => {
    const mobile = localStorage.getItem(GLOBAL_SESSION_KEY);
    if (mobile) {
      const saved = localStorage.getItem(`${STATE_PREFIX}${mobile}`);
      if (saved) {
        try {
          const parsed = JSON.parse(saved);
          return { ...initialState, ...parsed };
        } catch (e) {
          return initialState;
        }
      }
    }
    return initialState;
  });

  useEffect(() => {
    if (state.profile.mobileNumber && state.profile.isBoarded) {
      localStorage.setItem(GLOBAL_SESSION_KEY, state.profile.mobileNumber);
      localStorage.setItem(`${STATE_PREFIX}${state.profile.mobileNumber}`, JSON.stringify(state));
    }
  }, [state]);

  useEffect(() => {
    const persistToSupabase = async () => {
      if (!state.profile.mobileNumber || !state.profile.isBoarded) return;

      setIsCloudSyncing(true);
      try {
        const { error } = await supabase
          .from('user_states')
          .upsert({ 
            mobile_number: state.profile.mobileNumber, 
            state: state,
            updated_at: new Date().toISOString()
          }, { onConflict: 'mobile_number' });

        if (error) console.error('Supabase Persist Error:', error);
      } catch (err) {
        console.error('Cloud sync failed:', err);
      } finally {
        setTimeout(() => setIsCloudSyncing(false), 500);
      }
    };

    const timeoutId = setTimeout(persistToSupabase, 2000);
    return () => clearTimeout(timeoutId);
  }, [state]);

  const applyTransactionEffect = (transaction: Transaction, newState: FinancialState, isReversing: boolean) => {
    const factor = isReversing ? -1 : 1;
    const totalAmount = (transaction.amount || 0);
    const balanceDelta = (transaction.type === 'Income' || transaction.type === 'Liability') ? totalAmount : -totalAmount;
    const finalBalanceDelta = balanceDelta * factor;

    if (transaction.accountType === 'bank') {
      newState.banks = (newState.banks || []).map(b => b.id === transaction.accountId ? { ...b, balance: b.balance + finalBalanceDelta } : b);
    } else if (transaction.accountType === 'card') {
      const cardDelta = (transaction.type === 'Income' || transaction.type === 'Liability' ? -totalAmount : totalAmount) * factor;
      newState.cards = (newState.cards || []).map(c => c.id === transaction.accountId ? { ...c, balance: c.balance + cardDelta } : c);
    } else if (transaction.accountType === 'wallet') {
      newState.wallets = (newState.wallets || []).map(w => w.id === transaction.accountId ? { ...w, balance: w.balance + finalBalanceDelta } : w);
    } else if (transaction.accountType === 'liability') {
      const liabilityDelta = (transaction.type === 'Income' || transaction.type === 'Liability' ? -totalAmount : totalAmount) * factor;
      newState.liabilities = (newState.liabilities || []).map(l => l.id === transaction.accountId ? { ...l, amount: l.amount + liabilityDelta } : l);
    }

    if (isReversing) {
      newState.incomes = (newState.incomes || []).filter(i => i.id !== transaction.id);
      newState.expenses = (newState.expenses || []).filter(e => e.id !== transaction.id);
      newState.assets = (newState.assets || []).filter(a => a.id !== transaction.id);
      newState.liabilities = (newState.liabilities || []).filter(l => l.id !== transaction.id);
    } else {
      switch (transaction.type) {
        case 'Income':
          newState.incomes.push({ id: transaction.id, name: `${transaction.nature}: ${transaction.description}`, amount: transaction.amount, periodicity: 'Monthly', dateOfReceipt: transaction.date, ownerId: transaction.ownerId });
          break;
        case 'Expense':
          newState.expenses.push({ id: transaction.id, category: transaction.nature, amount: transaction.amount, date: transaction.date, ownerId: transaction.ownerId });
          break;
        case 'Asset':
          newState.assets.push({ 
            id: transaction.id, 
            name: `${transaction.nature}: ${transaction.description}`, 
            value: transaction.amount, 
            type: 'Physical', 
            ownerId: transaction.ownerId,
            isin: transaction.isin,
            units: transaction.units,
            classification: 'Non-Current Asset'
          });
          break;
        case 'Liability':
          newState.liabilities.push({ id: transaction.id, name: `${transaction.nature}: ${transaction.description}`, amount: transaction.amount, type: 'Debt', ownerId: transaction.ownerId, classification: 'Current Liability' });
          break;
      }
    }
  };

  const addTransactionNature = (nature: string) => {
    setState(prev => {
      if (prev.transactionNatures.includes(nature)) return prev;
      return { ...prev, transactionNatures: [...prev.transactionNatures, nature] };
    });
  };

  const deleteTransactionNature = (nature: string) => {
    setState(prev => ({
      ...prev,
      transactionNatures: prev.transactionNatures.filter(n => n !== nature)
    }));
  };

  const loadStateFromCloud = async (mobile: string): Promise<boolean> => {
    try {
      const { data, error } = await supabase.from('user_states').select('state').eq('mobile_number', mobile).single();
      if (data && data.state) {
        setState({ ...initialState, ...data.state });
        setActiveMobile(mobile);
        localStorage.setItem(GLOBAL_SESSION_KEY, mobile);
        setAuthenticated(true);
        return true;
      }
      return false;
    } catch (err) {
      return false;
    }
  };

  const importState = (newState: FinancialState) => {
    if (newState && newState.profile && newState.profile.mobileNumber) {
      setState({ ...initialState, ...newState });
      setActiveMobile(newState.profile.mobileNumber);
      localStorage.setItem(GLOBAL_SESSION_KEY, newState.profile.mobileNumber);
      setAuthenticated(true);
    }
  };

  const updateProfile = (profile: UserProfile) => {
    setState(prev => ({ ...prev, profile: { ...profile, isBoarded: true } }));
    if (profile.mobileNumber) {
      setActiveMobile(profile.mobileNumber);
      localStorage.setItem(GLOBAL_SESSION_KEY, profile.mobileNumber);
    }
  };

  const addFamilyMember = async (member: FamilyMember): Promise<{ success: boolean; syncedCount: number; error?: string }> => {
    if (member.mobileNumber === state.profile.mobileNumber) return { success: false, syncedCount: 0, error: "Cannot link your own account." };
    if (state.profile.familyMembers.some(m => m.mobileNumber === member.mobileNumber)) return { success: false, syncedCount: 0, error: 'Member already linked.' };
    let syncedCount = 0;
    let memberData: any = null;
    try {
      const { data } = await supabase.from('user_states').select('state').eq('mobile_number', member.mobileNumber).single();
      if (data && data.state) memberData = data.state;
    } catch (err) {}
    setState(prev => {
      const newFamilyMembers = [...(prev.profile.familyMembers || []), { ...member, canAddTransactions: member.canAddTransactions ?? true }];
      if (!memberData) return { ...prev, profile: { ...prev.profile, familyMembers: newFamilyMembers } };
      const syncTag = (item: any) => ({ ...item, id: `${member.id}_${item.id}`, ownerId: member.id });
      return {
        ...prev,
        profile: { ...prev.profile, familyMembers: newFamilyMembers },
        banks: [...(prev.banks || []), ...(memberData.banks || []).map(syncTag)],
        cards: [...(prev.cards || []), ...(memberData.cards || []).map(syncTag)],
        wallets: [...(prev.wallets || []), ...(memberData.wallets || []).map(syncTag)],
        transactions: [...(prev.transactions || []), ...(memberData.transactions || []).map(syncTag)],
        incomes: [...(prev.incomes || []), ...(memberData.incomes || []).map(syncTag)],
        expenses: [...(prev.expenses || []), ...(memberData.expenses || []).map(syncTag)],
        assets: [...(prev.assets || []), ...(memberData.assets || []).map(syncTag)],
        liabilities: [...(prev.liabilities || []), ...(memberData.liabilities || []).map(syncTag)],
        capital: prev.capital + (memberData.capital || 0),
      };
    });
    return { success: true, syncedCount };
  };

  const removeFamilyMember = (id: string) => setState(prev => ({
    ...prev,
    profile: { ...prev.profile, familyMembers: (prev.profile.familyMembers || []).filter(m => m.id !== id) }
  }));

  const toggleFamilyMemberTxPermission = (id: string) => setState(prev => ({
    ...prev,
    profile: {
      ...prev.profile,
      familyMembers: prev.profile.familyMembers.map(m => m.id === id ? { ...m, canAddTransactions: !m.canAddTransactions } : m)
    }
  }));

  const addBank = (bank: BankAccount) => setState(prev => ({ 
    ...prev, 
    banks: [...(prev.banks || []), { ...bank, classification: 'Current Asset' }],
    capital: prev.capital + bank.balance 
  }));
  const updateBank = (bank: BankAccount) => setState(prev => {
    const old = prev.banks.find(b => b.id === bank.id);
    const diff = bank.balance - (old?.balance || 0);
    return { 
      ...prev, 
      banks: prev.banks.map(b => b.id === bank.id ? { ...bank, classification: 'Current Asset' } : b),
      capital: prev.capital + diff
    };
  });
  const deleteBank = (id: string) => setState(prev => {
    const old = prev.banks.find(b => b.id === id);
    return { 
      ...prev, 
      banks: prev.banks.filter(b => b.id !== id),
      capital: prev.capital - (old?.balance || 0)
    };
  });

  const addCard = (card: CreditCard) => setState(prev => ({ 
    ...prev, 
    cards: [...(prev.cards || []), card],
    capital: prev.capital - card.balance
  }));
  const updateCard = (card: CreditCard) => setState(prev => {
    const old = prev.cards.find(c => c.id === card.id);
    const diff = card.balance - (old?.balance || 0);
    return { 
      ...prev, 
      cards: prev.cards.map(c => c.id === card.id ? card : c),
      capital: prev.capital - diff
    };
  });
  const deleteCard = (id: string) => setState(prev => {
    const old = prev.cards.find(c => c.id === id);
    return { 
      ...prev, 
      cards: prev.cards.filter(c => c.id !== id),
      capital: prev.capital + (old?.balance || 0)
    };
  });

  const addWallet = (wallet: Wallet) => setState(prev => ({ 
    ...prev, 
    wallets: [...(prev.wallets || []), { ...wallet, classification: 'Current Asset' }],
    capital: prev.capital + wallet.balance
  }));
  const updateWallet = (wallet: Wallet) => setState(prev => {
    const old = prev.wallets.find(w => w.id === wallet.id);
    const diff = wallet.balance - (old?.balance || 0);
    return { 
      ...prev, 
      wallets: prev.wallets.map(w => w.id === wallet.id ? { ...wallet, classification: 'Current Asset' } : w),
      capital: prev.capital + diff
    };
  });
  const deleteWallet = (id: string) => setState(prev => {
    const old = prev.wallets.find(w => w.id === id);
    return { 
      ...prev, 
      wallets: prev.wallets.filter(w => w.id !== id),
      capital: prev.capital - (old?.balance || 0)
    };
  });

  const addIncome = (income: IncomeStream) => setState(prev => ({ ...prev, incomes: [...prev.incomes, income] }));
  const addExpense = (expense: Expense) => setState(prev => ({ ...prev, expenses: [...prev.expenses, expense] }));

  const addAsset = (asset: Asset) => setState(prev => ({ 
    ...prev, 
    assets: [...prev.assets, asset],
    capital: prev.capital + asset.value
  }));
  const updateAsset = (asset: Asset) => setState(prev => {
    const old = prev.assets.find(a => a.id === asset.id);
    const diff = asset.value - (old?.value || 0);
    return { 
      ...prev, 
      assets: prev.assets.map(a => a.id === asset.id ? asset : a),
      capital: prev.capital + diff
    };
  });
  const deleteAsset = (id: string) => setState(prev => {
    const old = prev.assets.find(a => a.id === id);
    return { 
      ...prev, 
      assets: prev.assets.filter(a => a.id !== id),
      capital: prev.capital - (old?.value || 0)
    };
  });

  const addLiability = (liability: Liability) => setState(prev => ({ 
    ...prev, 
    liabilities: [...prev.liabilities, liability],
    capital: prev.capital - liability.amount
  }));
  const updateLiability = (liability: Liability) => setState(prev => {
    const old = prev.liabilities.find(l => l.id === liability.id);
    const diff = liability.amount - (old?.amount || 0);
    return { 
      ...prev, 
      liabilities: prev.liabilities.map(l => l.id === liability.id ? liability : l),
      capital: prev.capital - diff
    };
  });
  const deleteLiability = (id: string) => setState(prev => {
    const old = prev.liabilities.find(l => l.id === id);
    return { 
      ...prev, 
      liabilities: prev.liabilities.filter(l => l.id !== id),
      capital: prev.capital + (old?.amount || 0)
    };
  });

  const addTransaction = (transaction: Transaction) => {
    setState(prev => {
      const newState = { ...prev, transactions: [transaction, ...(prev.transactions || [])] };
      applyTransactionEffect(transaction, newState, false);
      return newState;
    });
  };

  const updateTransaction = (updatedTransaction: Transaction) => {
    setState(prev => {
      const oldTransaction = (prev.transactions || []).find(t => t.id === updatedTransaction.id);
      if (!oldTransaction) return prev;
      let newState = { ...prev };
      applyTransactionEffect(oldTransaction, newState, true);
      newState.transactions = (newState.transactions || []).map(t => t.id === updatedTransaction.id ? updatedTransaction : t);
      applyTransactionEffect(updatedTransaction, newState, false);
      return newState;
    });
  };

  const deleteTransaction = (id: string) => {
    setState(prev => {
      const transaction = (prev.transactions || []).find(t => t.id === id);
      if (!transaction) return prev;
      const newState = { ...prev, transactions: (prev.transactions || []).filter(t => t.id !== id) };
      applyTransactionEffect(transaction, newState, true);
      return newState;
    });
  };

  const clearNotifications = () => setState(prev => ({ ...prev, notifications: [] }));
  const markNotificationRead = (id: string) => setState(prev => ({
    ...prev,
    notifications: (prev.notifications || []).map(n => n.id === id ? { ...n, isRead: true } : n)
  }));

  const simulateSync = async () => {
    setState(prev => ({
      ...prev,
      notifications: [...(prev.notifications || []), {
        id: Math.random().toString(36).substr(2, 9),
        title: 'Cloud Sync Complete',
        message: 'Your ledger has been successfully synchronized with the cloud vault.',
        timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
        type: 'sync',
        isRead: false
      }]
    }));
  };

  const filteredState = useMemo(() => {
    if (activeMemberIds.includes('all')) return state;
    const isFiltered = activeMemberIds.length > 0;
    const filterIds = isFiltered ? activeMemberIds : [undefined, ''];
    const filterFn = (item: any) => filterIds.includes(item.ownerId || '');
    return {
      ...state,
      banks: (state.banks || []).filter(filterFn),
      cards: (state.cards || []).filter(filterFn),
      wallets: (state.wallets || []).filter(filterFn),
      incomes: (state.incomes || []).filter(filterFn),
      expenses: (state.expenses || []).filter(filterFn),
      assets: (state.assets || []).filter(filterFn),
      liabilities: (state.liabilities || []).filter(filterFn),
      transactions: (state.transactions || []).filter(filterFn),
    };
  }, [state, activeMemberIds]);

  const resetBoarding = async () => { 
    const mobile = state.profile.mobileNumber;
    if (mobile) {
      try {
        await supabase.from('user_states').delete().eq('mobile_number', mobile);
        localStorage.removeItem(`${STATE_PREFIX}${mobile}`);
      } catch (err) {
        console.error('Failed to purge cloud record during reset:', err);
      }
    }

    localStorage.removeItem(GLOBAL_SESSION_KEY);
    setState(initialState); 
    setAuthenticated(false); 
    setActiveMobile(null);
  };

  return (
    <FinanceContext.Provider value={{ 
      state, filteredState, isAuthenticated, activeMemberIds, isCloudSyncing, setActiveMemberIds, setAuthenticated, updateProfile, 
      addFamilyMember, removeFamilyMember, toggleFamilyMemberTxPermission,
      addBank, updateBank, deleteBank, addCard, updateCard, deleteCard, addWallet, updateWallet, deleteWallet, 
      addIncome, addExpense, addAsset, updateAsset, deleteAsset, addLiability, updateLiability, deleteLiability,
      addTransaction, updateTransaction, deleteTransaction, addTransactionNature, deleteTransactionNature,
      clearNotifications, markNotificationRead, simulateSync, resetBoarding, loadStateFromCloud, importState
    }}>
      {children}
    </FinanceContext.Provider>
  );
};

import { GoogleGenAI, Type } from "@google/genai";
import React, { useEffect, useMemo, useRef, useState } from 'react';
import * as XLSX from 'xlsx';
import { useFinance } from '../store/FinanceContext';
import { Transaction, TransactionType } from '../types';
import { formatCurrency } from '../utils/formatters';

type SplitType = 'equal' | 'exact' | 'percentage' | 'shares';

interface Participant {
  id: string; 
  name: string;
  mobile: string;
  value: string; 
  result: number; 
  isSelf: boolean;
}

interface ExtractedTrade {
  scrip: string;
  type: 'BUY' | 'SELL';
  grossValue: number;
  netTotal: number;
  units: number;
  date: string;
  isin: string;
  stt: number;
  allocatedCharges: number;
}

const Transactions: React.FC = () => {
  const { filteredState, state, addTransaction, updateTransaction, deleteTransaction, addTransactionNature, addWallet } = useFinance();
  const familyMembers = state.profile?.familyMembers || [];
  const natures = state.transactionNatures || [];
  const [showModal, setShowModal] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [confirmDeleteTx, setConfirmDeleteTx] = useState<Transaction | null>(null);
  const [isScanning, setIsScanning] = useState(false);
  const [isIsinResolving, setIsIsinResolving] = useState(false);
  const [scanTimeLeft, setScanTimeLeft] = useState(25);
  const [pdfPassword, setPdfPassword] = useState('');
  const [showPasswordInput, setShowPasswordInput] = useState(false);
  const [pendingFiles, setPendingFiles] = useState<File[]>([]);
  const [importOwnerId, setImportOwnerId] = useState<string>('');
  const [importAccountId, setImportAccountId] = useState<string>('');

  const [scanResult, setScanResult] = useState<{ 
    date: string; 
    trades: ExtractedTrade[];
    otherCharges: number;
  } | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const currency = state.profile.currency;

  const initialFormState = {
    type: 'Expense' as TransactionType,
    amount: '', 
    nature: natures[0] || '',
    description: '',
    accountId: '',
    date: new Date().toISOString().split('T')[0],
    isShared: false,
    includeSelf: true,
    numberOfPeople: 2,
    splitType: 'equal' as SplitType,
    participants: [] as Participant[],
    ownerId: '',
    isin: '',
    stockName: '',
    units: '',
    billingPeriod: '',
    estimatedLife: '1' 
  };

  const [formData, setFormData] = useState(initialFormState);

  const allAccounts = useMemo(() => {
    const banks = (state.banks || []).map(b => ({ id: b.id, name: b.name, type: 'bank' as const, ownerId: b.ownerId }));
    const cards = (state.cards || []).map(c => ({ id: c.id, name: c.lenderName, type: 'card' as const, ownerId: c.ownerId }));
    const liabilities = (state.liabilities || []).filter(l => l.type === 'Debt').map(l => ({ id: l.id, name: l.name, type: 'liability' as const, ownerId: l.ownerId }));
    const wallets = (state.wallets || []).map(w => ({ id: w.id, name: w.name, type: 'wallet' as const, ownerId: w.ownerId }));
    return [...banks, ...cards, ...wallets, ...liabilities];
  }, [state.banks, state.cards, state.wallets, state.liabilities]);

  useEffect(() => {
    if (scanResult) {
      const zerodha = allAccounts.find(a => a.name.toLowerCase().includes('zerodha') && (a.ownerId === importOwnerId || !a.ownerId));
      if (zerodha) {
        setImportAccountId(zerodha.id);
      } else {
        setImportAccountId('equity-protocol'); 
      }
    }
  }, [scanResult, importOwnerId, allAccounts]);

  useEffect(() => {
    if (!natures.includes('Investment in stocks')) {
      addTransactionNature('Investment in stocks');
    }
    if (!natures.includes('Other Charges')) {
      addTransactionNature('Other Charges');
    }
    if (!natures.includes('Securities transaction tax')) {
      addTransactionNature('Securities transaction tax');
    }

    const zerodhaExists = allAccounts.some(a => a.name.toLowerCase().includes('zerodha'));
    if (!zerodhaExists) {
      addWallet({
        id: 'zerodha-account-auto',
        name: 'Zerodha',
        balance: 0,
        ownerId: ''
      });
    }

    const capitalExists = allAccounts.some(a => a.id === 'equity-virtual');
    if (!capitalExists) {
      addWallet({
        id: 'equity-virtual',
        name: 'Capital Account',
        balance: 0,
        ownerId: ''
      });
    }
  }, [allAccounts]);

  const handleIsinLookup = async (isin: string) => {
    setIsIsinResolving(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Identify the security/stock name for the following ISIN identifier: ${isin}. Return ONLY the official short name of the security. No preamble.`
      });
      const resolvedName = response.text?.trim() || 'Unknown Security';
      setFormData(prev => ({ 
        ...prev, 
        stockName: resolvedName,
        description: prev.description || resolvedName
      }));
    } catch (err) {
      console.error("ISIN Resolution failed:", err);
    } finally {
      setIsIsinResolving(false);
    }
  };

  useEffect(() => {
    const timer = setTimeout(() => {
      if (formData.isin && formData.isin.length === 12 && !formData.stockName) {
        handleIsinLookup(formData.isin);
      }
    }, 500);
    return () => clearTimeout(timer);
  }, [formData.isin]);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(e.target.files || []) as File[];
    if (files.length === 0) return;
    const excelFiles = files.filter(f => f.name.endsWith('.xlsx') || f.name.endsWith('.xls'));
    const docFiles = files.filter(f => !f.name.endsWith('.xlsx') && !f.name.endsWith('.xls'));
    if (excelFiles.length > 0) handleExcelImport(excelFiles[0]);
    if (docFiles.length > 0) {
      setPendingFiles(docFiles);
      setShowPasswordInput(true);
    }
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const handleExcelImport = (file: File) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const data = new Uint8Array(e.target?.result as ArrayBuffer);
        const workbook = XLSX.read(data, { type: 'array', cellDates: true });
        const firstSheetName = workbook.SheetNames[0];
        const worksheet = workbook.Sheets[firstSheetName];
        const rows: any[] = XLSX.utils.sheet_to_json(worksheet);
        if (rows.length === 0) { alert("Excel file is empty."); return; }
        let totalOtherCharges = 0;
        let totalGrossValueAbs = 0;
        let lastDate = new Date().toISOString().split('T')[0];
        const cleanedRows = rows.map(r => {
          const newRow: any = {};
          Object.keys(r).forEach(k => newRow[k.trim()] = r[k]);
          return newRow;
        });
        cleanedRows.forEach((row: any) => {
          const grossValue = Math.abs(Number(row['Total Buy/Sell Value'] || 0));
          const chargesExclSTT = Math.abs(Number(row['Total Charges excluding STT'] || 0));
          totalOtherCharges += chargesExclSTT;
          totalGrossValueAbs += grossValue;
        });
        const trades: ExtractedTrade[] = [];
        cleanedRows.forEach((row: any) => {
          const isin = row['ISIN'] || 'UNKNOWN_ISIN';
          let txDateRaw = row['Date of transaction'];
          let formattedDate = lastDate;
          if (txDateRaw) {
            const d = new Date(txDateRaw);
            if (!isNaN(d.getTime())) formattedDate = d.toISOString().split('T')[0];
          }
          lastDate = formattedDate;
          const qty = Number(row['Quantity'] || 0);
          const type = String(row['Buy/Sell'] || 'BUY').toUpperCase();
          const grossValue = Math.abs(Number(row['Total Buy/Sell Value'] || 0));
          const stt = Math.abs(Number(row['STT'] || 0));
          const netSettlement = Number(row['Net Payable/ Receivable'] || 0);
          const proportion = totalGrossValueAbs > 0 ? (grossValue / totalGrossValueAbs) : 0;
          const allocatedOtherCharges = proportion * totalOtherCharges;
          const finalCostBasis = Math.abs(netSettlement) || (grossValue + stt + allocatedOtherCharges);
          trades.push({
            scrip: isin, 
            type: type === 'BUY' ? 'BUY' : 'SELL',
            grossValue: grossValue,
            netTotal: finalCostBasis,
            units: qty,
            date: formattedDate,
            isin: isin,
            stt: stt,
            allocatedCharges: allocatedOtherCharges
          });
        });
        setScanResult({ date: lastDate, trades, otherCharges: totalOtherCharges });
      } catch (err) { console.error(err); alert("Failed to parse Excel file."); }
    };
    reader.readAsArrayBuffer(file);
  };

  const startAIParsing = async () => {
    if (pendingFiles.length === 0) return;
    setShowPasswordInput(false);
    setIsScanning(true);
    setScanTimeLeft(30);
    try {
      const fileParts = await Promise.all(pendingFiles.map(async (file) => {
        return new Promise<any>((resolve) => {
          const reader = new FileReader();
          reader.onloadend = () => {
            const base64Data = (reader.result as string).split(',')[1];
            resolve({ inlineData: { data: base64Data, mimeType: file.type } });
          };
          reader.readAsDataURL(file);
        });
      }));
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const responseSchema = {
        type: Type.OBJECT,
        properties: {
          date: { type: Type.STRING, description: "The settlement date in YYYY-MM-DD format." },
          otherCharges: { type: Type.NUMBER },
          trades: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                isin: { type: Type.STRING },
                scrip: { type: Type.STRING },
                type: { type: Type.STRING },
                units: { type: Type.NUMBER },
                grossValue: { type: Type.NUMBER },
                stt: { type: Type.NUMBER },
                netSettlement: { type: Type.NUMBER }
              },
              required: ["isin", "type", "units", "grossValue", "netSettlement"]
            }
          }
        },
        required: ["date", "trades", "otherCharges"]
      };
      const response = await ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: {
          parts: [
            ...fileParts,
            { text: `Analyse Broker Note. Return JSON schema.` }
          ]
        },
        config: { 
          responseMimeType: "application/json",
          responseSchema: responseSchema,
          thinkingConfig: { thinkingBudget: 24000 }
        }
      });
      const resultText = response.text;
      if (!resultText) throw new Error("Empty AI response");
      const result = JSON.parse(resultText.trim());
      if (result && result.trades && Array.isArray(result.trades)) {
        const totalGross = result.trades.reduce((acc: number, t: any) => acc + (Math.abs(t.grossValue) || 0), 1);
        const mappedTrades = result.trades.map((t: any) => {
           const prop = Math.abs(t.grossValue) / totalGross;
           const alloc = prop * (Math.abs(result.otherCharges) || 0);
           return {
             scrip: t.scrip || t.isin || 'Unknown',
             type: (String(t.type).toUpperCase().includes('SELL')) ? 'SELL' : 'BUY',
             isin: t.isin || '',
             units: Math.abs(t.units) || 0,
             grossValue: Math.abs(t.grossValue) || 0,
             stt: Math.abs(t.stt) || 0,
             date: t.date || result.date || new Date().toISOString().split('T')[0],
             netTotal: Math.abs(t.netSettlement) || ((Math.abs(t.grossValue) || 0) + (Math.abs(t.stt) || 0) + alloc),
             allocatedCharges: alloc
           };
        });
        setScanResult({ date: result.date || new Date().toISOString().split('T')[0], trades: mappedTrades, otherCharges: Math.abs(result.otherCharges) || 0 });
      }
    } catch (err) { console.error(err); } finally { setIsScanning(false); setPdfPassword(''); setPendingFiles([]); }
  };

  const commitScannedTrade = () => {
    if (!scanResult) return;
    try {
      const isEquityProtocol = importAccountId === 'equity-protocol';
      const selectedAccount = allAccounts.find(a => a.id === importAccountId) || { id: 'equity-virtual', type: 'wallet' };
      const settlementAccountId = isEquityProtocol ? 'equity-virtual' : (selectedAccount as any).id;
      const settlementAccountType = isEquityProtocol ? 'wallet' : ((selectedAccount as any).type || 'wallet');

      scanResult.trades.forEach(t => {
        /**
         * RECTIFIED LOGIC:
         * BUY: All charges (Brokerage + STT) are ADDED to the purchase value.
         * SELL: All charges (Brokerage + STT) are REDUCED from the sale value.
         */
        const primaryTradeAmount = t.type === 'BUY' 
          ? (t.grossValue + t.allocatedCharges + t.stt) 
          : (t.grossValue - t.allocatedCharges - t.stt);

        addTransaction({
          id: Math.random().toString(36).substr(2, 9),
          type: t.type === 'BUY' ? 'Asset' : 'Income', 
          amount: primaryTradeAmount,
          nature: 'Investment in stocks',
          description: `${t.type} ${t.scrip}`,
          accountId: settlementAccountId,
          accountType: settlementAccountType,
          date: t.date || scanResult.date,
          ownerId: importOwnerId, 
          isin: t.isin,
          units: t.units,
          stt: t.stt,
          brokerage: t.allocatedCharges
        });
      });
      setScanResult(null);
    } catch (err) { console.error(err); }
  };

  const tradeSummaryPerScrip = useMemo(() => {
    if (!scanResult) return [];
    const summary: Record<string, { isin: string, scrip: string, bought: number, sold: number }> = {};
    scanResult.trades.forEach(t => {
