          {['current_month', 'all_time'].map(p => (
            <button key={p} onClick={() => setActivePeriod(p as Period)} className={`px-4 py-1.5 rounded-full text-[9px] font-black uppercase transition-all ${activePeriod === p ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500'}`}>
              {p.replace('_', ' ')}
