const CLASSIFICATIONS: AccountClassification[] = [
  'Current Asset',
  'Non-Current Asset',
  'Current Liability',
  'Non-Current Liability',
  'Equity'
];

const Accounts: React.FC = () => {
  const { filteredState, state, deleteBank, deleteCard, deleteWallet, deleteAsset, deleteLiability, addTransactionNature, deleteTransactionNature } = useFinance();
