  const handleEdit = (type: 'bank' | 'card' | 'wallet' | 'asset' | 'liability', account: any) => {
    setEditingAccount(account);
    setShowModal(type);
  };

  const handleDelete = (type: 'bank' | 'card' | 'wallet' | 'asset' | 'liability', id: string, name: string) => {
    setConfirmDelete({ id, type, name });
  };

  const executeDelete = () => {
    if (!confirmDelete) return;
    if (confirmDelete.type === 'bank') deleteBank(confirmDelete.id);
    else if (confirmDelete.type === 'card') deleteCard(confirmDelete.id);
    else if (confirmDelete.type === 'wallet') deleteWallet(confirmDelete.id);
    else if (confirmDelete.type === 'asset') deleteAsset(confirmDelete.id);
    else if (confirmDelete.type === 'liability') deleteLiability(confirmDelete.id);
    setConfirmDelete(null);
  };

  const calculateAnnualSpend = (card: CreditCard) => {
    if (!card.anniversaryDate) return { spend: 0, startDate: null, endDate: null };
    const startOfPeriod = getAnnualPeriodStart(card.anniversaryDate);
    const endOfPeriod = getAnnualPeriodEnd(startOfPeriod);
    const spend = state.transactions
      .filter(t => t.accountId === card.id && t.type === 'Expense' && new Date(t.date) >= startOfPeriod && new Date(t.date) <= endOfPeriod)
      .reduce((acc, t) => acc + t.amount, 0);
    return { spend, startDate: startOfPeriod, endDate: endOfPeriod };
  };

