                <button onClick={() => handleDelete('bank', bank.id, bank.name)} className="text-[9px] font-black uppercase text-rose-400 ml-auto">Delete</button>
              </div>
            </div>
          ))}
        </div>
      </section>

      <section>
        <div className="flex justify-between items-end mb-8">
          <div className="flex flex-col">
            <h3 className="text-lg font-bold text-slate-800 tracking-tight uppercase">Cash Wallets</h3>
            <p className="text-[10px] text-slate-400 font-medium uppercase tracking-widest">Liquid Current Assets</p>
          </div>
          <button onClick={() => { setEditingAccount(null); setShowModal('wallet'); }} className="px-5 py-3 bg-emerald-600 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest">+ Wallet</button>
        </div>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {(filteredState.wallets || []).map(wallet => (
