    else {
      let nextIds = activeMemberIds.filter(mid => mid !== 'all');
      nextIds = nextIds.includes(id) ? nextIds.filter(mid => mid !== id) : [...nextIds, id];
      setActiveMemberIds(nextIds);
    }
  };

  return (
    <div className="h-[100dvh] flex flex-col md:flex-row bg-slate-50 font-sans selection:bg-indigo-100 overflow-hidden">
      <aside className="hidden md:flex md:w-64 bg-slate-900 border-r border-slate-800 z-30 flex-col text-white sticky top-0 h-full">
        <div className="p-8 flex items-center justify-start gap-3">
             <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center font-bold">M</div>
             <h1 className="text-xl font-bold tracking-tight">MyFin</h1>
        </div>
        <nav className="flex-1 px-4 space-y-1">
          {navItems.map(item => (
            <button key={item.id} onClick={() => setActiveTab(item.id)} className={`w-full flex items-center gap-4 px-5 py-3 rounded-xl text-sm font-medium transition-all ${activeTab === item.id ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-400 hover:text-white hover:bg-slate-800'}`}>
              <span className="text-lg">{item.icon}</span>
              <span>{item.label}</span>
            </button>
          ))}
          <div className="pt-10">
             <button onClick={resetBoarding} className="w-full flex items-center gap-4 px-5 py-3 rounded-xl text-xs font-medium text-slate-500 hover:text-rose-400 transition-colors uppercase">
              <span className="text-sm">🚪</span>
              <span>Sign Out</span>
            </button>
          </div>
        </nav>
      </aside>

      <main ref={mainRef} className="flex-1 flex flex-col relative h-full overflow-y-auto overflow-x-hidden custom-scrollbar">
        <header className={`sticky top-0 bg-white/90 backdrop-blur-md border-b border-slate-200 px-4 md:px-8 z-40 flex justify-between items-center transition-all ${isShrunk ? 'h-14' : 'h-16 md:h-20'} pt-[var(--sat)]`}>
          <div className="flex items-center gap-3">
            <div className="md:hidden flex items-center gap-2">
               <div className="bg-indigo-600 w-8 h-8 rounded-lg flex items-center justify-center font-bold text-white text-sm">M</div>
            </div>
            <button onClick={() => simulateSync()} className="bg-indigo-600 text-white px-3 py-1.5 rounded-full text-[9px] font-black uppercase tracking-widest shadow-md">🔄 Sync</button>
          </div>

