import React, { useState, useMemo, useEffect } from 'react';
import { useFinance } from '../store/FinanceContext';
import { formatCurrency } from '../utils/formatters';
import { Periodicity, Budget } from '../types';

const FREQUENCIES: Periodicity[] = [
  'Daily', 'Weekly', 'Fortnightly', 'Monthly', 'Quarterly', 'Half-Yearly', 'Annually'
];

const BudgetPlanner: React.FC = () => {
  const { filteredState, state, addBudget, updateBudget, deleteBudget } = useFinance();
  const [showModal, setShowModal] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const currency = state.profile.currency;

  const [formData, setFormData] = useState<Partial<Budget> & { amountPerPeriod: number }>({
    category: '',
    amount: 0,
    amountPerPeriod: 0,
    frequency: 'Monthly',
    periodType: 'Financial',
    startDate: '',
    endDate: ''
  });

  const getPeriodDates = (type: 'Financial' | 'Calendar' | 'Custom') => {
    const now = new Date();
    const currentYear = now.getFullYear();
    if (type === 'Calendar') {
      return { start: `${currentYear}-01-01`, end: `${currentYear}-12-31` };
    } else if (type === 'Financial') {
      const startYear = now.getMonth() < 3 ? currentYear - 1 : currentYear;
      return { start: `${startYear}-04-01`, end: `${startYear + 1}-03-31` };
    }
    return { start: formData.startDate || '', end: formData.endDate || '' };
  };

  const getPeriodCount = (startStr: string, endStr: string, freq: Periodicity) => {
    if (!startStr || !endStr) return 0;
    const start = new Date(startStr);
    const end = new Date(endStr);
    if (isNaN(start.getTime()) || isNaN(end.getTime())) return 0;

    const diffMs = end.getTime() - start.getTime();
    const diffDays = Math.max(1, Math.ceil(diffMs / (1000 * 60 * 60 * 24)) + 1);

    switch (freq) {
      case 'Daily': return diffDays;
      case 'Weekly': return diffDays / 7;
      case 'Fortnightly': return diffDays / 14;
      case 'Monthly': {
        const months = (end.getFullYear() - start.getFullYear()) * 12 + (end.getMonth() - start.getMonth()) + 1;
        return Math.max(1, months);
      }
      case 'Quarterly': {
        const months = (end.getFullYear() - start.getFullYear()) * 12 + (end.getMonth() - start.getMonth()) + 1;
        return Math.max(0.3, months / 3);
      }
      case 'Half-Yearly': {
        const months = (end.getFullYear() - start.getFullYear()) * 12 + (end.getMonth() - start.getMonth()) + 1;
        return Math.max(0.1, months / 6);
      }
      case 'Annually': {
        const months = (end.getFullYear() - start.getFullYear()) * 12 + (end.getMonth() - start.getMonth()) + 1;
        return Math.max(0.08, months / 12);
      }
      default: return 1;
    }
  };

  // Recalculate total amount whenever inputs change
  useEffect(() => {
    const dates = getPeriodDates(formData.periodType as any);
    const count = getPeriodCount(dates.start, dates.end, formData.frequency as Periodicity);
    const total = (formData.amountPerPeriod || 0) * count;

    if (formData.amount !== total) {
      setFormData(prev => ({ ...prev, amount: total }));
    }
  }, [formData.amountPerPeriod, formData.frequency, formData.periodType, formData.startDate, formData.endDate]);

  const activeBudgets = filteredState.budgets || [];

  const budgetsWithActuals = useMemo(() => {
    return activeBudgets.map(budget => {
      const actual = filteredState.transactions
        .filter(t => t.type === 'Expense' && 
                     t.nature === budget.category && 
                     new Date(t.date) >= new Date(budget.startDate) && 
                     new Date(t.date) <= new Date(budget.endDate))
        .reduce((sum, t) => sum + t.amount, 0);

      return { ...budget, actual };
    });
  }, [activeBudgets, filteredState.transactions]);

  const handleOpenModal = (b?: Budget) => {
    if (b) {
      setEditingId(b.id);
      // Estimate the amount per period for the editing view
      const dates = { start: b.startDate, end: b.endDate };
      const count = getPeriodCount(dates.start, dates.end, b.frequency);
      setFormData({
        ...b,
        amountPerPeriod: count > 0 ? b.amount / count : b.amount
      });
    } else {
      setEditingId(null);
      const dates = getPeriodDates('Financial');
      setFormData({
        category: '',
        amount: 0,
        amountPerPeriod: 0,
        frequency: 'Monthly',
        periodType: 'Financial',
        startDate: dates.start,
        endDate: dates.end
      });
    }
    setShowModal(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const dates = getPeriodDates(formData.periodType as any);
    const budgetData: Budget = {
      id: editingId || Math.random().toString(36).substr(2, 9),
      category: formData.category || 'General',
      amount: Number(formData.amount),
      frequency: formData.frequency as Periodicity,
      startDate: dates.start,
      endDate: dates.end,
      periodType: formData.periodType as any,
      ownerId: ''
    };

    if (editingId) updateBudget(budgetData);
    else addBudget(budgetData);
    setShowModal(false);
  };

  const datesDisplay = getPeriodDates(formData.periodType as any);
  const periodCountDisplay = getPeriodCount(datesDisplay.start, datesDisplay.end, formData.frequency as Periodicity);

  return (
    <div className="space-y-10 animate-in fade-in duration-500 pb-20">
      <div className="flex justify-between items-end">
        <div>
          <h2 className="text-2xl md:text-3xl font-black text-slate-800 tracking-tight uppercase">Budget Architect</h2>
          <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mt-2">Strategic Resource Allocation</p>
        </div>
        <button onClick={() => handleOpenModal()} className="px-6 py-4 bg-indigo-600 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-xl shadow-indigo-100 active:scale-95 transition-all">+ New Target</button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {budgetsWithActuals.map(b => {
          const progress = Math.min(100, (b.actual / b.amount) * 100);
          const isWarning = progress > 85;
          const isOver = progress >= 100;

          return (
            <div key={b.id} className={`bg-white p-8 rounded-[2.5rem] border border-slate-200 shadow-sm transition-all hover:shadow-md relative overflow-hidden group ${isOver ? 'border-rose-200 bg-rose-50/10' : ''}`}>
              <div className="flex justify-between items-start mb-6">
                <div>
                  <h4 className="text-sm font-black text-slate-800 uppercase tracking-tight">{b.category}</h4>
                  <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mt-1">{b.frequency} Protocol</p>
                </div>
                <div className="flex gap-2">
                  <button onClick={() => handleOpenModal(b)} className="text-[10px] opacity-0 group-hover:opacity-100 transition-opacity">✎</button>
                  <button onClick={() => deleteBudget(b.id)} className="text-[10px] text-rose-400 opacity-0 group-hover:opacity-100 transition-opacity">✕</button>
                </div>
              </div>

              <div className="space-y-6">
                <div className="flex justify-between items-end">
                   <div>
                     <p className="text-[8px] font-black text-slate-400 uppercase tracking-widest">Utilized</p>
                     <p className={`text-xl font-black tracking-tighter ${isOver ? 'text-rose-600' : 'text-slate-800'}`}>{formatCurrency(b.actual, currency)}</p>
                   </div>
                   <div className="text-right">
                     <p className="text-[8px] font-black text-slate-400 uppercase tracking-widest">Target</p>
                     <p className="text-sm font-black text-slate-500">{formatCurrency(b.amount, currency)}</p>
                   </div>
                </div>

                <div className="space-y-2">
                   <div className="w-full h-3 bg-slate-100 rounded-full overflow-hidden">
                      <div 
                        className={`h-full transition-all duration-1000 ${isOver ? 'bg-rose-500' : isWarning ? 'bg-amber-400' : 'bg-indigo-600'}`}
                        style={{ width: `${progress}%` }}
                      ></div>
                   </div>
                   <div className="flex justify-between text-[8px] font-black uppercase tracking-widest">
                      <span className={isOver ? 'text-rose-500' : 'text-slate-400'}>{progress.toFixed(0)}% Burnt</span>
                      <span className="text-slate-300">{b.startDate} to {b.endDate}</span>
                   </div>
                </div>
              </div>
            </div>
          );
        })}
        {activeBudgets.length === 0 && (
          <div className="col-span-full py-20 text-center border-2 border-dashed border-slate-200 rounded-[3rem]">
            <p className="text-[10px] font-black text-slate-300 uppercase tracking-[0.3em]">No Budget Parameters Defined</p>
          </div>
        )}
      </div>

      {showModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/60 backdrop-blur-md p-4 overflow-y-auto">
          <div className="bg-white w-full max-w-xl rounded-[3rem] p-10 border border-slate-200 shadow-2xl animate-in zoom-in-95 duration-200">
            <h3 className="text-xl font-black text-slate-800 uppercase tracking-tight mb-10">Configure Target</h3>

