                 </div>
                 <div className="space-y-2">
                    <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Recurrence</label>
                    <select className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-black text-xs appearance-none" value={formData.frequency} onChange={e => setFormData({...formData, frequency: e.target.value as Periodicity})}>
                       {FREQUENCIES.map(f => <option key={f} value={f}>{f}</option>)}
                    </select>
                 </div>
              </div>

              {formData.periodType === 'Custom' && (
                <div className="grid grid-cols-2 gap-6 animate-in slide-in-from-top-4">
                   <div className="space-y-2">
                      <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">From</label>
                      <input type="date" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-black text-xs" value={formData.startDate} onChange={e => setFormData({...formData, startDate: e.target.value})} />
                   </div>
                   <div className="space-y-2">
                      <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">To</label>
                      <input type="date" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-black text-xs" value={formData.endDate} onChange={e => setFormData({...formData, endDate: e.target.value})} />
                   </div>
                </div>
              )}

              <div className="space-y-4 bg-slate-50 p-6 rounded-3xl border border-slate-100">
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Amount to Spent/Earn per {formData.frequency?.replace('-Yearly', '')}</label>
                  <input required type="number" step="any" className="w-full p-4 bg-white border border-slate-200 rounded-2xl outline-none font-black text-xl text-indigo-600 focus:ring-4 focus:ring-indigo-500/10 transition-all" value={formData.amountPerPeriod} onChange={e => setFormData({...formData, amountPerPeriod: Number(e.target.value)})} />
                </div>

                <div className="flex justify-between items-center pt-2">
                  <div className="space-y-1">
                    <p className="text-[8px] font-black text-slate-400 uppercase tracking-widest">Detected Duration</p>
                    <p className="text-[10px] font-black text-slate-700">{periodCountDisplay.toFixed(2)} {formData.frequency}s</p>
                  </div>
                  <div className="text-right space-y-1">
                    <p className="text-[8px] font-black text-indigo-400 uppercase tracking-widest">Total Period Budget</p>
                    <p className="text-xl font-black text-indigo-600">{formatCurrency(formData.amount || 0, currency)}</p>
                  </div>
                </div>
              </div>

              <div className="flex gap-4 pt-4">
                <button type="button" onClick={() => setShowModal(false)} className="flex-1 py-5 bg-slate-100 text-slate-500 font-black text-[10px] uppercase rounded-2xl">Cancel</button>
                <button type="submit" className="flex-[2] py-5 bg-indigo-600 text-white font-black text-[10px] uppercase rounded-2xl shadow-xl shadow-indigo-100">Establish Target</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default BudgetPlanner;

import React, { useState, useMemo, useEffect } from 'react';
import { useFinance } from '../store/FinanceContext';
import { formatCurrency } from '../utils/formatters';
import { Periodicity, Budget } from '../types';

const FREQUENCIES: Periodicity[] = [
  'Daily', 'Weekly', 'Fortnightly', 'Monthly', 'Quarterly', 'Half-Yearly', 'Annually'
];

const BudgetPlanner: React.FC = () => {
  const { filteredState, state, addBudget, updateBudget, deleteBudget } = useFinance();
  const [showModal, setShowModal] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const currency = state.profile.currency;

  const [formData, setFormData] = useState<Partial<Budget> & { amountPerPeriod: number }>({
    category: '',
    amount: 0,
    amountPerPeriod: 0,
    frequency: 'Monthly',
    periodType: 'Financial',
    startDate: '',
    endDate: ''
  });

  const getPeriodDates = (type: 'Financial' | 'Calendar' | 'Custom') => {
    const now = new Date();
    const currentYear = now.getFullYear();
    if (type === 'Calendar') {
      return { start: `${currentYear}-01-01`, end: `${currentYear}-12-31` };
    } else if (type === 'Financial') {
      const startYear = now.getMonth() < 3 ? currentYear - 1 : currentYear;
      return { start: `${startYear}-04-01`, end: `${startYear + 1}-03-31` };
    }
    return { start: formData.startDate || '', end: formData.endDate || '' };
  };

  const getPeriodCount = (startStr: string, endStr: string, freq: Periodicity) => {
    if (!startStr || !endStr) return 0;
    const start = new Date(startStr);
    const end = new Date(endStr);
    if (isNaN(start.getTime()) || isNaN(end.getTime())) return 0;

    const diffMs = end.getTime() - start.getTime();
    const diffDays = Math.max(1, Math.ceil(diffMs / (1000 * 60 * 60 * 24)) + 1);

    switch (freq) {
      case 'Daily': return diffDays;
      case 'Weekly': return diffDays / 7;
      case 'Fortnightly': return diffDays / 14;
      case 'Monthly': {
        const months = (end.getFullYear() - start.getFullYear()) * 12 + (end.getMonth() - start.getMonth()) + 1;
        return Math.max(1, months);
      }
      case 'Quarterly': {
        const months = (end.getFullYear() - start.getFullYear()) * 12 + (end.getMonth() - start.getMonth()) + 1;
        return Math.max(0.3, months / 3);
      }
      case 'Half-Yearly': {
        const months = (end.getFullYear() - start.getFullYear()) * 12 + (end.getMonth() - start.getMonth()) + 1;
        return Math.max(0.1, months / 6);
      }
      case 'Annually': {
        const months = (end.getFullYear() - start.getFullYear()) * 12 + (end.getMonth() - start.getMonth()) + 1;
        return Math.max(0.08, months / 12);
      }
      default: return 1;
    }
  };

  /**
   * Calculates the current period's start and end dates based on frequency.
   * E.g., if Monthly, returns the start and end of the current calendar month.
   */
  const getCurrentPeriodWindow = (freq: Periodicity) => {
    const now = new Date();
    let start = new Date(now);
    let end = new Date(now);

    switch (freq) {
      case 'Daily':
        start.setHours(0, 0, 0, 0);
        end.setHours(23, 59, 59, 999);
        break;
      case 'Weekly':
        const day = now.getDay();
        const diff = now.getDate() - day + (day === 0 ? -6 : 1); // Monday
        start = new Date(now.setDate(diff));
        start.setHours(0, 0, 0, 0);
        end = new Date(start);
        end.setDate(start.getDate() + 6);
        end.setHours(23, 59, 59, 999);
        break;
      case 'Fortnightly':
        start.setHours(0, 0, 0, 0); // Simplified for now
        end.setDate(start.getDate() + 14);
        end.setHours(23, 59, 59, 999);
        break;
      case 'Monthly':
        start = new Date(now.getFullYear(), now.getMonth(), 1);
        end = new Date(now.getFullYear(), now.getMonth() + 1, 0, 23, 59, 59);
        break;
      case 'Quarterly':
        const q = Math.floor(now.getMonth() / 3);
        start = new Date(now.getFullYear(), q * 3, 1);
        end = new Date(now.getFullYear(), (q + 1) * 3, 0, 23, 59, 59);
        break;
      case 'Half-Yearly':
        const h = now.getMonth() < 6 ? 0 : 6;
        start = new Date(now.getFullYear(), h, 1);
        end = new Date(now.getFullYear(), h + 6, 0, 23, 59, 59);
        break;
      case 'Annually':
        start = new Date(now.getFullYear(), 0, 1);
        end = new Date(now.getFullYear(), 11, 31, 23, 59, 59);
        break;
    }
    return { start, end };
  };

  useEffect(() => {
    const dates = getPeriodDates(formData.periodType as any);
    const count = getPeriodCount(dates.start, dates.end, formData.frequency as Periodicity);
    const total = (formData.amountPerPeriod || 0) * count;
    if (formData.amount !== total) {
      setFormData(prev => ({ ...prev, amount: total }));
    }
  }, [formData.amountPerPeriod, formData.frequency, formData.periodType, formData.startDate, formData.endDate]);

  const budgetsWithAnalytics = useMemo(() => {
    const now = new Date();
    return (filteredState.budgets || []).map(b => {
      const bStart = new Date(b.startDate);
      const bEnd = new Date(b.endDate);

      // 1. Full Term Actuals
      const fullTermActual = filteredState.transactions
        .filter(t => t.type === 'Expense' && t.nature === b.category && new Date(t.date) >= bStart && new Date(t.date) <= bEnd)
        .reduce((sum, t) => sum + t.amount, 0);

      // 2. Current Period Actuals
      const { start: cpStart, end: cpEnd } = getCurrentPeriodWindow(b.frequency);
      const periodActual = filteredState.transactions
        .filter(t => t.type === 'Expense' && t.nature === b.category && new Date(t.date) >= cpStart && new Date(t.date) <= cpEnd)
        .reduce((sum, t) => sum + t.amount, 0);

      const count = getPeriodCount(b.startDate, b.endDate, b.frequency);
      const budgetPerPeriod = count > 0 ? b.amount / count : b.amount;

      const isInactive = now < bStart || now > bEnd;

      return { ...b, fullTermActual, periodActual, budgetPerPeriod, isInactive };
    });
  }, [filteredState.budgets, filteredState.transactions]);

  const handleOpenModal = (b?: Budget) => {
    if (b) {
      setEditingId(b.id);
      const count = getPeriodCount(b.startDate, b.endDate, b.frequency);
      setFormData({ ...b, amountPerPeriod: count > 0 ? b.amount / count : b.amount });
    } else {
      setEditingId(null);
      const dates = getPeriodDates('Financial');
      setFormData({ category: '', amount: 0, amountPerPeriod: 0, frequency: 'Monthly', periodType: 'Financial', startDate: dates.start, endDate: dates.end });
    }
    setShowModal(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const dates = getPeriodDates(formData.periodType as any);
    const budgetData: Budget = {
      id: editingId || Math.random().toString(36).substr(2, 9),
      category: formData.category || 'General',
      amount: Number(formData.amount),
      frequency: formData.frequency as Periodicity,
      startDate: dates.start,
      endDate: dates.end,
      periodType: formData.periodType as any,
      ownerId: ''
    };
    if (editingId) updateBudget(budgetData);
    else addBudget(budgetData);
    setShowModal(false);
  };

  const datesDisplay = getPeriodDates(formData.periodType as any);
  const periodCountDisplay = getPeriodCount(datesDisplay.start, datesDisplay.end, formData.frequency as Periodicity);

  return (
    <div className="space-y-10 animate-in fade-in duration-500 pb-20">
      <div className="flex justify-between items-end px-4 md:px-0">
        <div>
          <h2 className="text-2xl md:text-3xl font-black text-slate-800 tracking-tight uppercase">Budget Architect</h2>
          <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mt-2">Strategic Resource Allocation</p>
        </div>
        <button onClick={() => handleOpenModal()} className="px-6 py-4 bg-indigo-600 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-xl shadow-indigo-100 active:scale-95 transition-all">+ Add Head</button>
      </div>

      <div className="bg-white rounded-[2.5rem] border border-slate-200 shadow-sm overflow-hidden">
        <div className="overflow-x-auto custom-scrollbar">
          <table className="w-full text-left border-collapse min-w-[1000px]">
            <thead className="bg-slate-50/50 text-slate-400 text-[9px] font-black uppercase tracking-[0.3em] border-b border-slate-100">
              <tr>
                <th className="px-8 py-6">Expense Category</th>
                <th className="px-8 py-6">Recurrence</th>
                <th className="px-8 py-6 text-right">Target (Per Period)</th>
                <th className="px-8 py-6 text-right">Actual (This Period)</th>
                <th className="px-8 py-6 text-center">Period Health</th>
                <th className="px-8 py-6 text-right">Term Budget</th>
                <th className="px-8 py-6 text-center">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {budgetsWithAnalytics.map(b => {
                const periodProgress = Math.min(100, (b.periodActual / b.budgetPerPeriod) * 100);
                const isOver = b.periodActual > b.budgetPerPeriod;
                const isWarning = periodProgress > 80;

                return (
                  <tr key={b.id} className={`hover:bg-slate-50/30 transition-colors group ${b.isInactive ? 'opacity-40 grayscale' : ''}`}>
                    <td className="px-8 py-6">
                      <p className="text-xs font-black text-slate-800 uppercase tracking-tight">{b.category}</p>
                      <p className="text-[8px] font-black text-slate-300 uppercase mt-1 tracking-widest">{b.startDate} to {b.endDate}</p>
                    </td>
                    <td className="px-8 py-6">
                       <span className="text-[9px] font-black bg-slate-100 text-slate-500 px-3 py-1 rounded-full uppercase tracking-widest">{b.frequency}</span>
                    </td>
                    <td className="px-8 py-6 text-right font-black text-xs text-indigo-600">
                      {formatCurrency(b.budgetPerPeriod, currency)}
                    </td>
                    <td className={`px-8 py-6 text-right font-black text-xs ${isOver ? 'text-rose-500' : 'text-slate-800'}`}>
                      {formatCurrency(b.periodActual, currency)}
                    </td>
                    <td className="px-8 py-6 text-center min-w-[120px]">
                       <div className="w-full h-1.5 bg-slate-100 rounded-full overflow-hidden max-w-[100px] mx-auto mb-1">
                          <div 
                            className={`h-full transition-all duration-700 ${isOver ? 'bg-rose-500' : isWarning ? 'bg-amber-400' : 'bg-emerald-500'}`}
                            style={{ width: `${periodProgress}%` }}
                          ></div>
                       </div>
                       <span className={`text-[8px] font-black uppercase tracking-widest ${isOver ? 'text-rose-400' : 'text-slate-400'}`}>
                         {periodProgress.toFixed(0)}% Burnt
                       </span>
                    </td>
                    <td className="px-8 py-6 text-right">
                       <p className="text-[10px] font-black text-slate-800">{formatCurrency(b.amount, currency)}</p>
                       <p className="text-[8px] font-black text-slate-300 uppercase tracking-widest mt-0.5">Total Allocation</p>
                    </td>
                    <td className="px-8 py-6 text-center">
                       <div className="flex items-center justify-center gap-2 opacity-0 group-hover:opacity-100 transition-all">
                          <button onClick={() => handleOpenModal(b)} className="p-2 text-indigo-400 hover:text-indigo-600">✎</button>
                          <button onClick={() => deleteBudget(b.id)} className="p-2 text-rose-300 hover:text-rose-500">✕</button>
                       </div>
                    </td>
                  </tr>
                );
              })}
              {budgetsWithAnalytics.length === 0 && (
                <tr>
                  <td colSpan={7} className="px-8 py-20 text-center text-[10px] font-black text-slate-300 uppercase tracking-[0.4em]">No active budget targets configured</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {showModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/60 backdrop-blur-md p-4 overflow-y-auto">
          <div className="bg-white w-full max-w-xl rounded-[3rem] p-10 border border-slate-200 shadow-2xl animate-in zoom-in-95 duration-200">
            <h3 className="text-xl font-black text-slate-800 uppercase tracking-tight mb-10">Target Protocol Configuration</h3>

            <form onSubmit={handleSubmit} className="space-y-8">
              <div className="space-y-2">
                <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Expense Category (Head)</label>
                <input required className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-black text-xs uppercase tracking-widest focus:ring-4 focus:ring-indigo-500/10 transition-all" value={formData.category} onChange={e => setFormData({...formData, category: e.target.value})} placeholder="e.g. DINING OUT" />
              </div>

              <div className="grid grid-cols-2 gap-6">
                 <div className="space-y-2">
                    <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Budget Span</label>
                    <select className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-black text-xs appearance-none" value={formData.periodType} onChange={e => {
                      const dates = getPeriodDates(e.target.value as any);
                      setFormData({...formData, periodType: e.target.value as any, startDate: dates.start, endDate: dates.end});
                    }}>
                       <option value="Financial">Financial Year</option>
                       <option value="Calendar">Calendar Year</option>
                       <option value="Custom">Custom Range</option>
                    </select>
                 </div>
                 <div className="space-y-2">
                    <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Tracking Frequency</label>
                    <select className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-black text-xs appearance-none" value={formData.frequency} onChange={e => setFormData({...formData, frequency: e.target.value as Periodicity})}>
                       {FREQUENCIES.map(f => <option key={f} value={f}>{f}</option>)}
                    </select>
                 </div>
              </div>

              {formData.periodType === 'Custom' && (
                <div className="grid grid-cols-2 gap-6 animate-in slide-in-from-top-4">
                   <div className="space-y-2">
                      <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">From</label>
                      <input type="date" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-black text-xs" value={formData.startDate} onChange={e => setFormData({...formData, startDate: e.target.value})} />
                   </div>
                   <div className="space-y-2">
                      <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">To</label>
                      <input type="date" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-black text-xs" value={formData.endDate} onChange={e => setFormData({...formData, endDate: e.target.value})} />
                   </div>
                </div>
              )}

              <div className="space-y-4 bg-slate-50 p-6 rounded-3xl border border-slate-100">
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Amount to Spend per {formData.frequency?.replace('-Yearly', '')}</label>
                  <input required type="number" step="any" className="w-full p-4 bg-white border border-slate-200 rounded-2xl outline-none font-black text-xl text-indigo-600 focus:ring-4 focus:ring-indigo-500/10 transition-all" value={formData.amountPerPeriod} onChange={e => setFormData({...formData, amountPerPeriod: Number(e.target.value)})} />
                </div>

                <div className="flex justify-between items-center pt-2">
                  <div className="space-y-1">
                    <p className="text-[8px] font-black text-slate-400 uppercase tracking-widest">Calculated Instances</p>
                    <p className="text-[10px] font-black text-slate-700">{periodCountDisplay.toFixed(2)} {formData.frequency}s</p>
                  </div>
                  <div className="text-right space-y-1">
                    <p className="text-[8px] font-black text-indigo-400 uppercase tracking-widest">Consolidated Term Budget</p>
                    <p className="text-xl font-black text-indigo-600">{formatCurrency(formData.amount || 0, currency)}</p>
                  </div>
                </div>
              </div>

              <div className="flex gap-4 pt-4">
                <button type="button" onClick={() => setShowModal(false)} className="flex-1 py-5 bg-slate-100 text-slate-500 font-black text-[10px] uppercase rounded-2xl">Cancel</button>
                <button type="submit" className="flex-[2] py-5 bg-indigo-600 text-white font-black text-[10px] uppercase rounded-2xl shadow-xl shadow-indigo-100">Deploy Protocol</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

