          <div className="pt-10 border-t border-slate-800/50 mt-10">
             <button onClick={() => { resetBoarding(); closeMenu(); }} className="w-full flex items-center gap-4 px-5 py-4 rounded-2xl text-[10px] font-black text-slate-500 hover:text-rose-400 hover:bg-rose-500/10 transition-colors uppercase tracking-widest">
              <span className="text-lg">🚪</span>
              <span>Sign Out</span>
            </button>
          </div>
        </nav>

        <div className="p-8 bg-slate-950/50">
           <p className="text-[8px] font-black text-slate-600 uppercase tracking-widest text-center">Protocol v2.5.0 Secure</p>
        </div>
      </aside>

      {/* Main Content Area */}
      <main ref={mainRef} className="flex-1 flex flex-col relative h-full overflow-y-auto overflow-x-hidden custom-scrollbar">

        <header className={`sticky top-0 bg-white/90 backdrop-blur-xl border-b border-slate-200 px-4 md:px-8 z-40 flex justify-between items-center transition-all ${isShrunk ? 'h-14' : 'h-16 md:h-24'} pt-[var(--sat)]`}>

          <div className="flex items-center gap-4 md:gap-6">
            {/* Hamburger Trigger */}
            <button 
              onClick={() => setIsMenuOpen(true)}
              className="w-10 h-10 md:w-12 md:h-12 bg-slate-900 text-white rounded-2xl flex flex-col items-center justify-center gap-1.5 shadow-lg active:scale-90 transition-all group"
            >
              <span className="w-5 h-0.5 bg-white rounded-full group-hover:w-6 transition-all"></span>
              <span className="w-6 h-0.5 bg-indigo-400 rounded-full"></span>
              <span className="w-5 h-0.5 bg-white rounded-full group-hover:w-6 transition-all"></span>
            </button>

            <div className="hidden md:flex flex-col">
               <h1 className="text-sm font-black text-slate-900 uppercase tracking-tighter leading-none">Command Hub</h1>
               <p className="text-[8px] font-black text-indigo-500 uppercase tracking-widest mt-1">Status: Active Verification</p>
            </div>
          </div>

          <div className="flex items-center gap-3">
            <button onClick={() => simulateSync()} className="hidden md:flex bg-indigo-600 text-white px-5 py-2.5 rounded-2xl text-[9px] font-black uppercase tracking-widest shadow-xl shadow-indigo-100 hover:bg-indigo-700 transition-all">🔄 Sync Cloud</button>

            <div className="relative" ref={selectorRef}>
              <button onClick={() => setShowMemberSelector(!showMemberSelector)} className="flex items-center gap-2 px-4 py-2.5 bg-slate-100 rounded-2xl text-[9px] font-black uppercase tracking-widest border border-slate-200 hover:bg-white transition-all">
                <span className="text-xs">👥</span>
                <span className="max-w-[70px] truncate">{getSelectionLabel()}</span>
              </button>
              {showMemberSelector && (
                <div className="absolute top-full right-0 mt-3 w-64 bg-white border border-slate-200 rounded-[2rem] shadow-2xl z-50 p-3 space-y-1 animate-in zoom-in-95 duration-200">
                    <button onClick={() => { toggleMember(''); setShowMemberSelector(false); }} className={`w-full text-left px-5 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest ${isMeSelected ? 'bg-indigo-600 text-white shadow-lg' : 'hover:bg-slate-50 text-slate-500'}`}>👤 My Vault</button>
                    <button onClick={() => { toggleMember('all'); setShowMemberSelector(false); }} className={`w-full text-left px-5 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest ${isAllSelected ? 'bg-indigo-600 text-white shadow-lg' : 'hover:bg-slate-50 text-slate-500'}`}>🌍 Consolidated</button>
                    <div className="h-px bg-slate-100 my-2"></div>
                    {familyMembers.map(m => (
                      <button key={m.id} onClick={() => { toggleMember(m.id); setShowMemberSelector(false); }} className={`w-full text-left px-5 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest ${activeMemberIds.includes(m.id) ? 'bg-indigo-600 text-white shadow-lg' : 'hover:bg-slate-50 text-slate-500'}`}>
                        {m.name}
                      </button>
                    ))}
                </div>
              )}
            </div>

            <button onClick={() => setShowNotifications(!showNotifications)} className="relative w-10 h-10 md:w-12 md:h-12 bg-slate-100 rounded-2xl text-slate-600 flex items-center justify-center hover:bg-white border border-slate-200 transition-all">
               <span className="text-xl">🔔</span>
               {unreadCount > 0 && <span className="absolute top-2 right-2 bg-rose-500 w-2.5 h-2.5 rounded-full border-2 border-white"></span>}
            </button>
          </div>
        </header>

        <div className="flex-1 p-4 md:p-12 w-full pb-20">
          {children}
        </div>

      </main>
    </div>
  );
};

export default Layout;

import React, { useState, useMemo, useEffect } from 'react';
import { useFinance } from '../store/FinanceContext';
import { formatCurrency } from '../utils/formatters';
import { Periodicity, Budget } from '../types';

const FREQUENCIES: Periodicity[] = [
  'Daily', 'Weekly', 'Fortnightly', 'Monthly', 'Quarterly', 'Half-Yearly', 'Annually'
];

type ViewWindow = 'This Month' | 'Last Month' | 'This Quarter' | 'Financial Year' | 'Custom';

const BudgetPlanner: React.FC = () => {
  const { filteredState, state, addBudget, updateBudget, deleteBudget } = useFinance();
  const [showModal, setShowModal] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const currency = state.profile.currency;

  // Global Analysis Window State
  const [viewWindowType, setViewWindowType] = useState<ViewWindow>('This Month');
  const [customViewStart, setCustomViewStart] = useState(new Date(new Date().getFullYear(), new Date().getMonth(), 1).toISOString().split('T')[0]);
  const [customViewEnd, setCustomViewEnd] = useState(new Date().toISOString().split('T')[0]);

  const [formData, setFormData] = useState<Partial<Budget> & { amountPerPeriod: number }>({
    category: '',
    amount: 0,
    amountPerPeriod: 0,
    frequency: 'Monthly',
    periodType: 'Financial',
    startDate: '',
    endDate: ''
  });

  const getPeriodDates = (type: 'Financial' | 'Calendar' | 'Custom') => {
    const now = new Date();
    const currentYear = now.getFullYear();
    if (type === 'Calendar') {
      return { start: `${currentYear}-01-01`, end: `${currentYear}-12-31` };
    } else if (type === 'Financial') {
      const startYear = now.getMonth() < 3 ? currentYear - 1 : currentYear;
      return { start: `${startYear}-04-01`, end: `${startYear + 1}-03-31` };
    }
    return { start: formData.startDate || '', end: formData.endDate || '' };
  };

  const getPeriodCount = (startStr: string, endStr: string, freq: Periodicity) => {
    if (!startStr || !endStr) return 0;
    const start = new Date(startStr);
    const end = new Date(endStr);
    if (isNaN(start.getTime()) || isNaN(end.getTime())) return 0;

    const diffMs = end.getTime() - start.getTime();
    const diffDays = Math.max(0, Math.ceil(diffMs / (1000 * 60 * 60 * 24)) + 1);

    switch (freq) {
      case 'Daily': return diffDays;
      case 'Weekly': return diffDays / 7;
      case 'Fortnightly': return diffDays / 14;
      case 'Monthly': {
        const months = (end.getFullYear() - start.getFullYear()) * 12 + (end.getMonth() - start.getMonth()) + 1;
        return Math.max(0, months);
      }
      case 'Quarterly': {
        const months = (end.getFullYear() - start.getFullYear()) * 12 + (end.getMonth() - start.getMonth()) + 1;
        return Math.max(0, months / 3);
      }
      case 'Half-Yearly': {
        const months = (end.getFullYear() - start.getFullYear()) * 12 + (end.getMonth() - start.getMonth()) + 1;
        return Math.max(0, months / 6);
      }
      case 'Annually': {
        const months = (end.getFullYear() - start.getFullYear()) * 12 + (end.getMonth() - start.getMonth()) + 1;
        return Math.max(0, months / 12);
      }
      default: return 1;
    }
  };

  const currentAnalysisWindow = useMemo(() => {
    const now = new Date();
    let start = new Date();
    let end = new Date();

    if (viewWindowType === 'This Month') {
      start = new Date(now.getFullYear(), now.getMonth(), 1);
      end = new Date(now.getFullYear(), now.getMonth() + 1, 0, 23, 59, 59);
    } else if (viewWindowType === 'Last Month') {
      start = new Date(now.getFullYear(), now.getMonth() - 1, 1);
      end = new Date(now.getFullYear(), now.getMonth(), 0, 23, 59, 59);
    } else if (viewWindowType === 'This Quarter') {
      const q = Math.floor(now.getMonth() / 3);
      start = new Date(now.getFullYear(), q * 3, 1);
      end = new Date(now.getFullYear(), (q + 1) * 3, 0, 23, 59, 59);
    } else if (viewWindowType === 'Financial') {
      const startYear = now.getMonth() < 3 ? now.getFullYear() - 1 : now.getFullYear();
      start = new Date(startYear, 3, 1);
      end = new Date(startYear + 1, 2, 31, 23, 59, 59);
    } else if (viewWindowType === 'Custom') {
      start = new Date(customViewStart);
      end = new Date(customViewEnd);
      end.setHours(23, 59, 59, 999);
    }
    return { start, end };
  }, [viewWindowType, customViewStart, customViewEnd]);

  useEffect(() => {
    const dates = getPeriodDates(formData.periodType as any);
    const count = getPeriodCount(dates.start, dates.end, formData.frequency as Periodicity);
    const total = (formData.amountPerPeriod || 0) * count;
    if (formData.amount !== total) {
      setFormData(prev => ({ ...prev, amount: total }));
    }
  }, [formData.amountPerPeriod, formData.frequency, formData.periodType, formData.startDate, formData.endDate]);

  const budgetsWithAnalytics = useMemo(() => {
    const now = new Date();
    const { start: windowStart, end: windowEnd } = currentAnalysisWindow;

    return (filteredState.budgets || []).map(b => {
      const bStart = new Date(b.startDate);
      const bEnd = new Date(b.endDate);

      // 1. Calculate the intersection of the Budget validity and the User's View Window
      const effectiveStart = new Date(Math.max(bStart.getTime(), windowStart.getTime()));
      const effectiveEnd = new Date(Math.min(bEnd.getTime(), windowEnd.getTime()));

      const hasOverlap = effectiveStart <= effectiveEnd;

      // 2. Actual Expenses in the window
      const windowActual = hasOverlap 
        ? filteredState.transactions
          .filter(t => t.type === 'Expense' && t.nature === b.category && new Date(t.date) >= effectiveStart && new Date(t.date) <= effectiveEnd)
          .reduce((sum, t) => sum + t.amount, 0)
        : 0;

      // 3. Dynamic Target for the window
      // How many units of the budget's frequency fall into this specific analysis window?
      const countInWindow = hasOverlap 
        ? getPeriodCount(effectiveStart.toISOString().split('T')[0], effectiveEnd.toISOString().split('T')[0], b.frequency)
        : 0;

      const fullCount = getPeriodCount(b.startDate, b.endDate, b.frequency);
      const amountPerFreq = fullCount > 0 ? b.amount / fullCount : b.amount;
      const dynamicTarget = amountPerFreq * countInWindow;

      const isInactive = now < bStart || now > bEnd;

      return { ...b, windowActual, dynamicTarget, amountPerFreq, isInactive, hasOverlap };
    });
  }, [filteredState.budgets, filteredState.transactions, currentAnalysisWindow]);

  const handleOpenModal = (b?: Budget) => {
    if (b) {
      setEditingId(b.id);
      const count = getPeriodCount(b.startDate, b.endDate, b.frequency);
      setFormData({ ...b, amountPerPeriod: count > 0 ? b.amount / count : b.amount });
    } else {
      setEditingId(null);
      const dates = getPeriodDates('Financial');
      setFormData({ category: '', amount: 0, amountPerPeriod: 0, frequency: 'Monthly', periodType: 'Financial', startDate: dates.start, endDate: dates.end });
    }
    setShowModal(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const dates = getPeriodDates(formData.periodType as any);
    const budgetData: Budget = {
      id: editingId || Math.random().toString(36).substr(2, 9),
      category: formData.category || 'General',
      amount: Number(formData.amount),
      frequency: formData.frequency as Periodicity,
      startDate: dates.start,
      endDate: dates.end,
      periodType: formData.periodType as any,
      ownerId: ''
    };
    if (editingId) updateBudget(budgetData);
    else addBudget(budgetData);
    setShowModal(false);
  };

  const datesDisplay = getPeriodDates(formData.periodType as any);
  const periodCountDisplay = getPeriodCount(datesDisplay.start, datesDisplay.end, formData.frequency as Periodicity);

  return (
    <div className="space-y-10 animate-in fade-in duration-500 pb-20">
      {/* Header Section */}
      <div className="flex flex-col md:flex-row md:items-end justify-between gap-6 px-4 md:px-0">
        <div>
          <h2 className="text-2xl md:text-3xl font-black text-slate-800 tracking-tight uppercase">Budget Architect</h2>
          <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mt-2">Strategic Resource Allocation</p>
        </div>

        <div className="flex flex-wrap items-center gap-2">
           <button onClick={() => handleOpenModal()} className="px-6 py-4 bg-indigo-600 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-xl shadow-indigo-100 active:scale-95 transition-all">+ Add Head</button>
        </div>
      </div>

      {/* Analysis Window Selector */}
      <div className="bg-white p-2 rounded-[2rem] border border-slate-200 shadow-sm flex flex-col md:flex-row md:items-center justify-between gap-4">
          <div className="flex flex-wrap items-center gap-1 p-1 bg-slate-50/50 rounded-2xl">
            {(['This Month', 'Last Month', 'This Quarter', 'Financial Year', 'Custom'] as ViewWindow[]).map(type => (
              <button 
                key={type} 
                onClick={() => setViewWindowType(type)}
                className={`px-4 py-2.5 rounded-xl text-[9px] font-black uppercase tracking-widest transition-all ${viewWindowType === type ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-400 hover:text-slate-600'}`}
              >
                {type}
              </button>
            ))}
          </div>

          {viewWindowType === 'Custom' ? (
            <div className="flex items-center gap-3 px-4 animate-in slide-in-from-right-4 duration-300">
               <input type="date" className="bg-slate-50 border border-slate-200 rounded-xl px-3 py-2 text-[10px] font-black outline-none" value={customViewStart} onChange={e => setCustomViewStart(e.target.value)} />
               <span className="text-slate-300 font-bold">to</span>
               <input type="date" className="bg-slate-50 border border-slate-200 rounded-xl px-3 py-2 text-[10px] font-black outline-none" value={customViewEnd} onChange={e => setCustomViewEnd(e.target.value)} />
            </div>
          ) : (
            <div className="px-6 py-2 text-right hidden md:block">
               <p className="text-[8px] font-black text-slate-400 uppercase tracking-widest">Active Audit Range</p>
               <p className="text-[10px] font-black text-indigo-600 uppercase mt-1">
                 {currentAnalysisWindow.start.toLocaleDateString()} — {currentAnalysisWindow.end.toLocaleDateString()}
               </p>
            </div>
          )}
      </div>

      {/* Budget Comparison Table */}
      <div className="bg-white rounded-[2.5rem] border border-slate-200 shadow-sm overflow-hidden">
        <div className="overflow-x-auto custom-scrollbar">
          <table className="w-full text-left border-collapse min-w-[1100px]">
            <thead className="bg-slate-50/50 text-slate-400 text-[9px] font-black uppercase tracking-[0.3em] border-b border-slate-100">
              <tr>
                <th className="px-8 py-6">Expense Category</th>
                <th className="px-8 py-6">Recurrence</th>
                <th className="px-8 py-6 text-right">Target (For Period)</th>
                <th className="px-8 py-6 text-right">Actual (In Window)</th>
                <th className="px-8 py-6 text-center">Efficiency Health</th>
                <th className="px-8 py-6 text-right">Term Goal</th>
                <th className="px-8 py-6 text-center">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {budgetsWithAnalytics.map(b => {
                const efficiency = b.dynamicTarget > 0 ? Math.min(100, (b.windowActual / b.dynamicTarget) * 100) : (b.windowActual > 0 ? 100 : 0);
                const isOver = b.windowActual > b.dynamicTarget;
                const isWarning = efficiency > 80;

                return (
                  <tr key={b.id} className={`hover:bg-slate-50/30 transition-colors group ${b.isInactive ? 'opacity-40 grayscale' : ''} ${!b.hasOverlap ? 'bg-slate-50/20' : ''}`}>
                    <td className="px-8 py-6">
                      <p className="text-xs font-black text-slate-800 uppercase tracking-tight">{b.category}</p>
                      <p className="text-[8px] font-black text-slate-300 uppercase mt-1 tracking-widest">
                        {b.startDate} to {b.endDate}
                      </p>
                    </td>
                    <td className="px-8 py-6">
                       <div className="flex flex-col">
                          <span className="text-[9px] font-black bg-slate-100 text-slate-500 px-3 py-1 rounded-full uppercase tracking-widest w-fit">{b.frequency}</span>
                          <span className="text-[7px] font-bold text-slate-300 mt-1 uppercase">Per {b.frequency}: {formatCurrency(b.amountPerFreq, currency)}</span>
                       </div>
                    </td>
                    <td className="px-8 py-6 text-right font-black text-xs text-indigo-600">
                      {formatCurrency(b.dynamicTarget, currency)}
                    </td>
                    <td className={`px-8 py-6 text-right font-black text-xs ${isOver ? 'text-rose-500' : 'text-slate-800'}`}>
                      {formatCurrency(b.windowActual, currency)}
                    </td>
                    <td className="px-8 py-6 text-center min-w-[140px]">
                       {!b.hasOverlap ? (
                         <span className="text-[8px] font-black text-slate-300 uppercase tracking-widest italic">Out of Range</span>
                       ) : (
                         <>
                           <div className="w-full h-1.5 bg-slate-100 rounded-full overflow-hidden max-w-[100px] mx-auto mb-1">
                              <div 
                                className={`h-full transition-all duration-700 ${isOver ? 'bg-rose-500 shadow-[0_0_8px_rgba(244,63,94,0.4)]' : isWarning ? 'bg-amber-400' : 'bg-emerald-500'}`}
                                style={{ width: `${efficiency}%` }}
                              ></div>
                           </div>
                           <span className={`text-[8px] font-black uppercase tracking-widest ${isOver ? 'text-rose-400' : 'text-slate-400'}`}>
                             {efficiency.toFixed(0)}% Utilized
                           </span>
                         </>
                       )}
                    </td>
                    <td className="px-8 py-6 text-right">
                       <p className="text-[10px] font-black text-slate-800">{formatCurrency(b.amount, currency)}</p>
                       <p className="text-[8px] font-black text-slate-300 uppercase tracking-widest mt-0.5">Projected Cap</p>
                    </td>
                    <td className="px-8 py-6 text-center">
                       <div className="flex items-center justify-center gap-2 opacity-0 group-hover:opacity-100 transition-all">
                          <button onClick={() => handleOpenModal(b)} className="p-2 text-indigo-400 hover:text-indigo-600 active:scale-90 transition-transform">✎</button>
                          <button onClick={() => deleteBudget(b.id)} className="p-2 text-rose-300 hover:text-rose-500 active:scale-90 transition-transform">✕</button>
                       </div>
                    </td>
                  </tr>
                );
              })}
              {budgetsWithAnalytics.length === 0 && (
                <tr>
                  <td colSpan={7} className="px-8 py-24 text-center">
                    <div className="flex flex-col items-center gap-4">
                      <div className="w-16 h-16 bg-slate-50 rounded-full flex items-center justify-center text-3xl">🏗️</div>
                      <p className="text-[10px] font-black text-slate-300 uppercase tracking-[0.4em]">No active budget targets configured</p>
                      <button onClick={() => handleOpenModal()} className="mt-2 text-[9px] font-black text-indigo-600 uppercase underline tracking-widest">Initialise First Target</button>
                    </div>
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {showModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/60 backdrop-blur-md p-4 overflow-y-auto">
          <div className="bg-white w-full max-w-xl rounded-[3rem] p-10 border border-slate-200 shadow-2xl animate-in zoom-in-95 duration-200">
            <div className="flex justify-between items-center mb-10">
              <h3 className="text-xl font-black text-slate-800 uppercase tracking-tight">Protocol Definition</h3>
              <button onClick={() => setShowModal(false)} className="text-slate-300 hover:text-slate-800 font-black text-2xl transition-colors">✕</button>
            </div>

            <form onSubmit={handleSubmit} className="space-y-8">
              <div className="space-y-2">
                <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Expense Category (Head)</label>
                <input required className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-black text-xs uppercase tracking-widest focus:ring-4 focus:ring-indigo-500/10 transition-all" value={formData.category} onChange={e => setFormData({...formData, category: e.target.value})} placeholder="e.g. DINING OUT" />
              </div>

              <div className="grid grid-cols-2 gap-6">
                 <div className="space-y-2">
                    <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Budget Span</label>
                    <select className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-black text-xs appearance-none cursor-pointer" value={formData.periodType} onChange={e => {
                      const dates = getPeriodDates(e.target.value as any);
                      setFormData({...formData, periodType: e.target.value as any, startDate: dates.start, endDate: dates.end});
                    }}>
                       <option value="Financial">Financial Year</option>
                       <option value="Calendar">Calendar Year</option>
                       <option value="Custom">Custom Range</option>
                    </select>
                 </div>
                 <div className="space-y-2">
                    <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Frequency Unit</label>
                    <select className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-black text-xs appearance-none cursor-pointer" value={formData.frequency} onChange={e => setFormData({...formData, frequency: e.target.value as Periodicity})}>
                       {FREQUENCIES.map(f => <option key={f} value={f}>{f}</option>)}
                    </select>
                 </div>
              </div>

              {(formData.periodType === 'Custom' || formData.periodType === 'Financial' || formData.periodType === 'Calendar') && (
                <div className="grid grid-cols-2 gap-6 animate-in slide-in-from-top-4">
                   <div className="space-y-2">
                      <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Effective From</label>
                      <input type="date" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-black text-xs" value={formData.startDate} onChange={e => setFormData({...formData, startDate: e.target.value})} />
                   </div>
                   <div className="space-y-2">
                      <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Effective To</label>
                      <input type="date" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-black text-xs" value={formData.endDate} onChange={e => setFormData({...formData, endDate: e.target.value})} />
                   </div>
                </div>
              )}

              <div className="space-y-4 bg-indigo-50/30 p-8 rounded-[2rem] border border-indigo-100">
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-indigo-400 uppercase tracking-widest block ml-2">Amount to Spent per {formData.frequency?.replace('-Yearly', '')}</label>
                  <input required type="number" step="any" className="w-full p-4 bg-white border border-indigo-200 rounded-2xl outline-none font-black text-2xl text-indigo-600 focus:ring-4 focus:ring-indigo-500/10 transition-all" value={formData.amountPerPeriod} onChange={e => setFormData({...formData, amountPerPeriod: Number(e.target.value)})} />
                </div>

                <div className="flex justify-between items-center pt-2">
                  <div className="space-y-1">
                    <p className="text-[8px] font-black text-slate-400 uppercase tracking-widest">Instance Count</p>
                    <p className="text-[10px] font-black text-slate-700">{periodCountDisplay.toFixed(2)} Occurrences</p>
                  </div>
                  <div className="text-right space-y-1">
                    <p className="text-[8px] font-black text-indigo-400 uppercase tracking-widest">Total Committed Budget</p>
                    <p className="text-2xl font-black text-indigo-600">{formatCurrency(formData.amount || 0, currency)}</p>
                  </div>
                </div>
              </div>

              <div className="flex gap-4 pt-4">
                <button type="button" onClick={() => setShowModal(false)} className="flex-1 py-5 bg-slate-100 text-slate-500 font-black text-[10px] uppercase rounded-2xl">Abort</button>
                <button type="submit" className="flex-[2] py-5 bg-indigo-600 text-white font-black text-[10px] uppercase rounded-2xl shadow-xl shadow-indigo-100 transition-all">Establish Goal</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default BudgetPlanner;

import React, { useState, useMemo, useEffect } from 'react';
import { useFinance } from '../store/FinanceContext';
import { formatCurrency } from '../utils/formatters';
import { Periodicity, Budget } from '../types';

const FREQUENCIES: Periodicity[] = [
  'Daily', 'Weekly', 'Fortnightly', 'Monthly', 'Quarterly', 'Half-Yearly', 'Annually'
];

type ViewWindow = 'This Month' | 'Last Month' | 'This Quarter' | 'Financial Year' | 'Custom';

/**
 * Frequency to Days mapping for normalized pro-rata calculations.
 * Using standard financial/commercial values:
 * Month = 30 days, Year = 365 days, Quarter = 91 days.
 */
const FREQ_DAYS: Record<Periodicity, number> = {
  'Daily': 1,
  'Weekly': 7,
  'Fortnightly': 14,
  'Monthly': 30,
  'Quarterly': 91.25,
  'Half-Yearly': 182.5,
  'Annually': 365
};

const BudgetPlanner: React.FC = () => {
  const { filteredState, state, addBudget, updateBudget, deleteBudget } = useFinance();
  const [showModal, setShowModal] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const currency = state.profile.currency;

  // Global Analysis Window State
  const [viewWindowType, setViewWindowType] = useState<ViewWindow>('This Month');
  const [customViewStart, setCustomViewStart] = useState(new Date(new Date().getFullYear(), new Date().getMonth(), 1).toISOString().split('T')[0]);
  const [customViewEnd, setCustomViewEnd] = useState(new Date().toISOString().split('T')[0]);

  const [formData, setFormData] = useState<Partial<Budget> & { amountPerPeriod: number }>({
    category: '',
    amount: 0,
    amountPerPeriod: 0,
    frequency: 'Monthly',
    periodType: 'Financial',
    startDate: '',
    endDate: ''
  });

  const getPeriodDates = (type: 'Financial' | 'Calendar' | 'Custom') => {
    const now = new Date();
    const currentYear = now.getFullYear();
    if (type === 'Calendar') {
      return { start: `${currentYear}-01-01`, end: `${currentYear}-12-31` };
    } else if (type === 'Financial') {
      const startYear = now.getMonth() < 3 ? currentYear - 1 : currentYear;
      return { start: `${startYear}-04-01`, end: `${startYear + 1}-03-31` };
    }
    return { start: formData.startDate || '', end: formData.endDate || '' };
  };

  /**
   * Calculates the floating point number of periods based on total days between two dates.
   * This provides the most accurate pro-rata calculation for dynamic targets.
   */
  const getPeriodCount = (startStr: string, endStr: string, freq: Periodicity) => {
    if (!startStr || !endStr) return 0;
    const start = new Date(startStr);
    const end = new Date(endStr);
    if (isNaN(start.getTime()) || isNaN(end.getTime())) return 0;

    // Normalize dates to midnight to ensure exact day count
    const d1 = new Date(start.getFullYear(), start.getMonth(), start.getDate());
    const d2 = new Date(end.getFullYear(), end.getMonth(), end.getDate());

    const diffMs = d2.getTime() - d1.getTime();
    // Inclusive day count
    const diffDays = Math.max(0, (diffMs / (1000 * 60 * 60 * 24)) + 1);

    return diffDays / FREQ_DAYS[freq];
  };

  const currentAnalysisWindow = useMemo(() => {
    const now = new Date();
    let start = new Date();
    let end = new Date();

    if (viewWindowType === 'This Month') {
      start = new Date(now.getFullYear(), now.getMonth(), 1);
      end = new Date(now.getFullYear(), now.getMonth() + 1, 0, 23, 59, 59);
    } else if (viewWindowType === 'Last Month') {
      start = new Date(now.getFullYear(), now.getMonth() - 1, 1);
      end = new Date(now.getFullYear(), now.getMonth(), 0, 23, 59, 59);
    } else if (viewWindowType === 'This Quarter') {
      const q = Math.floor(now.getMonth() / 3);
      start = new Date(now.getFullYear(), q * 3, 1);
      end = new Date(now.getFullYear(), (q + 1) * 3, 0, 23, 59, 59);
    } else if (viewWindowType === 'Financial') {
      const startYear = now.getMonth() < 3 ? now.getFullYear() - 1 : now.getFullYear();
      start = new Date(startYear, 3, 1);
      end = new Date(startYear + 1, 2, 31, 23, 59, 59);
    } else if (viewWindowType === 'Custom') {
      start = new Date(customViewStart);
      end = new Date(customViewEnd);
      end.setHours(23, 59, 59, 999);
    }
    return { start, end };
  }, [viewWindowType, customViewStart, customViewEnd]);

  // Recalculate total budget based on duration and amount per period
  useEffect(() => {
    const dates = getPeriodDates(formData.periodType as any);
    const count = getPeriodCount(dates.start, dates.end, formData.frequency as Periodicity);
    const total = (formData.amountPerPeriod || 0) * count;
    if (Math.abs(formData.amount - total) > 0.01) {
      setFormData(prev => ({ ...prev, amount: total }));
    }
  }, [formData.amountPerPeriod, formData.frequency, formData.periodType, formData.startDate, formData.endDate]);

  const budgetsWithAnalytics = useMemo(() => {
    const now = new Date();
    const { start: windowStart, end: windowEnd } = currentAnalysisWindow;

    return (filteredState.budgets || []).map(b => {
      const bStart = new Date(b.startDate);
      const bEnd = new Date(b.endDate);

      // 1. Calculate the intersection of the Budget validity and the User's View Window
      const effectiveStart = new Date(Math.max(bStart.getTime(), windowStart.getTime()));
      const effectiveEnd = new Date(Math.min(bEnd.getTime(), windowEnd.getTime()));

      const hasOverlap = effectiveStart <= effectiveEnd;

      // 2. Actual Expenses in the window
      const windowActual = hasOverlap 
        ? (filteredState.transactions || [])
          .filter(t => t.type === 'Expense' && t.nature === b.category && new Date(t.date) >= effectiveStart && new Date(t.date) <= effectiveEnd)
          .reduce((sum, t) => sum + t.amount, 0)
        : 0;

      // 3. CORRECT DYNAMIC TARGET:
      // (Total Term Budget / Total Term Days) * Total Days in the Current Analysis Window (within term)
      const budgetStart = new Date(b.startDate);
      const budgetEnd = new Date(b.endDate);
      const budgetTermMs = budgetEnd.getTime() - budgetStart.getTime();
      const budgetTermDays = Math.max(1, (budgetTermMs / (1000 * 60 * 60 * 24)) + 1);

      const windowMs = effectiveEnd.getTime() - effectiveStart.getTime();
      const windowDays = hasOverlap ? Math.max(0, (windowMs / (1000 * 60 * 60 * 24)) + 1) : 0;

      const dynamicTarget = (b.amount / budgetTermDays) * windowDays;

      // Display metric: amount per single frequency unit (e.g. Monthly rate)
      const amountPerFreq = b.amount / (budgetTermDays / FREQ_DAYS[b.frequency]);

      const isInactive = now < bStart || now > bEnd;

      return { ...b, windowActual, dynamicTarget, amountPerFreq, isInactive, hasOverlap };
    });
  }, [filteredState.budgets, filteredState.transactions, currentAnalysisWindow]);

  const handleOpenModal = (b?: Budget) => {
    if (b) {
      setEditingId(b.id);
      const count = getPeriodCount(b.startDate, b.endDate, b.frequency);
      setFormData({ ...b, amountPerPeriod: count > 0 ? b.amount / count : b.amount });
    } else {
      setEditingId(null);
      const dates = getPeriodDates('Financial');
      setFormData({ category: '', amount: 0, amountPerPeriod: 0, frequency: 'Monthly', periodType: 'Financial', startDate: dates.start, endDate: dates.end });
    }
    setShowModal(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const dates = getPeriodDates(formData.periodType as any);
    const budgetData: Budget = {
      id: editingId || Math.random().toString(36).substr(2, 9),
      category: formData.category || 'General',
      amount: Number(formData.amount),
      frequency: formData.frequency as Periodicity,
      startDate: dates.start,
      endDate: dates.end,
      periodType: formData.periodType as any,
      ownerId: ''
    };
    if (editingId) updateBudget(budgetData);
    else addBudget(budgetData);
    setShowModal(false);
  };

  const datesDisplay = getPeriodDates(formData.periodType as any);
  const periodCountDisplay = getPeriodCount(datesDisplay.start, datesDisplay.end, formData.frequency as Periodicity);

  return (
    <div className="space-y-10 animate-in fade-in duration-500 pb-20">
      {/* Header Section */}
      <div className="flex flex-col md:flex-row md:items-end justify-between gap-6 px-4 md:px-0">
        <div>
          <h2 className="text-2xl md:text-3xl font-black text-slate-800 tracking-tight uppercase">Budget Architect</h2>
          <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mt-2">Strategic Resource Allocation</p>
        </div>

        <div className="flex flex-wrap items-center gap-2">
           <button onClick={() => handleOpenModal()} className="px-6 py-4 bg-indigo-600 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-xl shadow-indigo-100 active:scale-95 transition-all">+ Add Head</button>
        </div>
      </div>

      {/* Analysis Window Selector */}
      <div className="bg-white p-2 rounded-[2rem] border border-slate-200 shadow-sm flex flex-col md:flex-row md:items-center justify-between gap-4">
          <div className="flex flex-wrap items-center gap-1 p-1 bg-slate-50/50 rounded-2xl">
            {(['This Month', 'Last Month', 'This Quarter', 'Financial Year', 'Custom'] as ViewWindow[]).map(type => (
              <button 
                key={type} 
                onClick={() => setViewWindowType(type)}
                className={`px-4 py-2.5 rounded-xl text-[9px] font-black uppercase tracking-widest transition-all ${viewWindowType === type ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-400 hover:text-slate-600'}`}
              >
                {type}
              </button>
            ))}
          </div>

          {viewWindowType === 'Custom' ? (
            <div className="flex items-center gap-3 px-4 animate-in slide-in-from-right-4 duration-300">
               <input type="date" className="bg-slate-50 border border-slate-200 rounded-xl px-3 py-2 text-[10px] font-black outline-none" value={customViewStart} onChange={e => setCustomViewStart(e.target.value)} />
               <span className="text-slate-300 font-bold">to</span>
               <input type="date" className="bg-slate-50 border border-slate-200 rounded-xl px-3 py-2 text-[10px] font-black outline-none" value={customViewEnd} onChange={e => setCustomViewEnd(e.target.value)} />
            </div>
          ) : (
            <div className="px-6 py-2 text-right hidden md:block">
               <p className="text-[8px] font-black text-slate-400 uppercase tracking-widest">Active Audit Range</p>
               <p className="text-[10px] font-black text-indigo-600 uppercase mt-1">
                 {currentAnalysisWindow.start.toLocaleDateString()} — {currentAnalysisWindow.end.toLocaleDateString()}
               </p>
            </div>
          )}
      </div>

      {/* Budget Comparison Table */}
      <div className="bg-white rounded-[2.5rem] border border-slate-200 shadow-sm overflow-hidden">
        <div className="overflow-x-auto custom-scrollbar">
          <table className="w-full text-left border-collapse min-w-[1100px]">
            <thead className="bg-slate-50/50 text-slate-400 text-[9px] font-black uppercase tracking-[0.3em] border-b border-slate-100">
              <tr>
                <th className="px-8 py-6">Expense Category</th>
                <th className="px-8 py-6">Recurrence</th>
                <th className="px-8 py-6 text-right">Target (For Period)</th>
                <th className="px-8 py-6 text-right">Actual (In Window)</th>
                <th className="px-8 py-6 text-center">Efficiency Health</th>
                <th className="px-8 py-6 text-right">Term Goal</th>
                <th className="px-8 py-6 text-center">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {budgetsWithAnalytics.map(b => {
                const efficiency = b.dynamicTarget > 0 ? Math.min(100, (b.windowActual / b.dynamicTarget) * 100) : (b.windowActual > 0 ? 100 : 0);
                const isOver = b.windowActual > b.dynamicTarget;
                const isWarning = efficiency > 80;

                return (
                  <tr key={b.id} className={`hover:bg-slate-50/30 transition-colors group ${b.isInactive ? 'opacity-40 grayscale' : ''} ${!b.hasOverlap ? 'bg-slate-50/20' : ''}`}>
                    <td className="px-8 py-6">
                      <p className="text-xs font-black text-slate-800 uppercase tracking-tight">{b.category}</p>
                      <p className="text-[8px] font-black text-slate-300 uppercase mt-1 tracking-widest">
                        {b.startDate} to {b.endDate}
                      </p>
                    </td>
                    <td className="px-8 py-6">
                       <div className="flex flex-col">
                          <span className="text-[9px] font-black bg-slate-100 text-slate-500 px-3 py-1 rounded-full uppercase tracking-widest w-fit">{b.frequency}</span>
                          <span className="text-[7px] font-bold text-slate-300 mt-1 uppercase">Per {b.frequency}: {formatCurrency(b.amountPerFreq, currency)}</span>
                       </div>
                    </td>
                    <td className="px-8 py-6 text-right font-black text-xs text-indigo-600">
                      {formatCurrency(b.dynamicTarget, currency)}
                    </td>
                    <td className={`px-8 py-6 text-right font-black text-xs ${isOver ? 'text-rose-500' : 'text-slate-800'}`}>
                      {formatCurrency(b.windowActual, currency)}
                    </td>
                    <td className="px-8 py-6 text-center min-w-[140px]">
                       {!b.hasOverlap ? (
                         <span className="text-[8px] font-black text-slate-300 uppercase tracking-widest italic">Out of Range</span>
                       ) : (
                         <>
                           <div className="w-full h-1.5 bg-slate-100 rounded-full overflow-hidden max-w-[100px] mx-auto mb-1">
                              <div 
                                className={`h-full transition-all duration-700 ${isOver ? 'bg-rose-500 shadow-[0_0_8px_rgba(244,63,94,0.4)]' : isWarning ? 'bg-amber-400' : 'bg-emerald-500'}`}
                                style={{ width: `${efficiency}%` }}
                              ></div>
                           </div>
                           <span className={`text-[8px] font-black uppercase tracking-widest ${isOver ? 'text-rose-400' : 'text-slate-400'}`}>
                             {efficiency.toFixed(0)}% Utilized
                           </span>
                         </>
                       )}
                    </td>
                    <td className="px-8 py-6 text-right">
                       <p className="text-[10px] font-black text-slate-800">{formatCurrency(b.amount, currency)}</p>
                       <p className="text-[8px] font-black text-slate-300 uppercase tracking-widest mt-0.5">Projected Cap</p>
                    </td>
                    <td className="px-8 py-6 text-center">
                       <div className="flex items-center justify-center gap-2 opacity-0 group-hover:opacity-100 transition-all">
                          <button onClick={() => handleOpenModal(b)} className="p-2 text-indigo-400 hover:text-indigo-600 active:scale-90 transition-transform">✎</button>
                          <button onClick={() => deleteBudget(b.id)} className="p-2 text-rose-300 hover:text-rose-500 active:scale-90 transition-transform">✕</button>
                       </div>
                    </td>
                  </tr>
                );
              })}
              {budgetsWithAnalytics.length === 0 && (
                <tr>
                  <td colSpan={7} className="px-8 py-24 text-center">
                    <div className="flex flex-col items-center gap-4">
                      <div className="w-16 h-16 bg-slate-50 rounded-full flex items-center justify-center text-3xl">🏗️</div>
                      <p className="text-[10px] font-black text-slate-300 uppercase tracking-[0.4em]">No active budget targets configured</p>
                      <button onClick={() => handleOpenModal()} className="mt-2 text-[9px] font-black text-indigo-600 uppercase underline tracking-widest">Initialise First Target</button>
                    </div>
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {showModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/60 backdrop-blur-md p-4 overflow-y-auto">
          <div className="bg-white w-full max-w-xl rounded-[3rem] p-10 border border-slate-200 shadow-2xl animate-in zoom-in-95 duration-200">
            <div className="flex justify-between items-center mb-10">
              <h3 className="text-xl font-black text-slate-800 uppercase tracking-tight">Protocol Definition</h3>
              <button onClick={() => setShowModal(false)} className="text-slate-300 hover:text-slate-800 font-black text-2xl transition-colors">✕</button>
            </div>

            <form onSubmit={handleSubmit} className="space-y-8">
              <div className="space-y-2">
                <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Expense Category (Head)</label>
                <input required className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-black text-xs uppercase tracking-widest focus:ring-4 focus:ring-indigo-500/10 transition-all" value={formData.category} onChange={e => setFormData({...formData, category: e.target.value})} placeholder="e.g. DINING OUT" />
              </div>

              <div className="grid grid-cols-2 gap-6">
                 <div className="space-y-2">
                    <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Budget Span</label>
                    <select className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-black text-xs appearance-none cursor-pointer" value={formData.periodType} onChange={e => {
                      const dates = getPeriodDates(e.target.value as any);
                      setFormData({...formData, periodType: e.target.value as any, startDate: dates.start, endDate: dates.end});
                    }}>
                       <option value="Financial">Financial Year</option>
                       <option value="Calendar">Calendar Year</option>
                       <option value="Custom">Custom Range</option>
                    </select>
                 </div>
                 <div className="space-y-2">
                    <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Frequency Unit</label>
                    <select className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-black text-xs appearance-none cursor-pointer" value={formData.frequency} onChange={e => setFormData({...formData, frequency: e.target.value as Periodicity})}>
                       {FREQUENCIES.map(f => <option key={f} value={f}>{f}</option>)}
                    </select>
                 </div>
              </div>

              {(formData.periodType === 'Custom' || formData.periodType === 'Financial' || formData.periodType === 'Calendar') && (
                <div className="grid grid-cols-2 gap-6 animate-in slide-in-from-top-4">
                   <div className="space-y-2">
                      <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Effective From</label>
                      <input type="date" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-black text-xs" value={formData.startDate} onChange={e => setFormData({...formData, startDate: e.target.value})} />
                   </div>
                   <div className="space-y-2">
                      <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Effective To</label>
                      <input type="date" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-black text-xs" value={formData.endDate} onChange={e => setFormData({...formData, endDate: e.target.value})} />
                   </div>
                </div>
              )}

              <div className="space-y-4 bg-indigo-50/30 p-8 rounded-[2rem] border border-indigo-100">
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-indigo-400 uppercase tracking-widest block ml-2">Amount to Spent per {formData.frequency?.replace('-Yearly', '')}</label>
                  <input required type="number" step="any" className="w-full p-4 bg-white border border-indigo-200 rounded-2xl outline-none font-black text-2xl text-indigo-600 focus:ring-4 focus:ring-indigo-500/10 transition-all" value={formData.amountPerPeriod} onChange={e => setFormData({...formData, amountPerPeriod: Number(e.target.value)})} />
                </div>

                <div className="flex justify-between items-center pt-2">
                  <div className="space-y-1">
                    <p className="text-[8px] font-black text-slate-400 uppercase tracking-widest">Instance Count</p>
                    <p className="text-[10px] font-black text-slate-700">{periodCountDisplay.toFixed(2)} Occurrences</p>
                  </div>
                  <div className="text-right space-y-1">
                    <p className="text-[8px] font-black text-indigo-400 uppercase tracking-widest">Total Committed Budget</p>
                    <p className="text-2xl font-black text-indigo-600">{formatCurrency(formData.amount || 0, currency)}</p>
                  </div>
                </div>
              </div>

              <div className="flex gap-4 pt-4">
                <button type="button" onClick={() => setShowModal(false)} className="flex-1 py-5 bg-slate-100 text-slate-500 font-black text-[10px] uppercase rounded-2xl">Abort</button>
                <button type="submit" className="flex-[2] py-5 bg-indigo-600 text-white font-black text-[10px] uppercase rounded-2xl shadow-xl shadow-indigo-100 transition-all">Establish Goal</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

