import React, { useState, useMemo, useEffect } from 'react';
import { useFinance } from '../store/FinanceContext';
import { formatCurrency } from '../utils/formatters';
import { Periodicity, Budget } from '../types';

const FREQUENCIES: Periodicity[] = [
  'Daily', 'Weekly', 'Fortnightly', 'Monthly', 'Quarterly', 'Half-Yearly', 'Annually'
];

type ViewWindow = 'This Month' | 'Last Month' | 'This Quarter' | 'Financial Year' | 'Custom';

const BudgetPlanner: React.FC = () => {
  const { filteredState, state, addBudget, updateBudget, deleteBudget } = useFinance();
  const [showModal, setShowModal] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const currency = state.profile.currency;

  // Global Analysis Window State
  const [viewWindowType, setViewWindowType] = useState<ViewWindow>('This Month');
  const [customViewStart, setCustomViewStart] = useState(new Date(new Date().getFullYear(), new Date().getMonth(), 1).toISOString().split('T')[0]);
  const [customViewEnd, setCustomViewEnd] = useState(new Date().toISOString().split('T')[0]);

  const [formData, setFormData] = useState<Partial<Budget> & { amountPerPeriod: number }>({
    category: '',
    amount: 0,
    amountPerPeriod: 0,
    frequency: 'Monthly',
    periodType: 'Financial',
    startDate: '',
    endDate: ''
  });

  const getPeriodDates = (type: 'Financial' | 'Calendar' | 'Custom') => {
    const now = new Date();
    const currentYear = now.getFullYear();
    if (type === 'Calendar') {
      return { start: `${currentYear}-01-01`, end: `${currentYear}-12-31` };
    } else if (type === 'Financial') {
      const startYear = now.getMonth() < 3 ? currentYear - 1 : currentYear;
      return { start: `${startYear}-04-01`, end: `${startYear + 1}-03-31` };
    }
    return { start: formData.startDate || '', end: formData.endDate || '' };
  };

  /**
   * Simplified multiplier logic for budget periods.
   * Returns how many budget units fit into the view window.
   */
  const getSimpleMultiplier = (view: ViewWindow, freq: Periodicity) => {
    if (view === 'Financial Year') return 'Total'; // Special case to use full budget amount

    const map: Record<ViewWindow, Record<Periodicity, number>> = {
      'This Month': { 'Daily': 30, 'Weekly': 4.33, 'Fortnightly': 2.16, 'Monthly': 1, 'Quarterly': 0.33, 'Half-Yearly': 0.16, 'Annually': 0.083 },
      'Last Month': { 'Daily': 30, 'Weekly': 4.33, 'Fortnightly': 2.16, 'Monthly': 1, 'Quarterly': 0.33, 'Half-Yearly': 0.16, 'Annually': 0.083 },
      'This Quarter': { 'Daily': 91, 'Weekly': 13, 'Fortnightly': 6.5, 'Monthly': 3, 'Quarterly': 1, 'Half-Yearly': 0.5, 'Annually': 0.25 },
      'Financial Year': { 'Daily': 365, 'Weekly': 52, 'Fortnightly': 26, 'Monthly': 12, 'Quarterly': 4, 'Half-Yearly': 2, 'Annually': 1 },
      'Custom': { 'Daily': 30, 'Weekly': 4.33, 'Fortnightly': 2.16, 'Monthly': 1, 'Quarterly': 0.33, 'Half-Yearly': 0.16, 'Annually': 0.083 } // Default to monthly for custom
    };

    return map[view][freq] || 1;
  };

  const getPeriodCount = (startStr: string, endStr: string, freq: Periodicity) => {
    if (!startStr || !endStr) return 0;
    const start = new Date(startStr);
    const end = new Date(endStr);
    const diffMs = end.getTime() - start.getTime();
    const diffDays = Math.max(0, (diffMs / (1000 * 60 * 60 * 24)) + 1);

    const freqDays: Record<Periodicity, number> = {
      'Daily': 1, 'Weekly': 7, 'Fortnightly': 14, 'Monthly': 30.44,
      'Quarterly': 91.31, 'Half-Yearly': 182.62, 'Annually': 365.25
    };

    return diffDays / freqDays[freq];
  };

  const currentAnalysisWindow = useMemo(() => {
    const now = new Date();
    let start = new Date();
    let end = new Date();

    if (viewWindowType === 'This Month') {
      start = new Date(now.getFullYear(), now.getMonth(), 1);
      end = new Date(now.getFullYear(), now.getMonth() + 1, 0, 23, 59, 59);
    } else if (viewWindowType === 'Last Month') {
      start = new Date(now.getFullYear(), now.getMonth() - 1, 1);
      end = new Date(now.getFullYear(), now.getMonth(), 0, 23, 59, 59);
    } else if (viewWindowType === 'This Quarter') {
      const q = Math.floor(now.getMonth() / 3);
      start = new Date(now.getFullYear(), q * 3, 1);
      end = new Date(now.getFullYear(), (q + 1) * 3, 0, 23, 59, 59);
    } else if (viewWindowType === 'Financial Year') {
      const startYear = now.getMonth() < 3 ? now.getFullYear() - 1 : now.getFullYear();
      start = new Date(startYear, 3, 1);
      end = new Date(startYear + 1, 2, 31, 23, 59, 59);
    } else if (viewWindowType === 'Custom') {
      start = new Date(customViewStart);
      end = new Date(customViewEnd);
      end.setHours(23, 59, 59, 999);
    }
    return { start, end };
  }, [viewWindowType, customViewStart, customViewEnd]);

