                <th className="px-8 py-6 border-b border-slate-100">Recurrence</th>
                <th className="px-8 py-6 text-right border-b border-slate-100">Target (For Period)</th>
                <th className="px-8 py-6 text-right border-b border-slate-100">Actual (In Window)</th>
                <th className="px-8 py-6 text-center border-b border-slate-100">Efficiency Health</th>
                <th className="px-8 py-6 text-right border-b border-slate-100">Term Goal</th>
                <th className="px-8 py-6 text-center border-b border-slate-100">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {budgetsWithAnalytics.map(b => {
                const efficiency = b.dynamicTarget > 0 ? Math.min(100, (b.windowActual / b.dynamicTarget) * 100) : (b.windowActual > 0 ? 100 : 0);
                const isOver = b.windowActual > b.dynamicTarget;
                const isWarning = efficiency > 80;

                return (
                  <tr key={b.id} className={`hover:bg-slate-50/30 transition-colors group ${b.isInactive ? 'opacity-40 grayscale' : ''}`}>
                    <td className="px-8 py-6 sticky left-0 z-10 bg-white group-hover:bg-slate-50/30 shadow-[2px_0_5px_-2px_rgba(0,0,0,0.05)] border-b border-slate-50">
                      <p className="text-xs font-black text-slate-800 uppercase tracking-tight">{b.category}</p>
                      <p className="text-[8px] font-black text-slate-300 uppercase mt-1 tracking-widest">{b.startDate} to {b.endDate}</p>
                    </td>
                    <td className="px-8 py-6">
                       <span className="text-[9px] font-black bg-slate-100 text-slate-500 px-3 py-1 rounded-full uppercase tracking-widest">{b.frequency}</span>
                    </td>
                    <td className="px-8 py-6 text-right font-black text-xs text-indigo-600">
                      {formatCurrency(b.dynamicTarget, currency)}
