                    }}><option value="Financial">Financial Year</option><option value="Calendar">Calendar Year</option><option value="Custom">Custom Range</option></select>
                 </div>
                 <div className="space-y-2">
                    <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Frequency</label>
                    <select className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl font-black text-xs outline-none" value={formData.frequency} onChange={e => setFormData({...formData, frequency: e.target.value as Periodicity})}>
                       {FREQUENCIES.map(f => <option key={f} value={f}>{f}</option>)}
                    </select>
                 </div>
              </div>
              <div className="space-y-4 bg-indigo-50/30 p-8 rounded-[2rem] border border-indigo-100">
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-indigo-400 uppercase tracking-widest block ml-2">Amount per {formData.frequency}</label>
                  <input required type="number" step="any" className="w-full p-4 bg-white border border-indigo-200 rounded-2xl outline-none font-black text-2xl text-indigo-600" value={formData.amountPerPeriod} onChange={e => setFormData({...formData, amountPerPeriod: Number(e.target.value)})} />
                </div>
                <div className="flex justify-between items-center text-right">
                  <p className="text-[8px] font-black text-indigo-400 uppercase tracking-widest">Total Goal</p>
                  <p className="text-2xl font-black text-indigo-600">{formatCurrency(formData.amount || 0, currency)}</p>
                </div>
              </div>
              <div className="flex gap-4 pt-4">
                <button type="button" onClick={() => setShowModal(false)} className="flex-1 py-5 bg-slate-100 text-slate-500 font-black text-[10px] uppercase rounded-2xl">Cancel</button>
                <button type="submit" className="flex-[2] py-5 bg-indigo-600 text-white font-black text-[10px] uppercase rounded-2xl">Establish Goal</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

