            ) : (
              <div className="px-6 text-[10px] font-black text-indigo-600 uppercase hidden md:block">
                Audit Range: {currentAnalysisWindow.start.toLocaleDateString()} — {currentAnalysisWindow.end.toLocaleDateString()}
              </div>
            )}
        </div>
      )}

      {/* Main Budget Data Workspace */}
      <div className="bg-white rounded-[2.5rem] border border-slate-200 shadow-sm overflow-hidden flex flex-col">
        <div className="overflow-x-auto custom-scrollbar relative">
          <table className="w-full text-left border-separate border-spacing-0 min-w-[1200px]">
            <thead className="bg-slate-50/80 backdrop-blur-md text-slate-400 text-[9px] font-black uppercase tracking-[0.3em] sticky top-0 z-30">
              <tr>
                <th className="px-8 py-6 sticky left-0 z-40 bg-slate-50 border-b border-slate-100 shadow-[4px_0_8px_-4px_rgba(0,0,0,0.1)]">Expense Category</th>
                <th className="px-8 py-6 border-b border-slate-100">Recurrence</th>
                <th className="px-8 py-6 text-right border-b border-slate-100">Target (For Period)</th>
                <th className="px-8 py-6 text-right border-b border-slate-100">Actual (In Window)</th>
                <th className="px-8 py-6 text-center border-b border-slate-100">Efficiency Health</th>
                <th className="px-8 py-6 text-right border-b border-slate-100">Term Goal</th>
                <th className="px-8 py-6 text-center border-b border-slate-100">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {budgetsWithAnalytics.map(b => {
                const efficiency = b.dynamicTarget > 0 ? Math.min(100, (b.windowActual / b.dynamicTarget) * 100) : (b.windowActual > 0 ? 100 : 0);
                const isOver = b.windowActual > b.dynamicTarget;
                const isWarning = efficiency > 80;

                return (
                  <tr key={b.id} className={`hover:bg-slate-50/30 transition-colors group ${b.isInactive ? 'opacity-40 grayscale' : ''}`}>
                    {/* Sticky Left Column with specific background to ensure it doesn't overlap text when scrolling */}
                    <td className="px-8 py-6 sticky left-0 z-20 bg-white group-hover:bg-[#f8fafc] border-b border-slate-50 shadow-[4px_0_12px_-4px_rgba(0,0,0,0.1)] transition-colors">
                      <p className="text-xs font-black text-slate-800 uppercase tracking-tight">{b.category}</p>
                      <p className="text-[8px] font-black text-slate-300 uppercase mt-1 tracking-widest whitespace-nowrap">{b.startDate} to {b.endDate}</p>
                    </td>
                    <td className="px-8 py-6">
                       <span className="text-[9px] font-black bg-slate-100 text-slate-500 px-3 py-1 rounded-full uppercase tracking-widest inline-block">{b.frequency}</span>
                    </td>
                    <td className="px-8 py-6 text-right font-black text-xs text-indigo-600">
                      {formatCurrency(b.dynamicTarget, currency)}
                    </td>
                    <td className={`px-8 py-6 text-right font-black text-xs ${isOver ? 'text-rose-500' : 'text-slate-800'}`}>
                      {formatCurrency(b.windowActual, currency)}
                    </td>
                    <td className="px-8 py-6 text-center min-w-[140px]">
                       {!b.hasOverlap ? <span className="text-[8px] font-black text-slate-300 uppercase italic">Out of Range</span> : (
                         <div className="flex flex-col items-center">
                           <div className="w-full h-1.5 bg-slate-100 rounded-full overflow-hidden max-w-[100px] mb-1">
                              <div className={`h-full transition-all duration-700 ${isOver ? 'bg-rose-500' : isWarning ? 'bg-amber-400' : 'bg-emerald-500'}`} style={{ width: `${efficiency}%` }}></div>
                           </div>
                           <span className={`text-[8px] font-black uppercase tracking-widest ${isOver ? 'text-rose-400' : 'text-slate-400'}`}>{efficiency.toFixed(0)}% Utilized</span>
                         </div>
                       )}
                    </td>
                    <td className="px-8 py-6 text-right">
                       <p className="text-[10px] font-black text-slate-800">{formatCurrency(b.amount, currency)}</p>
                       <p className="text-[8px] font-black text-slate-300 uppercase tracking-widest mt-0.5 whitespace-nowrap">Projected Cap</p>
                    </td>
                    <td className="px-8 py-6 text-center">
                       <div className="flex items-center justify-center gap-2 opacity-0 group-hover:opacity-100 transition-all">
                          <button onClick={() => handleOpenModal(b)} className="p-2.5 bg-white text-indigo-400 hover:text-indigo-600 rounded-lg shadow-sm border border-slate-100">✎</button>
                          <button onClick={() => deleteBudget(b.id)} className="p-2.5 bg-white text-rose-300 hover:text-rose-500 rounded-lg shadow-sm border border-slate-100">✕</button>
                       </div>
                    </td>
                  </tr>
                );
              })}
              {budgetsWithAnalytics.length === 0 && (
                <tr>
                   <td colSpan={7} className="px-8 py-32 text-center text-slate-300 italic text-[10px] uppercase tracking-widest">
                     No strategic allocations defined for this period
                   </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {showModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/60 backdrop-blur-md p-4">
          <div className="bg-white w-full max-w-xl rounded-[3rem] p-8 md:p-12 border border-slate-200 shadow-2xl animate-in zoom-in-95 duration-200 max-h-[90vh] overflow-y-auto custom-scrollbar">
            <h3 className="text-xl font-black text-slate-800 uppercase tracking-tight mb-10">Target Protocol</h3>
            <form onSubmit={handleSubmit} className="space-y-8">
              <div className="space-y-2">
                <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Category Head</label>
                <input required className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-black text-xs uppercase" placeholder="E.G. GROCERIES" value={formData.category} onChange={e => setFormData({...formData, category: e.target.value})} />
              </div>
              <div className="grid grid-cols-2 gap-6">
                 <div className="space-y-2">
                    <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Budget Span</label>
                    <select className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl font-black text-xs outline-none" value={formData.periodType} onChange={e => {
                      const dates = getPeriodDates(e.target.value as any);
                      setFormData({...formData, periodType: e.target.value as any, startDate: dates.start, endDate: dates.end});
                    }}><option value="Financial">Financial Year</option><option value="Calendar">Calendar Year</option><option value="Custom">Custom Range</option></select>
                 </div>
                 <div className="space-y-2">
                    <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Frequency</label>
                    <select className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl font-black text-xs outline-none" value={formData.frequency} onChange={e => setFormData({...formData, frequency: e.target.value as Periodicity})}>
                       {FREQUENCIES.map(f => <option key={f} value={f}>{f}</option>)}
                    </select>
                 </div>
              </div>
              <div className="space-y-4 bg-indigo-50/30 p-8 rounded-[2rem] border border-indigo-100">
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-indigo-400 uppercase tracking-widest block ml-2">Amount per {formData.frequency}</label>
                  <input required type="number" step="any" className="w-full p-4 bg-white border border-indigo-200 rounded-2xl outline-none font-black text-2xl text-indigo-600" value={formData.amountPerPeriod} onChange={e => setFormData({...formData, amountPerPeriod: Number(e.target.value)})} />
                </div>
                <div className="flex justify-between items-center text-right pt-2 border-t border-indigo-100">
                  <div className="text-left">
                    <p className="text-[8px] font-black text-slate-400 uppercase">Projection</p>
                    <p className="text-[10px] font-black text-slate-600 uppercase mt-0.5">{formData.frequency}</p>
                  </div>
                  <div>
                    <p className="text-[8px] font-black text-indigo-400 uppercase tracking-widest">Calculated Goal</p>
                    <p className="text-2xl font-black text-indigo-600">{formatCurrency(formData.amount || 0, currency)}</p>
                  </div>
                </div>
              </div>
              <div className="flex gap-4 pt-4">
                <button type="button" onClick={() => setShowModal(false)} className="flex-1 py-5 bg-slate-100 text-slate-500 font-black text-[10px] uppercase rounded-2xl">Abort</button>
                <button type="submit" className="flex-[2] py-5 bg-indigo-600 text-white font-black text-[10px] uppercase rounded-2xl shadow-xl shadow-indigo-100">Establish Goal</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default BudgetPlanner;

import React, { useState, useMemo, useEffect } from 'react';
import { useFinance } from '../store/FinanceContext';
import { formatCurrency } from '../utils/formatters';
import { Periodicity, Budget } from '../types';

const FREQUENCIES: Periodicity[] = [
  'Daily', 'Weekly', 'Fortnightly', 'Monthly', 'Quarterly', 'Half-Yearly', 'Annually'
];

type ViewWindow = 'This Month' | 'Last Month' | 'This Quarter' | 'Financial Year' | 'Custom';

/**
 * Standard annual multipliers for simple budget calculations.
 * Used to define the "Calculated Goal" in the budget modal.
 */
const ANNUAL_MULTIPLIERS: Record<Periodicity, number> = {
  'Daily': 365,
  'Weekly': 52,
  'Fortnightly': 26,
  'Monthly': 12,
  'Quarterly': 4,
  'Half-Yearly': 2,
  'Annually': 1
};

const BudgetPlanner: React.FC = () => {
  const { filteredState, state, addBudget, updateBudget, deleteBudget } = useFinance();
  const [showModal, setShowModal] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [isFocusMode, setIsFocusMode] = useState(false);
  const currency = state.profile.currency;

  // Global Analysis Window State
  const [viewWindowType, setViewWindowType] = useState<ViewWindow>('This Month');
  const [customViewStart, setCustomViewStart] = useState(new Date(new Date().getFullYear(), new Date().getMonth(), 1).toISOString().split('T')[0]);
  const [customViewEnd, setCustomViewEnd] = useState(new Date().toISOString().split('T')[0]);

  const [formData, setFormData] = useState<Partial<Budget> & { amountPerPeriod: number }>({
    category: '',
    amount: 0,
    amountPerPeriod: 0,
    frequency: 'Monthly',
    periodType: 'Financial',
    startDate: '',
    endDate: ''
  });

  const getPeriodDates = (type: 'Financial' | 'Calendar' | 'Custom') => {
    const now = new Date();
    const currentYear = now.getFullYear();
    if (type === 'Calendar') {
      return { start: `${currentYear}-01-01`, end: `${currentYear}-12-31` };
    } else if (type === 'Financial') {
      const startYear = now.getMonth() < 3 ? currentYear - 1 : currentYear;
      return { start: `${startYear}-04-01`, end: `${startYear + 1}-03-31` };
    }
    return { start: formData.startDate || '', end: formData.endDate || '' };
  };

  /**
   * Returns a simple multiplier for target calculation based on the view window.
   */
  const getWindowMultiplier = (view: ViewWindow, freq: Periodicity) => {
    if (view === 'Financial Year') return ANNUAL_MULTIPLIERS[freq];

    // Standard simplified mappings
    const map: Record<Exclude<ViewWindow, 'Financial Year'>, Record<Periodicity, number>> = {
      'This Month': { 'Daily': 30, 'Weekly': 4, 'Fortnightly': 2, 'Monthly': 1, 'Quarterly': 0.33, 'Half-Yearly': 0.16, 'Annually': 0.083 },
      'Last Month': { 'Daily': 30, 'Weekly': 4, 'Fortnightly': 2, 'Monthly': 1, 'Quarterly': 0.33, 'Half-Yearly': 0.16, 'Annually': 0.083 },
      'This Quarter': { 'Daily': 91, 'Weekly': 13, 'Fortnightly': 6, 'Monthly': 3, 'Quarterly': 1, 'Half-Yearly': 0.5, 'Annually': 0.25 },
      'Custom': { 'Daily': 30, 'Weekly': 4, 'Fortnightly': 2, 'Monthly': 1, 'Quarterly': 0.33, 'Half-Yearly': 0.16, 'Annually': 0.083 }
    };

    return map[view as Exclude<ViewWindow, 'Financial Year'>][freq] || 1;
  };

  // Simplified: The Total Goal in the form is always the Projected Annual Amount
  useEffect(() => {
    const total = (formData.amountPerPeriod || 0) * ANNUAL_MULTIPLIERS[formData.frequency as Periodicity];
    if (Math.abs(formData.amount - total) > 0.01) {
      setFormData(prev => ({ ...prev, amount: total }));
    }
  }, [formData.amountPerPeriod, formData.frequency]);

  const currentAnalysisWindow = useMemo(() => {
    const now = new Date();
    let start = new Date();
    let end = new Date();

    if (viewWindowType === 'This Month') {
      start = new Date(now.getFullYear(), now.getMonth(), 1);
      end = new Date(now.getFullYear(), now.getMonth() + 1, 0, 23, 59, 59);
    } else if (viewWindowType === 'Last Month') {
      start = new Date(now.getFullYear(), now.getMonth() - 1, 1);
      end = new Date(now.getFullYear(), now.getMonth(), 0, 23, 59, 59);
    } else if (viewWindowType === 'This Quarter') {
      const q = Math.floor(now.getMonth() / 3);
      start = new Date(now.getFullYear(), q * 3, 1);
      end = new Date(now.getFullYear(), (q + 1) * 3, 0, 23, 59, 59);
    } else if (viewWindowType === 'Financial Year') {
      const startYear = now.getMonth() < 3 ? now.getFullYear() - 1 : now.getFullYear();
      start = new Date(startYear, 3, 1);
      end = new Date(startYear + 1, 2, 31, 23, 59, 59);
    } else if (viewWindowType === 'Custom') {
      start = new Date(customViewStart);
      end = new Date(customViewEnd);
      end.setHours(23, 59, 59, 999);
    }
    return { start, end };
  }, [viewWindowType, customViewStart, customViewEnd]);

  const budgetsWithAnalytics = useMemo(() => {
    const now = new Date();
    const { start: windowStart, end: windowEnd } = currentAnalysisWindow;

    return (filteredState.budgets || []).map(b => {
      const bStart = new Date(b.startDate);
      const bEnd = new Date(b.endDate);

      const effectiveStart = new Date(Math.max(bStart.getTime(), windowStart.getTime()));
      const effectiveEnd = new Date(Math.min(bEnd.getTime(), windowEnd.getTime()));
      const hasOverlap = effectiveStart <= effectiveEnd;

      const windowActual = hasOverlap 
        ? (filteredState.transactions || [])
          .filter(t => t.type === 'Expense' && t.nature === b.category && new Date(t.date) >= effectiveStart && new Date(t.date) <= effectiveEnd)
          .reduce((sum, t) => sum + t.amount, 0)
        : 0;

      // Simple periodic multiplication for dynamic target
      const multiplier = getWindowMultiplier(viewWindowType, b.frequency);
      const amountPerFreq = b.amount / ANNUAL_MULTIPLIERS[b.frequency];

      const dynamicTarget = amountPerFreq * multiplier;
      const isInactive = now < bStart || now > bEnd;

      return { ...b, windowActual, dynamicTarget, amountPerFreq, isInactive, hasOverlap };
    });
  }, [filteredState.budgets, filteredState.transactions, currentAnalysisWindow, viewWindowType]);

  const handleOpenModal = (b?: Budget) => {
    if (b) {
      setEditingId(b.id);
      setFormData({ ...b, amountPerPeriod: b.amount / ANNUAL_MULTIPLIERS[b.frequency] });
    } else {
      setEditingId(null);
      const dates = getPeriodDates('Financial');
      setFormData({ category: '', amount: 0, amountPerPeriod: 0, frequency: 'Monthly', periodType: 'Financial', startDate: dates.start, endDate: dates.end });
    }
    setShowModal(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const dates = getPeriodDates(formData.periodType as any);
    const budgetData: Budget = {
      id: editingId || Math.random().toString(36).substr(2, 9),
      category: formData.category || 'General',
      amount: Number(formData.amount),
      frequency: formData.frequency as Periodicity,
      startDate: dates.start,
      endDate: dates.end,
      periodType: formData.periodType as any,
      ownerId: ''
    };
    if (editingId) updateBudget(budgetData);
    else addBudget(budgetData);
    setShowModal(false);
  };

  return (
    <div className="space-y-6 md:space-y-10 animate-in fade-in duration-500 pb-20">

      {/* Dynamic Header & Options Bar */}
      {!isFocusMode && (
        <div className="flex flex-col md:flex-row md:items-end justify-between gap-6 px-4 md:px-0 animate-in slide-in-from-top-4 duration-300">
          <div>
            <h2 className="text-2xl md:text-3xl font-black text-slate-800 tracking-tight uppercase">Budget Architect</h2>
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mt-2">Strategic Resource Allocation</p>
          </div>
          <div className="flex items-center gap-3">
             <button onClick={() => setIsFocusMode(true)} className="px-5 py-3.5 bg-slate-900 text-white rounded-2xl text-[9px] font-black uppercase tracking-widest shadow-xl shadow-slate-200 transition-transform active:scale-95">Focus Mode</button>
             <button onClick={() => handleOpenModal()} className="px-6 py-4 bg-indigo-600 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-xl shadow-indigo-100 active:scale-95 transition-all">+ Add Head</button>
          </div>
        </div>
      )}

      {/* Focus Mode Control Bar */}
      {isFocusMode && (
        <div className="sticky top-4 z-50 flex items-center justify-between bg-slate-900 text-white p-3 rounded-2xl shadow-2xl mx-4 md:mx-0 animate-in slide-in-from-top-4">
           <div className="flex items-center gap-4 px-3">
              <span className="text-sm">🧘</span>
              <p className="text-[10px] font-black uppercase tracking-[0.2em]">Focused Analysis</p>
           </div>
           <div className="flex items-center gap-2">
              <button onClick={() => handleOpenModal()} className="px-4 py-2 bg-indigo-600 text-[9px] font-black uppercase tracking-widest rounded-xl transition-all active:scale-95">+ Add</button>
              <button onClick={() => setIsFocusMode(false)} className="px-4 py-2 bg-white/10 hover:bg-white/20 text-[9px] font-black uppercase tracking-widest rounded-xl transition-colors">Exit Focus</button>
           </div>
        </div>
      )}

      {/* Period Options Bar - Hidden in Focus Mode for 'Clear View' */}
      {!isFocusMode && (
        <div className="bg-white p-2 rounded-[2rem] border border-slate-200 shadow-sm flex flex-col md:flex-row md:items-center justify-between gap-4 animate-in fade-in duration-500">
            <div className="flex flex-wrap items-center gap-1 p-1 bg-slate-50/50 rounded-2xl">
              {(['This Month', 'Last Month', 'This Quarter', 'Financial Year', 'Custom'] as ViewWindow[]).map(type => (
                <button 
                  key={type} 
                  onClick={() => setViewWindowType(type)}
                  className={`px-4 py-2.5 rounded-xl text-[9px] font-black uppercase tracking-widest transition-all ${viewWindowType === type ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-400 hover:text-slate-600'}`}
                >
                  {type}
                </button>
              ))}
            </div>
            {viewWindowType === 'Custom' ? (
              <div className="flex items-center gap-3 px-4 animate-in slide-in-from-right-4">
                 <input type="date" className="bg-slate-50 border border-slate-200 rounded-xl px-3 py-2 text-[10px] font-black outline-none" value={customViewStart} onChange={e => setCustomViewStart(e.target.value)} />
                 <input type="date" className="bg-slate-50 border border-slate-200 rounded-xl px-3 py-2 text-[10px] font-black outline-none" value={customViewEnd} onChange={e => setCustomViewEnd(e.target.value)} />
              </div>
            ) : (
              <div className="px-6 text-[10px] font-black text-indigo-600 uppercase hidden md:block">
                Audit Range: {currentAnalysisWindow.start.toLocaleDateString()} — {currentAnalysisWindow.end.toLocaleDateString()}
              </div>
            )}
        </div>
      )}

      {/* Main Budget Data Workspace */}
      <div className="bg-white rounded-[2.5rem] border border-slate-200 shadow-sm overflow-hidden flex flex-col">
        <div className="overflow-x-auto custom-scrollbar relative">
          <table className="w-full text-left border-separate border-spacing-0 min-w-[1200px]">
            <thead className="bg-slate-50/80 backdrop-blur-md text-slate-400 text-[9px] font-black uppercase tracking-[0.3em] sticky top-0 z-30">
              <tr>
                <th className="px-8 py-6 sticky left-0 z-40 bg-slate-50 border-b border-slate-100 shadow-[4px_0_8px_-4px_rgba(0,0,0,0.1)]">Expense Category</th>
                <th className="px-8 py-6 border-b border-slate-100">Recurrence</th>
                <th className="px-8 py-6 text-right border-b border-slate-100">Target (For Period)</th>
                <th className="px-8 py-6 text-right border-b border-slate-100">Actual (In Window)</th>
                <th className="px-8 py-6 text-center border-b border-slate-100">Efficiency Health</th>
                <th className="px-8 py-6 text-right border-b border-slate-100">Projected Annual</th>
                <th className="px-8 py-6 text-center border-b border-slate-100">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {budgetsWithAnalytics.map(b => {
                const efficiency = b.dynamicTarget > 0 ? Math.min(100, (b.windowActual / b.dynamicTarget) * 100) : (b.windowActual > 0 ? 100 : 0);
                const isOver = b.windowActual > b.dynamicTarget;
                const isWarning = efficiency > 80;

                return (
                  <tr key={b.id} className={`hover:bg-slate-50/30 transition-colors group ${b.isInactive ? 'opacity-40 grayscale' : ''}`}>
                    <td className="px-8 py-6 sticky left-0 z-20 bg-white group-hover:bg-[#f8fafc] border-b border-slate-50 shadow-[4px_0_12px_-4px_rgba(0,0,0,0.1)] transition-colors">
                      <p className="text-xs font-black text-slate-800 uppercase tracking-tight">{b.category}</p>
                      <p className="text-[8px] font-black text-slate-300 uppercase mt-1 tracking-widest whitespace-nowrap">{b.startDate} to {b.endDate}</p>
                    </td>
                    <td className="px-8 py-6">
                       <span className="text-[9px] font-black bg-slate-100 text-slate-500 px-3 py-1 rounded-full uppercase tracking-widest inline-block">{b.frequency}</span>
                    </td>
                    <td className="px-8 py-6 text-right font-black text-xs text-indigo-600">
                      {formatCurrency(b.dynamicTarget, currency)}
                    </td>
                    <td className={`px-8 py-6 text-right font-black text-xs ${isOver ? 'text-rose-500' : 'text-slate-800'}`}>
                      {formatCurrency(b.windowActual, currency)}
                    </td>
                    <td className="px-8 py-6 text-center min-w-[140px]">
                       {!b.hasOverlap ? <span className="text-[8px] font-black text-slate-300 uppercase italic">Out of Range</span> : (
                         <div className="flex flex-col items-center">
                           <div className="w-full h-1.5 bg-slate-100 rounded-full overflow-hidden max-w-[100px] mb-1">
                              <div className={`h-full transition-all duration-700 ${isOver ? 'bg-rose-500' : isWarning ? 'bg-amber-400' : 'bg-emerald-500'}`} style={{ width: `${efficiency}%` }}></div>
                           </div>
                           <span className={`text-[8px] font-black uppercase tracking-widest ${isOver ? 'text-rose-400' : 'text-slate-400'}`}>{efficiency.toFixed(0)}% Utilized</span>
                         </div>
                       )}
                    </td>
                    <td className="px-8 py-6 text-right">
                       <p className="text-[10px] font-black text-slate-800">{formatCurrency(b.amount, currency)}</p>
                       <p className="text-[8px] font-black text-slate-300 uppercase tracking-widest mt-0.5 whitespace-nowrap">Annual Cap</p>
                    </td>
                    <td className="px-8 py-6 text-center">
                       <div className="flex items-center justify-center gap-2 opacity-0 group-hover:opacity-100 transition-all">
                          <button onClick={() => handleOpenModal(b)} className="p-2.5 bg-white text-indigo-400 hover:text-indigo-600 rounded-lg shadow-sm border border-slate-100 transition-colors">✎</button>
                          <button onClick={() => deleteBudget(b.id)} className="p-2.5 bg-white text-rose-300 hover:text-rose-500 rounded-lg shadow-sm border border-slate-100 transition-colors">✕</button>
                       </div>
                    </td>
                  </tr>
                );
              })}
              {budgetsWithAnalytics.length === 0 && (
                <tr>
                   <td colSpan={7} className="px-8 py-32 text-center text-slate-300 italic text-[10px] uppercase tracking-widest">
                     No strategic allocations defined for this period
                   </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {showModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/60 backdrop-blur-md p-4">
          <div className="bg-white w-full max-w-xl rounded-[3rem] p-8 md:p-12 border border-slate-200 shadow-2xl animate-in zoom-in-95 duration-200 max-h-[90vh] overflow-y-auto custom-scrollbar">
            <h3 className="text-xl font-black text-slate-800 uppercase tracking-tight mb-10">Target Protocol</h3>
            <form onSubmit={handleSubmit} className="space-y-8">
              <div className="space-y-2">
                <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Category Head</label>
                <input required className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-black text-xs uppercase" placeholder="E.G. GROCERIES" value={formData.category} onChange={e => setFormData({...formData, category: e.target.value})} />
              </div>
              <div className="grid grid-cols-2 gap-6">
                 <div className="space-y-2">
                    <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Budget Span</label>
                    <select className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl font-black text-xs outline-none cursor-pointer" value={formData.periodType} onChange={e => {
                      const dates = getPeriodDates(e.target.value as any);
                      setFormData({...formData, periodType: e.target.value as any, startDate: dates.start, endDate: dates.end});
                    }}><option value="Financial">Financial Year</option><option value="Calendar">Calendar Year</option><option value="Custom">Custom Range</option></select>
                 </div>
                 <div className="space-y-2">
                    <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Frequency</label>
                    <select className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl font-black text-xs outline-none cursor-pointer" value={formData.frequency} onChange={e => setFormData({...formData, frequency: e.target.value as Periodicity})}>
                       {FREQUENCIES.map(f => <option key={f} value={f}>{f}</option>)}
                    </select>
                 </div>
              </div>
              <div className="space-y-4 bg-indigo-50/30 p-8 rounded-[2rem] border border-indigo-100">
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-indigo-400 uppercase tracking-widest block ml-2">Amount per {formData.frequency}</label>
                  <input required type="number" step="any" className="w-full p-4 bg-white border border-indigo-200 rounded-2xl outline-none font-black text-2xl text-indigo-600 focus:ring-4 focus:ring-indigo-500/10 transition-all" value={formData.amountPerPeriod} onChange={e => setFormData({...formData, amountPerPeriod: Number(e.target.value)})} />
                </div>
                <div className="flex justify-between items-center text-right pt-2 border-t border-indigo-100">
                  <div className="text-left">
                    <p className="text-[8px] font-black text-slate-400 uppercase">Multiplier</p>
                    <p className="text-[10px] font-black text-slate-600 uppercase mt-0.5">x{ANNUAL_MULTIPLIERS[formData.frequency as Periodicity]} (Annual)</p>
                  </div>
                  <div>
                    <p className="text-[8px] font-black text-indigo-400 uppercase tracking-widest">Calculated Annual Goal</p>
                    <p className="text-2xl font-black text-indigo-600">{formatCurrency(formData.amount || 0, currency)}</p>
                  </div>
                </div>
              </div>
              <div className="flex gap-4 pt-4">
                <button type="button" onClick={() => setShowModal(false)} className="flex-1 py-5 bg-slate-100 text-slate-500 font-black text-[10px] uppercase rounded-2xl hover:bg-slate-200 transition-colors">Abort</button>
                <button type="submit" className="flex-[2] py-5 bg-indigo-600 text-white font-black text-[10px] uppercase rounded-2xl shadow-xl shadow-indigo-100 hover:bg-indigo-700 transition-all active:scale-95">Establish Goal</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default BudgetPlanner;

export type Periodicity = 'Daily' | 'Weekly' | 'Fortnightly' | 'Monthly' | 'Quarterly' | 'Half-Yearly' | 'Annually';
export type AccountClassification = 'Current Asset' | 'Non-Current Asset' | 'Current Liability' | 'Non-Current Liability' | 'Equity';

export interface FamilyMember {
  id: string;
  name: string;
  relation: string;
  mobileNumber: string;
  canAddTransactions?: boolean;
}

export interface UserProfile {
  name: string;
  designation: string;
  age: number;
  city: string;
  country: string;
  currency: string;
  mobileNumber?: string;
  isBoarded: boolean;
  familyMembers: FamilyMember[];
  cloudDatabaseName?: string;
}

export interface Notification {
  id: string;
  title: string;
  message: string;
  timestamp: string;
  type: 'transaction' | 'system' | 'sync';
  isRead: boolean;
}

export interface BankAccount {
  id: string;
  name: string;
  accountNumber?: string;
  balance: number;
  ownerId?: string;
  accountType?: 'Savings' | 'Current' | 'Salary' | 'Others';
  customAccountType?: string;
  classification?: AccountClassification;
}

export interface CreditCardOtherBenefit {
  condition: string;
  benefitName: string;
  linkedNatures: string[];
}

export interface CreditCard {
  id: string;
  lenderName: string;
  balance: number;
  last4: string;
  limit?: number;
  annualLimit?: number; 
  anniversaryDate?: string;
  billingDay?: number;
  dueDate?: string;
  offers: {
    movie: boolean;
    dining: boolean;
    concierge: boolean;
    lounge: boolean;
  };
  ownerId?: string;
  classification?: AccountClassification;
  cashbackPct?: number;
  movieOffers?: {
    onePlusOne: boolean;
    amountBased: number;
  };
  loungeAccess?: {
    count: number;
    spendLimit: number;
    period: string;
  };
  fuelSurchargeWaiver?: boolean;
  forexMarkup?: number;
  pointsConversion?: string;
  otherBenefits?: CreditCardOtherBenefit[];
}

export interface Wallet {
  id: string;
  name: string;
  balance: number;
  ownerId?: string;
  classification?: AccountClassification;
}

export interface IncomeStream {
  id: string;
  name: string;
  amount: number;
  periodicity: Periodicity;
  dateOfReceipt: string;
  ownerId?: string;
}

export interface Expense {
  id: string;
  category: string;
  amount: number;
  date: string;
  periodicity?: Periodicity;
  ownerId?: string;
}

export interface Asset {
  id: string;
  name: string;
  value: number;
  type?: 'Physical' | 'Receivable';
  ownerId?: string;
  classification?: AccountClassification;
  isin?: string;
  units?: number;
}

export interface Liability {
  id: string;
  name: string;
  amount: number;
  type?: 'Debt' | 'Payable';
  ownerId?: string;
  classification?: AccountClassification;
}

export type TransactionType = 'Income' | 'Expense' | 'Asset' | 'Liability';

export interface SharedContact {
  name: string;
  mobile: string;
  amount: number;
}

export interface Transaction {
  id: string;
  type: TransactionType;
  amount: number;
  nature: string; 
  description: string;
  accountId: string;
  accountType: 'bank' | 'card' | 'wallet' | 'liability';
  date: string;
  category?: string;
  isShared?: boolean;
  sharedAmount?: number;
  numberOfPeople?: number;
  includeSelf?: boolean;
  sharedContacts?: SharedContact[];
  ownerId?: string; 
  isin?: string;
  stockName?: string;
  units?: number; 
  stt?: number; 
  brokerage?: number; 
  billingPeriod?: string; 
  isSettled?: boolean;
  estimatedLife?: number;
}

export interface HoldingItem {
  isin: string;
  name: string;
  value: number;
  units: number;
  count: number;
}

export interface Budget {
  id: string;
  category: string;
  amount: number;
  frequency: Periodicity;
  startDate: string;
  endDate: string;
  dueDate?: string;
  periodType: 'Financial' | 'Calendar' | 'Custom';
  ownerId?: string;
}

export interface FinancialState {
  profile: UserProfile;
  banks: BankAccount[];
  cards: CreditCard[];
  wallets: Wallet[];
  incomes: IncomeStream[];
  expenses: Expense[];
  assets: Asset[];
  liabilities: Liability[];
  transactions: Transaction[];
  budgets: Budget[]; // Added budget tracking
  notifications: Notification[];
  transactionNatures: string[]; 
  capital: number; 
}

import React, { useState, useMemo } from 'react';
import { useFinance } from '../store/FinanceContext';
import { formatCurrency } from '../utils/formatters';
import { Transaction, CreditCard, AccountClassification, CreditCardOtherBenefit } from '../types';
import { getAnnualPeriodStart, getAnnualPeriodEnd } from '../utils/calculations';

const CLASSIFICATIONS: AccountClassification[] = [
  'Current Asset',
  'Non-Current Asset',
  'Current Liability',
  'Non-Current Liability',
  'Equity'
];

const Accounts: React.FC = () => {
  const { filteredState, state, deleteBank, deleteCard, deleteWallet, deleteAsset, deleteLiability, addTransactionNature, deleteTransactionNature } = useFinance();
  const [showModal, setShowModal] = useState<'bank' | 'card' | 'wallet' | 'asset' | 'liability' | null>(null);
  const [editingAccount, setEditingAccount] = useState<any>(null);
  const [viewingHistory, setViewingHistory] = useState<any>(null);
  const [confirmDelete, setConfirmDelete] = useState<{ id: string, type: 'bank' | 'card' | 'wallet' | 'asset' | 'liability', name: string } | null>(null);
  const [newNature, setNewNature] = useState('');
  const currency = filteredState.profile.currency;

  const handleEdit = (type: 'bank' | 'card' | 'wallet' | 'asset' | 'liability', account: any) => {
    setEditingAccount(account);
    setShowModal(type);
  };

  const handleDelete = (type: 'bank' | 'card' | 'wallet' | 'asset' | 'liability', id: string, name: string) => {
    setConfirmDelete({ id, type, name });
  };

  const executeDelete = () => {
    if (!confirmDelete) return;
    if (confirmDelete.type === 'bank') deleteBank(confirmDelete.id);
    else if (confirmDelete.type === 'card') deleteCard(confirmDelete.id);
    else if (confirmDelete.type === 'wallet') deleteWallet(confirmDelete.id);
    else if (confirmDelete.type === 'asset') deleteAsset(confirmDelete.id);
    else if (confirmDelete.type === 'liability') deleteLiability(confirmDelete.id);
    setConfirmDelete(null);
  };

  return (
    <div className="space-y-8 md:space-y-12 animate-in fade-in duration-500 pb-20">
      <section>
        <div className="flex justify-between items-end mb-8">
          <div className="flex flex-col">
            <h3 className="text-lg font-bold text-slate-800 tracking-tight uppercase">Depository Assets</h3>
            <p className="text-[10px] text-slate-400 font-medium uppercase tracking-widest">Forced Current Assets Protocol</p>
          </div>
          <button onClick={() => { setEditingAccount(null); setShowModal('bank'); }} className="px-5 py-3 bg-indigo-600 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest">+ Bank</button>
        </div>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {(filteredState.banks || []).map(bank => (
            <div key={bank.id} className="bg-white p-6 rounded-3xl border border-slate-200 relative group shadow-sm">
              <span className="absolute top-6 right-6 text-[8px] font-black uppercase text-indigo-600 bg-indigo-50 px-2.5 py-1 rounded-full">Current Asset</span>
              <h4 className="text-sm font-black text-slate-800 mb-1">{bank.name}</h4>
              <p className="text-[10px] text-slate-400 font-bold mb-4">{bank.accountNumber || '**** **** ****'}</p>
              <p className="text-2xl font-black text-slate-800 tracking-tight">{formatCurrency(bank.balance, currency)}</p>
              <div className="flex gap-4 pt-6 border-t border-slate-50 mt-6">
                <button onClick={() => handleEdit('bank', bank)} className="text-[9px] font-black uppercase text-indigo-600">Edit</button>
                <button onClick={() => handleDelete('bank', bank.id, bank.name)} className="text-[9px] font-black uppercase text-rose-400 ml-auto">Delete</button>
              </div>
            </div>
          ))}
        </div>
      </section>

      <section>
        <div className="flex justify-between items-end mb-8">
          <div className="flex flex-col">
            <h3 className="text-lg font-bold text-slate-800 tracking-tight uppercase">Cash Wallets</h3>
            <p className="text-[10px] text-slate-400 font-medium uppercase tracking-widest">Liquid Current Assets</p>
          </div>
          <button onClick={() => { setEditingAccount(null); setShowModal('wallet'); }} className="px-5 py-3 bg-emerald-600 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest">+ Wallet</button>
        </div>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {(filteredState.wallets || []).map(wallet => (
            <div key={wallet.id} className="bg-white p-6 rounded-3xl border border-slate-200 relative group shadow-sm">
              <span className="absolute top-6 right-6 text-[8px] font-black uppercase text-emerald-600 bg-emerald-50 px-2.5 py-1 rounded-full">Current Asset</span>
              <h4 className="text-sm font-black text-slate-800 mb-4">{wallet.name}</h4>
              <p className="text-2xl font-black text-slate-800 tracking-tight">{formatCurrency(wallet.balance, currency)}</p>
              <div className="flex gap-4 pt-6 border-t border-slate-50 mt-6">
                <button onClick={() => handleEdit('wallet', wallet)} className="text-[9px] font-black uppercase text-emerald-600">Edit</button>
                <button onClick={() => handleDelete('wallet', wallet.id, wallet.name)} className="text-[9px] font-black uppercase text-rose-400 ml-auto">Delete</button>
              </div>
            </div>
          ))}
        </div>
      </section>

      {/* Credit Section */}
      <section>
        <div className="flex justify-between items-end mb-8">
          <div className="flex flex-col">
            <h3 className="text-lg font-bold text-slate-800 tracking-tight uppercase">Credit Lines</h3>
            <p className="text-[10px] text-slate-400 font-medium uppercase tracking-widest">Liability Tracking</p>
          </div>
          <button onClick={() => { setEditingAccount(null); setShowModal('card'); }} className="px-5 py-3 bg-slate-900 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest">+ New Card</button>
        </div>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
          {(filteredState.cards || []).map(card => {
            const isReceivable = card.balance < 0;
            return (
              <div key={card.id} className={`bg-gradient-to-br ${isReceivable ? 'from-emerald-600 to-emerald-800' : 'from-slate-800 to-slate-900'} p-8 rounded-[2.5rem] text-white shadow-xl relative`}>
                <span className="absolute top-8 right-8 text-[8px] font-black text-white/40 uppercase tracking-widest">Current Liability</span>
                <h4 className="text-xl font-black mb-1">{card.lenderName}</h4>
                <div className="flex justify-between items-center mb-10">
                  <p className="text-xs font-mono text-white/40 tracking-[0.3em]">•••• {card.last4}</p>
                  {card.dueDate && (
                    <p className="text-[9px] font-black text-rose-300 uppercase bg-white/5 px-3 py-1 rounded-full border border-white/10">Due: {card.dueDate}</p>
                  )}
                </div>
                <p className="text-4xl font-black tracking-tighter">{formatCurrency(Math.abs(card.balance), currency)}</p>
                <div className="flex gap-4 pt-8 border-t border-white/10 mt-8">
                  <button onClick={() => handleEdit('card', card)} className="text-[9px] font-black uppercase text-white/60">Configure</button>
                  <button onClick={() => handleDelete('card', card.id, card.lenderName)} className="text-[9px] font-black uppercase text-rose-400 ml-auto">Purge</button>
                </div>
              </div>
            );
          })}
        </div>
      </section>

      {showModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/60 backdrop-blur-sm p-4">
          <div className="bg-white w-full max-w-2xl rounded-[3rem] border border-slate-200 shadow-2xl animate-in zoom-in duration-200 flex flex-col max-h-[90vh] overflow-hidden">
            <div className="p-8 border-b border-slate-100 flex justify-between items-center">
              <h3 className="text-lg font-black text-slate-800 uppercase tracking-tighter">Configure {showModal}</h3>
              <button onClick={() => { setShowModal(null); setEditingAccount(null); }} className="text-slate-300 hover:text-slate-800 text-2xl font-black">✕</button>
            </div>
            <div className="flex-1 overflow-y-auto p-8 custom-scrollbar">
              <AccountForm type={showModal} account={editingAccount} onCancel={() => { setShowModal(null); setEditingAccount(null); }} />
            </div>
          </div>
        </div>
      )}
      {viewingHistory && <TransactionHistoryModal account={viewingHistory} currency={currency} onClose={() => setViewingHistory(null)} />}
      {confirmDelete && <DeleteConfirmationModal accountName={confirmDelete.name} onCancel={() => setConfirmDelete(null)} onConfirm={executeDelete} />}
    </div>
  );
};

