      {/* Slide-out Sidebar Drawer */}
      <aside 
        className={`fixed top-0 left-0 bottom-0 w-72 bg-slate-900 border-r border-slate-800 z-[70] flex flex-col text-white transition-transform duration-500 ease-out transform ${isMenuOpen ? 'translate-x-0' : '-translate-x-full'}`}
      >
        <div className="p-8 flex items-center justify-between border-b border-slate-800/50">
          <div className="flex items-center gap-3">
             <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center font-bold">M</div>
             <h1 className="text-xl font-bold tracking-tight">MyFin</h1>
          </div>
          <button onClick={closeMenu} className="text-slate-400 hover:text-white p-2">✕</button>
        </div>

        <nav className="flex-1 px-4 py-8 space-y-1">
          <p className="text-[10px] font-black text-slate-500 uppercase tracking-[0.3em] px-5 mb-4">Command Center</p>
          {navItems.map(item => (
            <button 
              key={item.id} 
              onClick={() => { setActiveTab(item.id); closeMenu(); }} 
              className={`w-full flex items-center gap-4 px-5 py-4 rounded-2xl text-sm font-black transition-all group ${activeTab === item.id ? 'bg-indigo-600 text-white shadow-xl' : 'text-slate-400 hover:text-white hover:bg-slate-800'}`}
            >
              <span className={`text-xl transition-transform ${activeTab === item.id ? 'scale-110' : 'group-hover:scale-110'}`}>{item.icon}</span>
              <span className="uppercase tracking-widest text-[11px]">{item.label}</span>
            </button>
          ))}

          <div className="pt-10 border-t border-slate-800/50 mt-10">
             <button onClick={() => { resetBoarding(); closeMenu(); }} className="w-full flex items-center gap-4 px-5 py-4 rounded-2xl text-[10px] font-black text-slate-500 hover:text-rose-400 hover:bg-rose-500/10 transition-colors uppercase tracking-widest">
              <span className="text-lg">🚪</span>
              <span>Sign Out</span>
            </button>
          </div>
        </nav>

        <div className="p-8 bg-slate-950/50">
           <p className="text-[8px] font-black text-slate-600 uppercase tracking-widest text-center">Protocol v2.5.0 Secure</p>
        </div>
      </aside>

      {/* Main Content Area */}
      <main ref={mainRef} className="flex-1 flex flex-col relative h-full overflow-y-auto overflow-x-hidden custom-scrollbar">

        <header className={`sticky top-0 bg-white/90 backdrop-blur-xl border-b border-slate-200 px-4 md:px-8 z-40 flex justify-between items-center transition-all ${isShrunk ? 'h-14' : 'h-16 md:h-24'} pt-[var(--sat)]`}>

