          <div className="flex items-center gap-3">
            <button onClick={() => simulateSync()} className="hidden md:flex bg-indigo-600 text-white px-5 py-2.5 rounded-2xl text-[9px] font-black uppercase tracking-widest shadow-xl shadow-indigo-100 hover:bg-indigo-700 transition-all">🔄 Sync Cloud</button>

