                    {familyMembers.map(m => (
                      <button key={m.id} onClick={() => { toggleMember(m.id); setShowMemberSelector(false); }} className={`w-full text-left px-5 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest ${activeMemberIds.includes(m.id) ? 'bg-indigo-600 text-white shadow-lg' : 'hover:bg-slate-50 text-slate-500'}`}>
                        {m.name}
                      </button>
                    ))}
