            <button onClick={() => setShowNotifications(!showNotifications)} className="relative w-10 h-10 md:w-12 md:h-12 bg-slate-100 rounded-2xl text-slate-600 flex items-center justify-center hover:bg-white border border-slate-200 transition-all">
               <span className="text-xl">🔔</span>
               {unreadCount > 0 && <span className="absolute top-2 right-2 bg-rose-500 w-2.5 h-2.5 rounded-full border-2 border-white"></span>}
