            <tbody className="divide-y divide-slate-50">
              {budgetsWithAnalytics.map(b => {
                const efficiency = b.dynamicTarget > 0 ? Math.min(100, (b.windowActual / b.dynamicTarget) * 100) : (b.windowActual > 0 ? 100 : 0);
                const isOver = b.windowActual > b.dynamicTarget;
                const isWarning = efficiency > 80;

                return (
                  <tr key={b.id} className={`hover:bg-slate-50/30 transition-colors group ${b.isInactive ? 'opacity-40 grayscale' : ''}`}>
                    <td className="px-8 py-6 sticky left-0 z-20 bg-white group-hover:bg-[#f8fafc] border-b border-slate-50 shadow-[4px_0_12px_-4px_rgba(0,0,0,0.1)] transition-colors">
