                    </td>
                    <td className="px-8 py-6">
                       <span className="text-[9px] font-black bg-slate-100 text-slate-500 px-3 py-1 rounded-full uppercase tracking-widest inline-block">{b.frequency}</span>
                    </td>
                    <td className="px-8 py-6 text-right font-black text-xs text-indigo-600">
                      {formatCurrency(b.dynamicTarget, currency)}
