                <div className="absolute top-[50%] left-[50%] -translate-x-1/2 -translate-y-1/2 text-center pointer-events-none">
                   <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Equity</p>
                   <p className="text-xl md:text-2xl font-black text-slate-800 tracking-tight leading-none mt-1">{formatCurrency(netWorthData.netWorth, currency)}</p>
                </div>
