import React, { useMemo, useState } from 'react';
import { useFinance } from '../store/FinanceContext';
import { formatCurrency } from '../utils/formatters';
import { Periodicity } from '../types';
import { ANNUAL_MULTIPLIERS } from '../utils/calculations';

const getBudgetDueDateForWindow = (dueDateStr: string | undefined, windowStart: Date) => {
  if (!dueDateStr) return null;
  const refDate = new Date(dueDateStr);
  if (isNaN(refDate.getTime())) return null;

  const day = refDate.getDate();
  const targetDate = new Date(windowStart.getFullYear(), windowStart.getMonth(), day);

  if (targetDate.getMonth() !== windowStart.getMonth()) {
    targetDate.setDate(0); 
  }
  return targetDate;
};

const FiscalSentinel: React.FC = () => {
  const { filteredState } = useFinance();
  const currency = filteredState.profile.currency;

  const [viewDate, setViewDate] = useState(new Date());

  const calendarData = useMemo(() => {
    const year = viewDate.getFullYear();
    const month = viewDate.getMonth();
    const windowStart = new Date(year, month, 1);

    // Calculate Previous Month Total Income
    const prevMonthStart = new Date(year, month - 1, 1);
    const prevMonthEnd = new Date(year, month, 0, 23, 59, 59);
    const prevMonthIncome = (filteredState.transactions || [])
      .filter(t => t.type === 'Income' && new Date(t.date) >= prevMonthStart && new Date(t.date) <= prevMonthEnd)
      .reduce((acc, t) => acc + t.amount, 0);

    const dailyThresholdWarning = prevMonthIncome * 0.2;
    const cumulativeBlowoutThreshold = prevMonthIncome * 0.5;

    const daysInMonth = new Date(year, month + 1, 0).getDate();
    // Tracks if a day is a due date regardless of amount
    const dailyMap: Record<number, { amount: number, items: { name: string, amount: number }[], hasScheduledDue: boolean }> = {};
    const dailyActualSpent: Record<number, number> = {};

    for (let d = 1; d <= daysInMonth; d++) {
      dailyMap[d] = { amount: 0, items: [], hasScheduledDue: false };
      dailyActualSpent[d] = 0;
    }

    // Process Dues (Budgets and Credit Cards)
    (filteredState.budgets || []).forEach(b => {
      const windowDueDate = getBudgetDueDateForWindow(b.dueDate, windowStart);
      if (windowDueDate && windowDueDate.getMonth() === month) {
        const day = windowDueDate.getDate();
        const amountPerFreq = b.amount / ANNUAL_MULTIPLIERS[b.frequency];
        if (dailyMap[day]) {
          dailyMap[day].amount += amountPerFreq;
          dailyMap[day].hasScheduledDue = true;
          dailyMap[day].items.push({ name: b.category, amount: amountPerFreq });
        }
      }
    });

    (filteredState.cards || []).forEach(c => {
      if (c.dueDate) {
        const refDate = new Date(c.dueDate);
        const day = refDate.getDate();
        if (dailyMap[day]) {
          const bal = Math.abs(c.balance);
          // Only add items if it's the specific target month/year for better tooltips
          if (refDate.getMonth() === month && refDate.getFullYear() === year) {
             dailyMap[day].amount += bal;
             dailyMap[day].items.push({ name: c.lenderName, amount: bal });
          }
          // Highlight day regardless of amount/month specific instance to warn of recurring obligation
          dailyMap[day].hasScheduledDue = true;
        }
      }
    });

    // Process Actual Expenses for Cumulative Blowout Logic
    (filteredState.transactions || [])
      .filter(t => t.type === 'Expense' && new Date(t.date).getMonth() === month && new Date(t.date).getFullYear() === year)
      .forEach(t => {
        const d = new Date(t.date).getDate();
        if (dailyActualSpent[d] !== undefined) {
          dailyActualSpent[d] += t.amount;
        }
      });

    // Identify the first day of Blowout
    let cumulativeSum = 0;
    let firstBlowoutDay: number | null = null;
    for (let d = 1; d <= daysInMonth; d++) {
      cumulativeSum += dailyActualSpent[d];
      if (firstBlowoutDay === null && cumulativeSum > cumulativeBlowoutThreshold) {
        firstBlowoutDay = d;
      }
    }

    return { 
      dailyMap, 
      dailyThresholdWarning, 
      cumulativeBlowoutThreshold, 
      firstBlowoutDay, 
      year, 
      month, 
      daysInMonth, 
      prevMonthIncome,
      cumulativeTotalSpent: cumulativeSum 
    };
  }, [filteredState, viewDate]);

  const monthName = new Date(calendarData.year, calendarData.month).toLocaleString('default', { month: 'long' });
  const startDayOfWeek = new Date(calendarData.year, calendarData.month, 1).getDay();

  const handlePrevMonth = () => setViewDate(new Date(calendarData.year, calendarData.month - 1, 1));
  const handleNextMonth = () => setViewDate(new Date(calendarData.year, calendarData.month + 1, 1));

  return (
    <div className="space-y-10 animate-in fade-in duration-500 pb-20">
      <div className="flex flex-col md:flex-row md:items-end justify-between gap-6 px-4 md:px-0">
        <div>
          <h2 className="text-2xl md:text-3xl font-black text-slate-800 tracking-tight uppercase">Fiscal Sentinel</h2>
          <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mt-2">Due Date Pressure Analysis Protocol</p>
        </div>
        <div className="flex items-center gap-2 bg-white p-1.5 rounded-2xl border border-slate-200 shadow-sm">
          <button onClick={handlePrevMonth} className="w-10 h-10 flex items-center justify-center rounded-xl hover:bg-slate-50 transition-colors">←</button>
          <span className="px-6 text-[10px] font-black uppercase tracking-widest text-slate-800">{monthName} {calendarData.year}</span>
          <button onClick={handleNextMonth} className="w-10 h-10 flex items-center justify-center rounded-xl hover:bg-slate-50 transition-colors">→</button>
        </div>
      </div>

      <section className="bg-white p-6 md:p-10 rounded-[3rem] border border-slate-200 shadow-sm animate-in fade-in duration-700">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 mb-10">
          <div>
            <h3 className="text-xl font-black text-slate-800 uppercase tracking-tight">Liquidity Forecast</h3>
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-1">Status Report for {monthName} cycle</p>
          </div>
          <div className="flex flex-wrap items-center gap-6">
             <div className="flex items-center gap-2">
               <div className="w-3 h-3 rounded-full bg-rose-600"></div>
               <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Blowout</span>
             </div>
             <div className="flex items-center gap-2">
               <div className="w-3 h-3 rounded-full bg-amber-400"></div>
               <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Pressure</span>
             </div>
             <div className="flex items-center gap-2">
               <div className="w-3 h-3 rounded-full bg-emerald-600"></div>
               <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Safe</span>
             </div>
             <div className="flex items-center gap-2">
               <div className="w-3 h-3 rounded-full bg-yellow-400"></div>
               <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Due Date</span>
             </div>
          </div>
        </div>

        <div className="grid grid-cols-7 gap-2 md:gap-4">
          {['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'].map(d => (
            <div key={d} className="text-center text-[9px] font-black text-slate-300 uppercase tracking-widest mb-4">{d}</div>
          ))}

          {Array.from({ length: startDayOfWeek }).map((_, i) => (
            <div key={`empty-${i}`} className="aspect-square bg-slate-50/30 rounded-2xl"></div>
          ))}

          {Array.from({ length: calendarData.daysInMonth }).map((_, i) => {
            const day = i + 1;
            const info = calendarData.dailyMap[day];
            const hasAmount = info.amount > 0;
            const hasScheduledDue = info.hasScheduledDue;
            const isBlowout = calendarData.firstBlowoutDay !== null && day >= calendarData.firstBlowoutDay;
            const isWarning = hasAmount && info.amount > calendarData.dailyThresholdWarning && !isBlowout;
            const isSafe = hasAmount && !isWarning && !isBlowout;

            // Priority: Blowout > Warning > Safe > ScheduledDue (Yellow)
            return (
              <div 
                key={day} 
                className={`relative aspect-square flex flex-col items-center justify-center transition-all group cursor-default border-2 ${
                  isBlowout 
                    ? 'bg-rose-600 border-rose-600 text-white shadow-xl shadow-rose-200 rounded-full scale-105' 
                    : isWarning
                        ? 'bg-amber-400 border-amber-400 text-white shadow-xl shadow-amber-200 rounded-full scale-105'
                        : isSafe
                          ? 'bg-emerald-600 border-emerald-600 text-white shadow-xl shadow-emerald-200 rounded-full scale-105'
                          : hasScheduledDue
                            ? 'bg-yellow-400 border-yellow-500 text-slate-900 shadow-xl shadow-yellow-100 rounded-full scale-105 ring-4 ring-yellow-200/50'
                            : 'bg-white border-slate-100 rounded-2xl hover:border-slate-300 text-slate-400'
                }`}
              >
                <div className={`w-full h-full flex flex-col items-center justify-center p-1`}>
                   <span className={`text-[10px] md:text-sm font-black ${isBlowout || isWarning || isSafe ? 'text-white' : 'text-slate-800'}`}>{day}</span>
                   {hasScheduledDue && (
                     <div className="mt-0.5 hidden md:block">
                        <p className={`text-[8px] font-black ${isBlowout || isWarning || isSafe ? 'text-white/70' : 'text-slate-600'}`}>
                          {hasAmount ? formatCurrency(info.amount, currency) : 'DUE'}
                        </p>
                     </div>
                   )}
                </div>

                {hasScheduledDue && (
                  <div className="absolute bottom-full left-1/2 -translate-x-1/2 mb-3 w-48 bg-slate-900 text-white p-4 rounded-2xl shadow-2xl opacity-0 group-hover:opacity-100 pointer-events-none transition-all z-50">
                     <p className="text-[8px] font-black text-slate-500 uppercase tracking-widest mb-2">Audit Detail • {day} {monthName}</p>
                     <div className="space-y-1.5">
                        {info.items.length > 0 ? info.items.map((item, idx) => (
                          <div key={idx} className="flex justify-between items-center text-[10px] font-black">
                            <span className="uppercase tracking-tight truncate max-w-[100px]">{item.name}</span>
                            <span>{item.amount > 0 ? formatCurrency(item.amount, currency) : 'Recurring'}</span>
                          </div>
                        )) : (
                          <p className="text-[10px] font-black text-slate-400 italic">Scheduled Occurrence</p>
                        )}
                     </div>
                     {hasAmount && (
                       <div className="mt-3 pt-3 border-t border-white/10 flex justify-between items-center text-[10px] font-black text-indigo-400">
                         <span>Total Due</span>
                         <span>{formatCurrency(info.amount, currency)}</span>
                       </div>
                     )}
                  </div>
                )}
              </div>
            );
          })}
        </div>

        <div className="mt-12 p-6 bg-slate-50 rounded-[2rem] border border-slate-100 flex flex-col md:flex-row justify-between items-center gap-6">
           <div className="flex items-center gap-4">
             <div className="w-10 h-10 bg-white rounded-xl shadow-sm flex items-center justify-center text-xl">📊</div>
             <div>
               <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Basis Reference</p>
               <p className="text-sm font-black text-slate-800 uppercase">Prev. Month Income: <span className="text-indigo-600">{formatCurrency(calendarData.prevMonthIncome, currency)}</span></p>
             </div>
           </div>
           <div className="flex flex-col md:flex-row gap-8">
             <div className="text-right">
                <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Pressure Threshold (20%)</p>
                <p className="text-xl font-black text-amber-500 uppercase">{formatCurrency(calendarData.dailyThresholdWarning, currency)}</p>
             </div>
             <div className="text-right">
                <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Blowout Threshold (50%)</p>
                <p className="text-xl font-black text-rose-500 uppercase">{formatCurrency(calendarData.cumulativeBlowoutThreshold, currency)}</p>
