  if (!context) throw new Error('useFinance must be used within a FinanceProvider');
  return context;
};

export const FinanceProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [isAuthenticated, setAuthenticated] = useState(false);
  const [activeMemberIds, setActiveMemberIds] = useState<string[]>([]);
  const [isCloudSyncing, setIsCloudSyncing] = useState(false);
  const [activeMobile, setActiveMobile] = useState<string | null>(() => localStorage.getItem(GLOBAL_SESSION_KEY));

  const [state, setState] = useState<FinancialState>(() => {
    const mobile = localStorage.getItem(GLOBAL_SESSION_KEY);
    if (mobile) {
      const saved = localStorage.getItem(`${STATE_PREFIX}${mobile}`);
      if (saved) {
        try {
          const parsed = JSON.parse(saved);
          return { ...initialState, ...parsed };
        } catch (e) {
          return initialState;
        }
      }
    }
    return initialState;
  });

  useEffect(() => {
    if (state.profile.mobileNumber && state.profile.isBoarded) {
      localStorage.setItem(GLOBAL_SESSION_KEY, state.profile.mobileNumber);
      localStorage.setItem(`${STATE_PREFIX}${state.profile.mobileNumber}`, JSON.stringify(state));
    }
  }, [state]);

  useEffect(() => {
    const persistToSupabase = async () => {
      if (!state.profile.mobileNumber || !state.profile.isBoarded) return;
      setIsCloudSyncing(true);
      try {
        await supabase.from('user_states').upsert({ 
          mobile_number: state.profile.mobileNumber, state: state, updated_at: new Date().toISOString()
        }, { onConflict: 'mobile_number' });
      } catch (err) {} finally {
        setTimeout(() => setIsCloudSyncing(false), 500);
      }
    };
    const timeoutId = setTimeout(persistToSupabase, 2000);
    return () => clearTimeout(timeoutId);
  }, [state]);

  // Automated Notification Engine for Due Dates
  useEffect(() => {
    if (!state.profile.isBoarded) return;

    const checkUpcomingDues = () => {
      const now = new Date();
      now.setHours(0,0,0,0);
      const nextWeek = new Date();
      nextWeek.setDate(now.getDate() + 7);
      nextWeek.setHours(23,59,59,999);

      const newNotifications: Notification[] = [];

      const getRelevantDueDate = (dueDateStr: string | undefined) => {
        if (!dueDateStr) return null;
        const ref = new Date(dueDateStr);
        if (isNaN(ref.getTime())) return null;
        const day = ref.getDate();
        let target = new Date(now.getFullYear(), now.getMonth(), day);
        if (target < now) {
          target = new Date(now.getFullYear(), now.getMonth() + 1, day);
        }
        return target;
      };

      // Check Credit Cards
      state.cards.forEach(card => {
        const due = getRelevantDueDate(card.dueDate);
        if (due && due >= now && due <= nextWeek) {
          const notifId = `due_card_${card.id}_${due.getMonth()}_${due.getFullYear()}`;
          if (!state.notifications.some(n => n.id === notifId)) {
            newNotifications.push({
              id: notifId,
              title: 'Upcoming Card Payment',
              message: `Your payment for ${card.lenderName} (•••• ${card.last4}) is due on ${due.toLocaleDateString('default', { day: 'numeric', month: 'short' })}.`,
              timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
              type: 'system',
              isRead: false
            });
          }
        }
      });

      // Check Budgets
      state.budgets.forEach(budget => {
        const due = getRelevantDueDate(budget.dueDate);
        if (due && due >= now && due <= nextWeek) {
          const notifId = `due_budget_${budget.id}_${due.getMonth()}_${due.getFullYear()}`;
          if (!state.notifications.some(n => n.id === notifId)) {
            newNotifications.push({
              id: notifId,
              title: 'Budget Milestone Near',
              message: `Strategic allocation for ${budget.category} is scheduled for ${due.toLocaleDateString('default', { day: 'numeric', month: 'short' })}.`,
              timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
              type: 'system',
              isRead: false
            });
          }
        }
      });

      if (newNotifications.length > 0) {
        setState(prev => ({
          ...prev,
          notifications: [...newNotifications, ...prev.notifications].slice(0, 50)
        }));
      }
    };

    const timer = setTimeout(checkUpcomingDues, 5000); // Initial check
    return () => clearTimeout(timer);
  }, [state.cards, state.budgets, state.profile.isBoarded]);

  const addTransactionNature = (nature: string) => {
    setState(prev => {
      if (prev.transactionNatures.includes(nature)) return prev;
      return { ...prev, transactionNatures: [...prev.transactionNatures, nature] };
    });
  };

  const deleteTransactionNature = (nature: string) => {
    setState(prev => ({ ...prev, transactionNatures: prev.transactionNatures.filter(n => n !== nature) }));
  };

  const addBudget = (budget: Budget) => {
    addTransactionNature(budget.category);
    setState(prev => ({ ...prev, budgets: [budget, ...(prev.budgets || [])] }));
  };

  const updateBudget = (budget: Budget) => {
    addTransactionNature(budget.category);
    setState(prev => ({ ...prev, budgets: (prev.budgets || []).map(b => b.id === budget.id ? budget : b) }));
  };

  const deleteBudget = (id: string) => {
    setState(prev => ({ ...prev, budgets: (prev.budgets || []).filter(b => b.id !== id) }));
  };

  const applyTransactionEffect = (transaction: Transaction, newState: FinancialState, isReversing: boolean) => {
    const factor = isReversing ? -1 : 1;
    const totalAmount = transaction.amount || 0;
    const balanceDelta = (transaction.type === 'Income' || transaction.type === 'Liability') ? totalAmount : -totalAmount;
    const finalBalanceDelta = balanceDelta * factor;

    if (transaction.accountType === 'bank') {
      newState.banks = (newState.banks || []).map(b => b.id === transaction.accountId ? { ...b, balance: b.balance + finalBalanceDelta } : b);
    } else if (transaction.accountType === 'card') {
      const cardDelta = (transaction.type === 'Income' || transaction.type === 'Liability' ? -totalAmount : totalAmount) * factor;
      newState.cards = (newState.cards || []).map(c => c.id === transaction.accountId ? { ...c, balance: c.balance + cardDelta } : c);
    } else if (transaction.accountType === 'wallet') {
      newState.wallets = (newState.wallets || []).map(w => w.id === transaction.accountId ? { ...w, balance: w.balance + finalBalanceDelta } : w);
    } else if (transaction.accountType === 'liability') {
      const liabilityDelta = (transaction.type === 'Income' || transaction.type === 'Liability' ? -totalAmount : totalAmount) * factor;
      newState.liabilities = (newState.liabilities || []).map(l => l.id === transaction.accountId ? { ...l, amount: l.amount + liabilityDelta } : l);
    }

    if (isReversing) {
      newState.incomes = (newState.incomes || []).filter(i => i.id !== transaction.id);
      newState.expenses = (newState.expenses || []).filter(e => e.id !== transaction.id);
      newState.assets = (newState.assets || []).filter(a => a.id !== transaction.id);
      newState.liabilities = (newState.liabilities || []).filter(l => l.id !== transaction.id);
    } else {
      switch (transaction.type) {
        case 'Income':
          newState.incomes.push({ id: transaction.id, name: `${transaction.nature}: ${transaction.description}`, amount: transaction.amount, periodicity: 'Monthly', dateOfReceipt: transaction.date, ownerId: transaction.ownerId });
          break;
        case 'Expense':
          newState.expenses.push({ id: transaction.id, category: transaction.nature, amount: transaction.amount, date: transaction.date, ownerId: transaction.ownerId });
          break;
        case 'Asset':
          newState.assets.push({ id: transaction.id, name: `${transaction.nature}: ${transaction.description}`, value: transaction.amount, type: 'Physical', ownerId: transaction.ownerId, isin: transaction.isin, units: transaction.units, classification: 'Non-Current Asset' });
          break;
        case 'Liability':
          newState.liabilities.push({ id: transaction.id, name: `${transaction.nature}: ${transaction.description}`, amount: transaction.amount, type: 'Debt', ownerId: transaction.ownerId, classification: 'Current Liability' });
          break;
      }
    }
  };

  const addTransaction = (transaction: Transaction) => {
    setState(prev => {
      const newState = { ...prev, transactions: [transaction, ...(prev.transactions || [])] };
      applyTransactionEffect(transaction, newState, false);
      return newState;
    });
  };

  const updateTransaction = (updatedTransaction: Transaction) => {
    setState(prev => {
      const oldTransaction = (prev.transactions || []).find(t => t.id === updatedTransaction.id);
      if (!oldTransaction) return prev;
      let newState = { ...prev };
      applyTransactionEffect(oldTransaction, newState, true);
      newState.transactions = (newState.transactions || []).map(t => t.id === updatedTransaction.id ? updatedTransaction : t);
      applyTransactionEffect(updatedTransaction, newState, false);
      return newState;
    });
  };

  const deleteTransaction = (id: string) => {
    setState(prev => {
      const transaction = (prev.transactions || []).find(t => t.id === id);
      if (!transaction) return prev;
      const newState = { ...prev, transactions: (prev.transactions || []).filter(t => t.id !== id) };
      applyTransactionEffect(transaction, newState, true);
      return newState;
    });
  };

  const loadStateFromCloud = async (mobile: string): Promise<boolean> => {
    try {
      const { data } = await supabase.from('user_states').select('state').eq('mobile_number', mobile).single();
      if (data && data.state) {
        setState({ ...initialState, ...data.state });
        setActiveMobile(mobile);
        localStorage.setItem(GLOBAL_SESSION_KEY, mobile);
        setAuthenticated(true);
        return true;
      }
      return false;
    } catch (err) { return false; }
  };

  const updateProfile = (profile: UserProfile) => setState(prev => ({ ...prev, profile: { ...profile, isBoarded: true } }));
  const importState = (newState: FinancialState) => {
    if (newState?.profile?.mobileNumber) {
      setState({ ...initialState, ...newState });
      setActiveMobile(newState.profile.mobileNumber);
      localStorage.setItem(GLOBAL_SESSION_KEY, newState.profile.mobileNumber);
      setAuthenticated(true);
    }
  };

  const addFamilyMember = async (member: FamilyMember) => {
    if (member.mobileNumber === state.profile.mobileNumber) return { success: false, syncedCount: 0, error: "Self link blocked." };
    setState(prev => ({ ...prev, profile: { ...prev.profile, familyMembers: [...(prev.profile.familyMembers || []), member] } }));
    return { success: true, syncedCount: 0 };
  };

  const removeFamilyMember = (id: string) => setState(prev => ({ ...prev, profile: { ...prev.profile, familyMembers: (prev.profile.familyMembers || []).filter(m => m.id !== id) } }));
  const toggleFamilyMemberTxPermission = (id: string) => setState(prev => ({ ...prev, profile: { ...prev.profile, familyMembers: prev.profile.familyMembers.map(m => m.id === id ? { ...m, canAddTransactions: !m.canAddTransactions } : m) } }));

  const addBank = (bank: BankAccount) => setState(prev => ({ ...prev, banks: [...prev.banks, bank], capital: prev.capital + bank.balance }));
  const updateBank = (bank: BankAccount) => setState(prev => {
    const old = prev.banks.find(b => b.id === bank.id);
    return { ...prev, banks: prev.banks.map(b => b.id === bank.id ? bank : b), capital: prev.capital + (bank.balance - (old?.balance || 0)) };
  });
  const deleteBank = (id: string) => setState(prev => {
    const old = prev.banks.find(b => b.id === id);
    return { ...prev, banks: prev.banks.filter(b => b.id !== id), capital: prev.capital - (old?.balance || 0) };
  });

  const addCard = (card: CreditCard) => setState(prev => ({ ...prev, cards: [...prev.cards, card], capital: prev.capital - card.balance }));
  const updateCard = (card: CreditCard) => setState(prev => {
    const old = prev.cards.find(c => c.id === card.id);
    return { ...prev, cards: prev.cards.map(c => c.id === card.id ? card : c), capital: prev.capital - (card.balance - (old?.balance || 0)) };
  });
  const deleteCard = (id: string) => setState(prev => {
    const old = prev.cards.find(c => c.id === id);
    return { ...prev, cards: prev.cards.filter(c => c.id !== id), capital: prev.capital + (old?.balance || 0) };
  });

  const addWallet = (wallet: Wallet) => setState(prev => ({ ...prev, wallets: [...prev.wallets, wallet], capital: prev.capital + wallet.balance }));
  const updateWallet = (wallet: Wallet) => setState(prev => {
    const old = prev.wallets.find(w => w.id === wallet.id);
    return { ...prev, wallets: prev.wallets.map(w => w.id === wallet.id ? wallet : w), capital: prev.capital + (wallet.balance - (old?.balance || 0)) };
  });
  const deleteWallet = (id: string) => setState(prev => {
    const old = prev.wallets.find(w => w.id === id);
    return { ...prev, wallets: prev.wallets.filter(w => w.id !== id), capital: prev.capital - (old?.balance || 0) };
  });

  const addAsset = (asset: Asset) => setState(prev => ({ ...prev, assets: [...prev.assets, asset], capital: prev.capital + asset.value }));
  const updateAsset = (asset: Asset) => setState(prev => {
    const old = prev.assets.find(a => a.id === asset.id);
    return { ...prev, assets: prev.assets.map(a => a.id === asset.id ? asset : a), capital: prev.capital + (asset.value - (old?.value || 0)) };
  });
  const deleteAsset = (id: string) => setState(prev => {
    const old = prev.assets.find(a => a.id === id);
    return { ...prev, assets: prev.assets.filter(a => a.id !== id), capital: prev.capital - (old?.value || 0) };
  });

  const addLiability = (liability: Liability) => setState(prev => ({ ...prev, liabilities: [...prev.liabilities, liability], capital: prev.capital - liability.amount }));
  const updateLiability = (liability: Liability) => setState(prev => {
    const old = prev.liabilities.find(l => l.id === liability.id);
    return { ...prev, liabilities: prev.liabilities.map(l => l.id === liability.id ? liability : l), capital: prev.capital - (liability.amount - (old?.amount || 0)) };
  });
  const deleteLiability = (id: string) => setState(prev => {
    const old = prev.liabilities.find(l => l.id === id);
    return { ...prev, liabilities: prev.liabilities.filter(l => l.id !== id), capital: prev.capital + (old?.amount || 0) };
  });

  const filteredState = useMemo(() => {
    if (activeMemberIds.includes('all')) return state;
    const isFiltered = activeMemberIds.length > 0;
    const filterIds = isFiltered ? activeMemberIds : [undefined, ''];
    const filterFn = (item: any) => filterIds.includes(item.ownerId || '');
    return {
      ...state,
      banks: (state.banks || []).filter(filterFn),
      cards: (state.cards || []).filter(filterFn),
      wallets: (state.wallets || []).filter(filterFn),
      transactions: (state.transactions || []).filter(filterFn),
      budgets: (state.budgets || []).filter(filterFn),
    };
  }, [state, activeMemberIds]);

  const resetBoarding = async () => { 
    localStorage.removeItem(GLOBAL_SESSION_KEY);
    setState(initialState); setAuthenticated(false);
  };

  return (
    <FinanceContext.Provider value={{ 
      state, filteredState, isAuthenticated, activeMemberIds, isCloudSyncing, setActiveMemberIds, setAuthenticated, updateProfile, 
      addFamilyMember, removeFamilyMember, toggleFamilyMemberTxPermission,
      addBank, updateBank, deleteBank, addCard, updateCard, deleteCard, addWallet, updateWallet, deleteWallet, 
      addIncome: (i) => {}, addExpense: (e) => {}, addAsset, updateAsset, deleteAsset, addLiability, updateLiability, deleteLiability,
      addTransaction, updateTransaction, deleteTransaction, addBudget, updateBudget, deleteBudget, addTransactionNature, deleteTransactionNature,
      clearNotifications: () => setState(prev => ({...prev, notifications: []})), 
      markNotificationRead: (id) => setState(prev => ({...prev, notifications: prev.notifications.map(n => n.id === id ? {...n, isRead: true} : n)})), 
      simulateSync: async () => {}, resetBoarding, loadStateFromCloud, importState
    }}>
      {children}
    </FinanceContext.Provider>
  );
};

import React, { useMemo, useState, useEffect } from 'react';
import { useFinance } from '../store/FinanceContext';
import { formatCurrency } from '../utils/formatters';
import { calculateAllocatedExpense } from '../utils/calculations';

type RankCategory = 'savings' | 'spending' | 'investments';

interface PeerData {
  id: string;
  name: string;
  value: number;
  percentile: number;
  isUser?: boolean;
}

const Ranking: React.FC = () => {
  const { filteredState, activeMemberIds } = useFinance();
  const [activeCategory, setActiveCategory] = useState<RankCategory>('savings');
  const currency = filteredState.profile.currency;

  const fyDates = useMemo(() => {
    const now = new Date();
    const currentYear = now.getFullYear();
    const startYear = now.getMonth() < 3 ? currentYear - 1 : currentYear;
    const start = new Date(startYear, 3, 1, 0, 0, 0); // April 1st
    const end = new Date(startYear + 1, 2, 31, 23, 59, 59); // March 31st
    return { start, end };
  }, []);

  const userStats = useMemo(() => {
    const { start, end } = fyDates;
    const transactions = filteredState.transactions || [];

    const income = transactions
      .filter(t => t.type === 'Income' && new Date(t.date) >= start && new Date(t.date) <= end)
      .reduce((acc, t) => acc + t.amount, 0);

    const spending = calculateAllocatedExpense(transactions, start, end);

    const investments = transactions
      .filter(t => t.type === 'Asset' && new Date(t.date) >= start && new Date(t.date) <= end)
      .reduce((acc, t) => acc + t.amount, 0);

    return {
      savings: income - spending,
      spending: spending,
      investments: investments
    };
  }, [filteredState.transactions, fyDates]);

  // Simulated Global Peer Group (In a real production app, this would be an aggregate query from Supabase)
  const peerList = useMemo(() => {
    const baseValue = userStats[activeCategory];
    const seed = activeCategory === 'savings' ? 50000 : activeCategory === 'spending' ? 30000 : 20000;

    const peers: PeerData[] = [
      { id: 'p1', name: 'Alpha Vault', value: baseValue * 1.4 + seed * 2, percentile: 99 },
      { id: 'p2', name: 'Delta Strategy', value: baseValue * 1.2 + seed * 1.5, percentile: 95 },
      { id: 'p3', name: 'Zion Reserve', value: baseValue * 1.1 + seed, percentile: 90 },
      { id: 'user', name: 'YOU (Current)', value: baseValue, percentile: 0, isUser: true },
      { id: 'p4', name: 'Node Prime', value: baseValue * 0.8 + seed * 0.5, percentile: 75 },
      { id: 'p5', name: 'Echo Liquidity', value: baseValue * 0.6 + seed * 0.2, percentile: 60 },
      { id: 'p6', name: 'Beta Sector', value: baseValue * 0.4, percentile: 40 },
    ];

    // Sort by value (Spending is ranked inversely - lower is "better" for ranking, but usually leaderboards show high spenders too)
    // We will rank by absolute volume for this dashboard.
    return peers.sort((a, b) => b.value - a.value).map((p, index) => ({
      ...p,
      rank: index + 1,
      // Recalculate percentile based on position in this set for UI feel
      percentile: Math.max(1, Math.floor(((peers.length - index) / peers.length) * 100))
    }));
  }, [userStats, activeCategory]);

  const userRank = peerList.find(p => p.isUser);

  return (
    <div className="space-y-10 animate-in fade-in duration-700 pb-20">
      <div className="flex flex-col md:flex-row md:items-end justify-between gap-6 px-4 md:px-0">
        <div>
          <h2 className="text-2xl md:text-3xl font-black text-slate-800 tracking-tight uppercase">Global Standing</h2>
          <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mt-2">Real-Time Financial Year Benchmarking</p>
        </div>
        <div className="flex items-center gap-1 bg-white p-1.5 rounded-2xl border border-slate-200 shadow-sm">
          {(['savings', 'spending', 'investments'] as RankCategory[]).map(cat => (
            <button 
              key={cat}
              onClick={() => setActiveCategory(cat)}
              className={`px-6 py-2.5 rounded-xl text-[9px] font-black uppercase tracking-widest transition-all ${activeCategory === cat ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-400 hover:text-slate-600'}`}
            >
              {cat}
            </button>
          ))}
        </div>
      </div>

      {/* Highlights / Podium Cards */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="bg-slate-900 p-8 rounded-[2.5rem] text-white shadow-2xl relative overflow-hidden group">
          <div className="absolute top-0 right-0 p-6 text-6xl opacity-10 font-black">#1</div>
          <p className="text-[9px] font-black text-indigo-400 uppercase tracking-widest mb-1">Global Leader</p>
          <h4 className="text-xl font-black uppercase truncate">{peerList[0].name}</h4>
          <p className="text-2xl font-black mt-4 text-emerald-400">{formatCurrency(peerList[0].value, currency)}</p>
          <div className="mt-6 pt-6 border-t border-white/10 flex justify-between items-center">
            <span className="text-[8px] font-black text-white/30 uppercase tracking-widest">99th Percentile</span>
            <span className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse"></span>
          </div>
        </div>

        <div className="bg-white p-8 rounded-[2.5rem] border-2 border-indigo-600 shadow-xl relative overflow-hidden group scale-105 z-10">
          <div className="absolute top-0 right-0 p-6 text-6xl opacity-5 font-black text-indigo-600">ME</div>
          <p className="text-[9px] font-black text-indigo-600 uppercase tracking-widest mb-1">Your Performance</p>
          <h4 className="text-xl font-black uppercase">Active Audit</h4>
          <p className="text-3xl font-black mt-4 text-slate-800">{formatCurrency(userStats[activeCategory], currency)}</p>
          <div className="mt-6 pt-6 border-t border-slate-100 flex justify-between items-center">
            <span className="text-[10px] font-black text-indigo-500 uppercase tracking-widest">Rank #{userRank?.rank} globally</span>
            <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{userRank?.percentile}% Score</span>
          </div>
        </div>

        <div className="bg-slate-50 p-8 rounded-[2.5rem] border border-slate-200 shadow-sm relative overflow-hidden">
           <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-1">Next Milestone</p>
           <h4 className="text-xl font-black text-slate-800 uppercase">To Rank Up</h4>
           <p className="text-2xl font-black mt-4 text-indigo-500">
             +{formatCurrency((peerList[Math.max(0, (userRank?.rank || 1) - 2)].value - userStats[activeCategory]), currency)}
           </p>
           <div className="mt-6 space-y-3">
             <div className="w-full h-1.5 bg-slate-200 rounded-full overflow-hidden">
               <div className="h-full bg-indigo-600 transition-all duration-1000" style={{ width: '65%' }}></div>
             </div>
             <p className="text-[8px] font-black text-slate-400 uppercase tracking-widest">Approaching Top {(userRank?.percentile || 0) + 5}%</p>
           </div>
        </div>
      </div>

      {/* Leaderboard Table */}
      <div className="bg-white rounded-[3rem] border border-slate-200 shadow-sm overflow-hidden">
        <div className="p-8 md:p-10 border-b border-slate-100 flex justify-between items-center bg-slate-50/50">
           <div>
             <h3 className="text-sm font-black text-slate-800 uppercase tracking-widest">Real-Time Leaderboard</h3>
             <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mt-1">Comparing {activeCategory} across active vaults</p>
           </div>
           <span className="px-4 py-2 bg-white border border-slate-200 rounded-xl text-[8px] font-black text-indigo-600 uppercase tracking-widest shadow-sm">Updated Just Now</span>
        </div>

        <div className="divide-y divide-slate-50">
          {peerList.map((peer, i) => (
            <div 
              key={peer.id} 
              className={`p-6 md:px-10 flex items-center justify-between transition-all ${peer.isUser ? 'bg-indigo-50/50 border-l-4 border-indigo-600' : 'hover:bg-slate-50'}`}
            >
              <div className="flex items-center gap-6">
                <div className={`w-10 h-10 rounded-xl flex items-center justify-center font-black text-sm shadow-sm ${
                  i === 0 ? 'bg-yellow-400 text-white' : 
                  i === 1 ? 'bg-slate-300 text-white' : 
                  i === 2 ? 'bg-amber-600 text-white' : 
                  'bg-slate-100 text-slate-400'
                }`}>
                  {i + 1}
                </div>
                <div>
                  <p className={`text-sm font-black uppercase tracking-tight ${peer.isUser ? 'text-indigo-600' : 'text-slate-800'}`}>
                    {peer.name} {peer.isUser && '(ME)'}
                  </p>
                  <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">
                    FY {fyDates.start.getFullYear()}-{fyDates.end.getFullYear().toString().slice(-2)} Audit
                  </p>
                </div>
              </div>

              <div className="text-right">
                <p className={`text-base font-black tracking-tighter ${peer.isUser ? 'text-indigo-600' : 'text-slate-800'}`}>
                  {formatCurrency(peer.value, currency)}
                </p>
                <p className="text-[8px] font-black text-slate-300 uppercase tracking-widest">Top {100 - peer.percentile}%</p>
              </div>
            </div>
          ))}
        </div>

        <div className="p-10 text-center">
           <button className="text-[9px] font-black text-indigo-500 uppercase tracking-widest hover:text-indigo-700 transition-colors">Load Full Global Dataset (5,000+ Vaults)</button>
        </div>
      </div>

      {/* Footer / Context */}
      <div className="bg-indigo-900 p-8 rounded-[2.5rem] text-white flex flex-col md:flex-row items-center justify-between gap-6 shadow-xl relative overflow-hidden">
        <div className="absolute top-0 left-0 p-8 text-6xl opacity-5 font-black">STATS</div>
        <div className="relative z-10 text-center md:text-left">
           <p className="text-[10px] font-black text-indigo-300 uppercase tracking-widest mb-1">Financial Integrity Disclosure</p>
           <h4 className="text-sm font-black uppercase max-w-md leading-relaxed">Rankings are calculated using anonymized data tokens. Your private vault remains strictly isolated and encrypted.</h4>
        </div>
        <div className="relative z-10 grid grid-cols-2 gap-8 text-center md:text-right border-l border-white/10 pl-8">
           <div><p className="text-[8px] font-black text-white/30 uppercase mb-1">Global Avg</p><p className="text-xl font-black text-indigo-200">{formatCurrency(userStats[activeCategory] * 0.85, currency)}</p></div>
           <div><p className="text-[8px] font-black text-white/30 uppercase mb-1">Your Delta</p><p className="text-xl font-black text-emerald-400">+{((userRank?.percentile || 0) - 50).toFixed(0)}%</p></div>
        </div>
      </div>
    </div>
  );
};

export default Ranking;

import React, { useState, useEffect, useRef } from 'react';
import { useFinance } from '../store/FinanceContext';

interface LayoutProps {
  children: React.ReactNode;
  activeTab: string;
  setActiveTab: (tab: string) => void;
}

const Layout: React.FC<LayoutProps> = ({ children, activeTab, setActiveTab }) => {
  const { state, activeMemberIds, isCloudSyncing, setActiveMemberIds, resetBoarding, simulateSync } = useFinance();
  const [showNotifications, setShowNotifications] = useState(false);
  const [showMemberSelector, setShowMemberSelector] = useState(false);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [isShrunk, setIsShrunk] = useState(false);

  const mainRef = useRef<HTMLDivElement>(null);
  const selectorRef = useRef<HTMLDivElement>(null);
  const familyMembers = state.profile?.familyMembers || [];
  const unreadCount = state.notifications.filter(n => !n.isRead).length;

  useEffect(() => {
    const handleScroll = () => {
      if (mainRef.current) {
        setIsShrunk(mainRef.current.scrollTop > 30);
      }
    };
    const currentMain = mainRef.current;
    if (currentMain) {
      currentMain.addEventListener('scroll', handleScroll);
    }
    return () => currentMain?.removeEventListener('scroll', handleScroll);
  }, []);

  const navItems = [
    { id: 'dashboard', label: 'Dashboard', icon: '📊' },
    { id: 'rankings', label: 'Rankings', icon: '🏆' },
    { id: 'accounts', label: 'Accounts', icon: '🏦' },
    { id: 'transactions', label: 'Transactions', icon: '💸' },
    { id: 'budget', label: 'Budget', icon: '🎯' },
    { id: 'calendar', label: 'Calendar', icon: '📅' },
    { id: 'statements', label: 'Reports', icon: '📜' },
    { id: 'profile', label: 'You', icon: '👤' },
  ];

  const isAllSelected = activeMemberIds.includes('all');
  const isMeSelected = activeMemberIds.length === 0;

  const getSelectionLabel = () => {
    if (isAllSelected) return 'Entire Family';
    if (isMeSelected) return 'Mine';
    if (activeMemberIds.length === 1) {
      const member = familyMembers.find(m => m.id === activeMemberIds[0]);
      return member ? member.name : 'Custom View';
    }
    return `Group (${activeMemberIds.length})`;
  };

  const toggleMember = (id: string | 'all') => {
    if (id === 'all') setActiveMemberIds(['all']);
    else if (id === '') setActiveMemberIds([]);
    else {
      let nextIds = activeMemberIds.filter(mid => mid !== 'all');
      nextIds = nextIds.includes(id) ? nextIds.filter(mid => mid !== id) : [...nextIds, id];
      setActiveMemberIds(nextIds);
    }
  };

  const closeMenu = () => setIsMenuOpen(false);

  return (
    <div className="h-[100dvh] w-full flex bg-slate-50 font-sans selection:bg-indigo-100 overflow-hidden relative">

      {/* Drawer Overlay */}
      {isMenuOpen && (
        <div 
          className="fixed inset-0 bg-slate-900/40 backdrop-blur-sm z-[60] animate-in fade-in duration-300"
          onClick={closeMenu}
        />
      )}

      {/* Slide-out Sidebar Drawer */}
      <aside 
        className={`fixed top-0 left-0 bottom-0 w-72 bg-slate-900 border-r border-slate-800 z-[70] flex flex-col text-white transition-transform duration-500 ease-out transform ${isMenuOpen ? 'translate-x-0' : '-translate-x-full'}`}
      >
        <div className="p-8 flex items-center justify-between border-b border-slate-800/50">
          <div className="flex items-center gap-3">
             <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center font-bold">M</div>
             <h1 className="text-xl font-bold tracking-tight">MyFin</h1>
          </div>
          <button onClick={closeMenu} className="text-slate-400 hover:text-white p-2">✕</button>
        </div>

        <nav className="flex-1 px-4 py-8 space-y-1">
          <p className="text-[10px] font-black text-slate-500 uppercase tracking-[0.3em] px-5 mb-4">Command Center</p>
          {navItems.map(item => (
            <button 
              key={item.id} 
              onClick={() => { setActiveTab(item.id); closeMenu(); }} 
              className={`w-full flex items-center gap-4 px-5 py-4 rounded-2xl text-sm font-black transition-all group ${activeTab === item.id ? 'bg-indigo-600 text-white shadow-xl' : 'text-slate-400 hover:text-white hover:bg-slate-800'}`}
            >
              <span className={`text-xl transition-transform ${activeTab === item.id ? 'scale-110' : 'group-hover:scale-110'}`}>{item.icon}</span>
              <span className="uppercase tracking-widest text-[11px]">{item.label}</span>
            </button>
          ))}

          <div className="pt-10 border-t border-slate-800/50 mt-10">
             <button onClick={() => { resetBoarding(); closeMenu(); }} className="w-full flex items-center gap-4 px-5 py-4 rounded-2xl text-[10px] font-black text-slate-500 hover:text-rose-400 hover:bg-rose-500/10 transition-colors uppercase tracking-widest">
              <span className="text-lg">🚪</span>
              <span>Sign Out</span>
            </button>
          </div>
        </nav>

        <div className="p-8 bg-slate-950/50">
           <p className="text-[8px] font-black text-slate-600 uppercase tracking-widest text-center">Protocol v2.5.0 Secure</p>
        </div>
      </aside>

      {/* Main Content Area */}
      <main ref={mainRef} className="flex-1 flex flex-col relative h-full overflow-y-auto overflow-x-hidden custom-scrollbar">

        <header className={`sticky top-0 bg-white/90 backdrop-blur-xl border-b border-slate-200 px-4 md:px-8 z-40 flex justify-between items-center transition-all ${isShrunk ? 'h-14' : 'h-16 md:h-24'} pt-[var(--sat)]`}>

          <div className="flex items-center gap-4 md:gap-6">
            {/* Hamburger Trigger */}
            <button 
              onClick={() => setIsMenuOpen(true)}
              className="w-10 h-10 md:w-12 md:h-12 bg-slate-900 text-white rounded-2xl flex flex-col items-center justify-center gap-1.5 shadow-lg active:scale-90 transition-all group"
            >
              <span className="w-5 h-0.5 bg-white rounded-full group-hover:w-6 transition-all"></span>
              <span className="w-6 h-0.5 bg-indigo-400 rounded-full"></span>
              <span className="w-5 h-0.5 bg-white rounded-full group-hover:w-6 transition-all"></span>
            </button>

            <div className="hidden md:flex flex-col">
               <h1 className="text-sm font-black text-slate-900 uppercase tracking-tighter leading-none">Command Hub</h1>
               <p className="text-[8px] font-black text-indigo-500 uppercase tracking-widest mt-1">Status: Active Verification</p>
            </div>
          </div>

          <div className="flex items-center gap-3">
            <button onClick={() => simulateSync()} className="hidden md:flex bg-indigo-600 text-white px-5 py-2.5 rounded-2xl text-[9px] font-black uppercase tracking-widest shadow-xl shadow-indigo-100 hover:bg-indigo-700 transition-all">🔄 Sync Cloud</button>

            <div className="relative" ref={selectorRef}>
              <button onClick={() => setShowMemberSelector(!showMemberSelector)} className="flex items-center gap-2 px-4 py-2.5 bg-slate-100 rounded-2xl text-[9px] font-black uppercase tracking-widest border border-slate-200 hover:bg-white transition-all">
                <span className="text-xs">👥</span>
                <span className="max-w-[70px] truncate">{getSelectionLabel()}</span>
              </button>
              {showMemberSelector && (
                <div className="absolute top-full right-0 mt-3 w-64 bg-white border border-slate-200 rounded-[2rem] shadow-2xl z-50 p-3 space-y-1 animate-in zoom-in-95 duration-200">
                    <button onClick={() => { toggleMember(''); setShowMemberSelector(false); }} className={`w-full text-left px-5 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest ${isMeSelected ? 'bg-indigo-600 text-white shadow-lg' : 'hover:bg-slate-50 text-slate-500'}`}>👤 My Vault</button>
                    <button onClick={() => { toggleMember('all'); setShowMemberSelector(false); }} className={`w-full text-left px-5 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest ${isAllSelected ? 'bg-indigo-600 text-white shadow-lg' : 'hover:bg-slate-50 text-slate-500'}`}>🌍 Consolidated</button>
                    <div className="h-px bg-slate-100 my-2"></div>
                    {familyMembers.map(m => (
                      <button key={m.id} onClick={() => { toggleMember(m.id); setShowMemberSelector(false); }} className={`w-full text-left px-5 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest ${activeMemberIds.includes(m.id) ? 'bg-indigo-600 text-white shadow-lg' : 'hover:bg-slate-50 text-slate-500'}`}>
                        {m.name}
                      </button>
                    ))}
                </div>
              )}
            </div>

            <button onClick={() => setShowNotifications(!showNotifications)} className="relative w-10 h-10 md:w-12 md:h-12 bg-slate-100 rounded-2xl text-slate-600 flex items-center justify-center hover:bg-white border border-slate-200 transition-all">
               <span className="text-xl">🔔</span>
               {unreadCount > 0 && <span className="absolute top-2 right-2 bg-rose-500 w-2.5 h-2.5 rounded-full border-2 border-white"></span>}
            </button>
          </div>
        </header>

        <div className="flex-1 p-4 md:p-12 w-full pb-20">
          {children}
        </div>

      </main>
    </div>
  );
};

export default Layout;

import React, { useState } from 'react';
import { FinanceProvider, useFinance } from './store/FinanceContext';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import Accounts from './components/Accounts';
import Statements from './components/Statements';
import Profile from './components/Profile';
import Onboarding from './components/Onboarding';
import Transactions from './components/Transactions';
import Rewards from './components/Rewards';
import BudgetPlanner from './components/BudgetPlanner';
import FiscalSentinel from './components/FiscalSentinel';
import Ranking from './components/Ranking';

const MainApp: React.FC = () => {
  const { state, isAuthenticated } = useFinance();
  const [activeTab, setActiveTab] = useState('dashboard');

  if (!isAuthenticated || !state.profile.isBoarded) {
    return <Onboarding />;
  }

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab}>
      {activeTab === 'dashboard' && <Dashboard />}
      {activeTab === 'rankings' && <Ranking />}
      {activeTab === 'transactions' && <Transactions />}
      {activeTab === 'accounts' && <Accounts />}
      {activeTab === 'statements' && <Statements />}
      {activeTab === 'profile' && <Profile />}
      {activeTab === 'rewards' && <Rewards />}
      {activeTab === 'budget' && <BudgetPlanner />}
      {activeTab === 'calendar' && <FiscalSentinel />}
    </Layout>
  );
};

const App: React.FC = () => {
  return (
    <FinanceProvider>
      <MainApp />
    </FinanceProvider>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { useFinance } from '../store/FinanceContext';
import { calculateRates, calculateNetWorth, ANNUAL_MULTIPLIERS } from '../utils/calculations';
import { formatCurrency } from '../utils/formatters';
import { Tooltip, ResponsiveContainer, Cell, PieChart, Pie } from 'recharts';

type RateDisplayMode = 'hourly' | 'daily';

const Dashboard: React.FC = () => {
  const { filteredState, state, activeMemberIds } = useFinance();
  const [displayMode, setDisplayMode] = useState<RateDisplayMode>('hourly');
  const [hoursPerDay, setHoursPerDay] = useState(24);

  const rawRates = calculateRates(filteredState);
  const netWorthData = calculateNetWorth(filteredState);
  const currency = filteredState.profile.currency;

  const familyNotifications = state.notifications.slice(0, 4);
  const isConsolidated = activeMemberIds.includes('all') || activeMemberIds.length > 1;

  // Actual "Live" Derived Calculations (Simple date-based division)
  const dailyIncome = rawRates.income / rawRates.daysPassed;
  const dailyExpense = rawRates.expense / rawRates.daysPassed;
  const dailySavings = dailyIncome - dailyExpense;

  const displayIncome = displayMode === 'daily' ? dailyIncome : (dailyIncome / hoursPerDay);
  const displayExpense = displayMode === 'daily' ? dailyExpense : (dailyExpense / hoursPerDay);
  const displaySavings = displayMode === 'daily' ? dailySavings : (dailySavings / hoursPerDay);

  // Planned "Budgeted" Derived Calculations (Simplified annual to daily/hourly)
  const budgetedAnnualIncome = (filteredState.incomes || []).reduce((acc, inc) => acc + (inc.amount * ANNUAL_MULTIPLIERS[inc.periodicity]), 0);
  const budgetedAnnualExpense = (filteredState.budgets || []).reduce((acc, bud) => acc + (bud.amount), 0);

  const budgetedDailyIncome = budgetedAnnualIncome / 365;
  const budgetedDailyExpense = budgetedAnnualExpense / 365;
  const budgetedDailySavings = budgetedDailyIncome - budgetedDailyExpense;

  const displayBudgetedIncome = displayMode === 'daily' ? budgetedDailyIncome : (budgetedDailyIncome / hoursPerDay);
  const displayBudgetedExpense = displayMode === 'daily' ? budgetedDailyExpense : (budgetedDailyExpense / hoursPerDay);
  const displayBudgetedSavings = displayMode === 'daily' ? budgetedDailySavings : (budgetedDailySavings / hoursPerDay);

  const stats = [
    { 
      label: isConsolidated ? 'Income' : (displayMode === 'daily' ? 'Earnings/Day' : 'Earnings/HR'), 
      value: formatCurrency(displayIncome, currency), 
      budgetedValue: formatCurrency(displayBudgetedIncome, currency),
      color: 'text-indigo-600', 
      bg: 'bg-white',
      border: 'border-slate-200',
      cycle: displayMode === 'daily' ? 'day' : 'hr',
      type: 'income'
    },
    { 
      label: isConsolidated ? 'Spend' : (displayMode === 'daily' ? 'Burn/Day' : 'Burn/HR'), 
      value: formatCurrency(displayExpense, currency), 
      budgetedValue: formatCurrency(displayBudgetedExpense, currency),
      color: 'text-rose-600', 
      bg: 'bg-white',
      border: 'border-slate-200',
      cycle: displayMode === 'daily' ? 'day' : 'hr',
      type: 'expense'
    },
    { 
      label: isConsolidated ? 'Savings' : (displayMode === 'daily' ? 'Savings/Day' : 'Savings/HR'), 
      value: formatCurrency(displaySavings, currency), 
      budgetedValue: formatCurrency(displayBudgetedSavings, currency),
      color: 'text-emerald-600', 
      bg: 'bg-white',
      border: 'border-slate-200',
      cycle: displayMode === 'daily' ? 'day' : 'hr',
      type: 'savings'
    },
    { 
      label: 'Assets', 
      value: formatCurrency(netWorthData.assets, currency), 
      color: 'text-slate-800', 
      bg: 'bg-white',
      border: 'border-slate-200',
      cycle: '' 
    },
    { 
      label: 'Net Worth', 
      value: formatCurrency(netWorthData.netWorth, currency), 
      color: 'text-white', 
      bg: 'bg-indigo-600',
      border: 'border-indigo-600',
      cycle: '' 
