  ];

  const pieData = [
    { name: 'Assets', value: netWorthData.assets, color: '#4f46e5' },
    { name: 'Liabilities', value: netWorthData.liabilities, color: '#cbd5e1' },
  ];

  return (
    <div className="space-y-6 md:space-y-10 animate-in fade-in duration-500 max-w-full">
      {/* Rate Metric Controls - Fixed layout for better mobile visibility */}
