        <div className="flex items-center gap-1 p-1 bg-slate-100/50 rounded-2xl w-full sm:w-auto">
          <button 
            onClick={() => setDisplayMode('hourly')}
            className={`flex-1 sm:flex-none px-4 md:px-6 py-2 rounded-xl text-[9px] md:text-[10px] font-black uppercase tracking-widest transition-all ${displayMode === 'hourly' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-400 hover:text-slate-600'}`}
          >
            Hourly
          </button>
          <button 
