        <div className="fixed inset-0 z-[60] flex items-center justify-center bg-slate-900/60 backdrop-blur-md p-4">
           <div className="bg-white w-full max-w-sm p-10 rounded-[2.5rem] border border-slate-200 shadow-2xl animate-in zoom-in duration-200 text-center">
              <div className="w-16 h-16 bg-rose-50 text-rose-500 rounded-full flex items-center justify-center text-3xl mx-auto mb-8">⚠️</div>
              <h4 className="text-lg font-black text-slate-800 mb-2 uppercase tracking-tighter">Delete Transaction?</h4>
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-10">This will permanently reverse the balance effect of the transaction from your account.</p>
              <div className="flex flex-col gap-3">
                 <button onClick={() => { deleteTransaction(confirmDeleteTx.id); setConfirmDeleteTx(null); }} className="w-full py-4 bg-rose-600 text-white font-black text-[10px] uppercase rounded-2xl shadow-xl shadow-rose-100 hover:bg-rose-700 transition-all active:scale-95">Confirm Purge</button>
                 <button onClick={() => setConfirmDeleteTx(null)} className="w-full py-4 bg-slate-100 text-slate-500 font-black text-[10px] uppercase rounded-2xl hover:bg-slate-200 transition-colors">Abort</button>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

