const Onboarding: React.FC = () => {
  const { state, updateProfile, setAuthenticated, addWallet, loadStateFromCloud, updateMonitoredApps } = useFinance();
  const [authState, setAuthState] = useState<'MOBILE' | 'MFA' | 'PROFILE' | 'APP_SENTINEL'>('MOBILE');
  const [mobileNumber, setMobileNumber] = useState('');
  const [otp, setOtp] = useState(['', '', '', '']);
  const [isVerifyingCloud, setIsVerifyingCloud] = useState(false);
  const [isExistingUser, setIsExistingUser] = useState(false);

  // Sentinel State
  const [isScanning, setIsScanning] = useState(false);
  const [detectedApps, setDetectedApps] = useState<MonitoredApp[]>([]);
  const [hasScanned, setHasScanned] = useState(false);

  const [formData, setFormData] = useState({
    name: '',
    designation: '',
    age: '',
    city: '',
    country: 'India',
    currency: 'INR',
    openingCash: '0'
  });

  const handleSendOtp = async (e: React.FormEvent) => {
    e.preventDefault();
    if (mobileNumber.length >= 8) {
      setIsVerifyingCloud(true);
      const exists = await loadStateFromCloud(mobileNumber);
      setIsExistingUser(exists);
      setIsVerifyingCloud(false);
      setAuthState('MFA');
    }
  };

  const handleVerifyMfa = (e: React.FormEvent) => {
    e.preventDefault();
    if (otp.every(d => d !== '')) {
      if (isExistingUser) setAuthenticated(true);
      else setAuthState('PROFILE');
    }
  };

  const handleProfileSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setAuthState('APP_SENTINEL');
  };

  const startScanning = () => {
    setIsScanning(true);
    setTimeout(() => {
      setDetectedApps(SUGGESTED_APPS);
      setIsScanning(false);
      setHasScanned(true);
    }, 3000);
  };

  const toggleApp = (id: string) => {
    setDetectedApps(prev => prev.map(a => a.id === id ? { ...a, isEnabled: !a.isEnabled } : a));
  };

  const finalizeOnboarding = () => {
    updateProfile({ 
      ...formData, 
      age: Number(formData.age), 
      mobileNumber, 
      isBoarded: true, 
      familyMembers: [],
      cloudDatabaseName: 'Default_Vault',
      monitoredApps: detectedApps.filter(a => a.isEnabled),
      remindersEnabled: true
    });

    addWallet({ id: 'default-cash', name: 'Cash', balance: Number(formData.openingCash) });
    setAuthenticated(true);
  };

  const containerClasses = "min-h-[100dvh] bg-white md:bg-slate-50 flex items-stretch md:items-center justify-center overflow-hidden";
  const cardClasses = "w-full md:max-w-md bg-white p-8 md:p-12 md:rounded-[3rem] md:shadow-2xl md:border md:border-slate-100 flex flex-col justify-center animate-in fade-in zoom-in-95 duration-500";

  if (authState === 'MOBILE') {
    return (
      <div className={containerClasses}>
        <div className={cardClasses}>
          <div className="mb-12 text-center">
            <div className="w-16 h-16 bg-indigo-600 text-white rounded-3xl flex items-center justify-center text-3xl font-black mx-auto mb-6 shadow-xl shadow-indigo-200">M</div>
            <h1 className="text-4xl font-black tracking-tighter text-slate-900">MyFin</h1>
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.3em] mt-3">Private Wealth Portal</p>
          </div>

          <form onSubmit={handleSendOtp} className="space-y-10">
            <div className="space-y-4">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block ml-1">Authentication Key</label>
              <div className="relative border-b-4 border-slate-100 pb-4 focus-within:border-indigo-600 transition-all duration-300">
                <div className="flex items-center">
                  <span className="text-slate-400 font-black text-2xl mr-2">+</span>
                  <input 
                    required 
                    type="tel" 
                    autoFocus
                    placeholder="Mobile Number" 
                    className="w-full bg-transparent outline-none font-black text-3xl tracking-tight text-slate-900 placeholder:text-slate-200" 
                    value={mobileNumber} 
                    onChange={e => setMobileNumber(e.target.value.replace(/\D/g, ''))} 
                  />
                </div>
              </div>
            </div>

            <button 
              type="submit" 
              disabled={isVerifyingCloud || mobileNumber.length < 8} 
              className={`w-full py-6 text-white font-black text-xs uppercase tracking-widest rounded-3xl transition-all shadow-xl flex items-center justify-center gap-3 ${isVerifyingCloud || mobileNumber.length < 8 ? 'bg-slate-200 text-slate-400' : 'bg-indigo-600 hover:bg-indigo-700 shadow-indigo-100 active:scale-95'}`}
            >
              {isVerifyingCloud ? (<><span className="animate-spin">⚙️</span> Syncing (~5s)...</>) : 'Request Access'}
            </button>
          </form>

          <p className="mt-12 text-[10px] text-slate-400 text-center font-bold leading-relaxed uppercase tracking-widest opacity-60">
            Secure End-to-End Encryption Enabled
          </p>
        </div>
      </div>
    );
  }

  if (authState === 'MFA') {
    return (
      <div className={containerClasses}>
        <div className={cardClasses}>
          <div className="mb-12">
            <h2 className="text-[10px] font-black text-indigo-600 uppercase tracking-[0.3em] mb-3">Security Check</h2>
            <p className="text-2xl font-black text-slate-900 tracking-tight">Enter verification code sent to <span className="text-indigo-600">+{mobileNumber}</span></p>
          </div>
          <div className="flex justify-between gap-3 mb-12">
            {otp.map((digit, i) => (
              <input 
                key={i} 
                id={`otp-${i}`} 
                required 
                type="number" 
                className="w-full h-20 text-center text-4xl font-black bg-slate-50 border-2 border-transparent rounded-3xl focus:border-indigo-600 focus:bg-white outline-none transition-all" 
                value={digit} 
                onChange={e => {
                  const n = [...otp]; n[i] = e.target.value.slice(-1); setOtp(n);
                  if (e.target.value && i < 3) document.getElementById(`otp-${i+1}`)?.focus();
                }} 
              />
            ))}
          </div>
          <button 
            onClick={handleVerifyMfa} 
            disabled={otp.some(d => d === '')}
            className={`w-full py-6 font-black text-xs uppercase tracking-widest rounded-3xl shadow-xl transition-all ${otp.some(d => d === '') ? 'bg-slate-100 text-slate-400' : 'bg-slate-900 text-white hover:bg-black shadow-slate-200'}`}
          >
            {isExistingUser ? 'Restore & Vault' : 'Validate Session'}
          </button>
          <button onClick={() => setAuthState('MOBILE')} className="mt-6 text-[10px] font-black text-slate-400 uppercase tracking-widest text-center hover:text-indigo-600 transition-colors">Wrong number?</button>
        </div>
      </div>
    );
  }

  if (authState === 'APP_SENTINEL') {
    return (
      <div className={containerClasses}>
        <div className="w-full md:max-w-2xl bg-white p-8 md:p-16 md:rounded-[3rem] md:shadow-2xl md:border md:border-slate-100 flex flex-col justify-center animate-in fade-in duration-500 overflow-y-auto max-h-[90dvh] custom-scrollbar">
          {!hasScanned && !isScanning ? (
            <div className="text-center py-10">
               <div className="w-20 h-20 bg-indigo-50 text-indigo-600 rounded-3xl flex items-center justify-center text-4xl mx-auto mb-8 shadow-inner animate-pulse">📡</div>
               <h2 className="text-2xl font-black text-slate-900 uppercase tracking-tighter">Sentinel Protocol</h2>
               <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mt-3 leading-loose">To enable contextual reminders, MyFin needs to scan for banking and UPI apps in your local ecosystem.</p>
               <button 
                 onClick={startScanning}
                 className="mt-12 w-full py-6 bg-slate-900 text-white font-black text-[10px] uppercase tracking-[0.3em] rounded-3xl shadow-xl active:scale-95 transition-all"
               >
                 Initialise Environment Scan
               </button>
               <button onClick={finalizeOnboarding} className="mt-4 text-[9px] font-black text-slate-300 uppercase tracking-widest hover:text-slate-500 transition-colors">Skip for now</button>
            </div>
          ) : isScanning ? (
            <div className="text-center py-20 relative">
               <div className="absolute inset-0 flex items-center justify-center">
                  <div className="w-40 h-40 border-4 border-indigo-100 rounded-full animate-ping opacity-20"></div>
                  <div className="absolute w-60 h-60 border-2 border-indigo-50 rounded-full animate-ping opacity-10" style={{ animationDelay: '0.5s' }}></div>
               </div>
               <div className="relative z-10">
                 <div className="w-12 h-12 bg-indigo-600 text-white rounded-xl flex items-center justify-center text-xl mx-auto mb-6 animate-bounce">🔍</div>
                 <p className="text-xs font-black text-indigo-600 uppercase tracking-[0.4em] animate-pulse">Scanning Ecosystem...</p>
                 <p className="text-[8px] font-black text-slate-300 uppercase mt-4 tracking-widest">Identifying local financial endpoints</p>
               </div>
            </div>
          ) : (
            <div className="animate-in fade-in duration-700">
               <div className="flex justify-between items-center mb-10">
                  <div>
                    <h2 className="text-xl font-black text-slate-900 uppercase tracking-tighter">Scan Result</h2>
                    <p className="text-[9px] font-black text-emerald-500 uppercase tracking-widest mt-1">✓ Environment Verified</p>
                  </div>
                  <div className="px-4 py-2 bg-indigo-50 text-indigo-600 rounded-xl text-[8px] font-black uppercase tracking-widest">7 Apps Found</div>
               </div>

               <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-6">Link apps to enable "Contextual Reminders"</p>

               <div className="grid grid-cols-1 gap-3 mb-12">
                  {detectedApps.map(app => (
                    <div 
                      key={app.id} 
                      onClick={() => toggleApp(app.id)}
                      className={`p-5 rounded-3xl border-2 transition-all cursor-pointer flex items-center justify-between group ${app.isEnabled ? 'bg-indigo-50 border-indigo-600 shadow-lg shadow-indigo-100/50' : 'bg-white border-slate-100 hover:border-slate-200'}`}
                    >
                      <div className="flex items-center gap-5">
                         <div className={`w-12 h-12 rounded-2xl flex items-center justify-center text-2xl shadow-sm transition-transform group-hover:scale-110 ${app.isEnabled ? 'bg-white text-indigo-600' : 'bg-slate-50'}`}>
                           {app.icon}
                         </div>
                         <div>
                            <p className={`text-xs font-black uppercase tracking-tight ${app.isEnabled ? 'text-indigo-600' : 'text-slate-800'}`}>{app.name}</p>
                            <p className="text-[8px] font-black text-slate-400 uppercase tracking-widest mt-1">{app.category}</p>
                         </div>
                      </div>
                      <div className={`w-10 h-6 rounded-full relative transition-colors ${app.isEnabled ? 'bg-indigo-600' : 'bg-slate-200'}`}>
                         <div className={`absolute top-1 w-4 h-4 bg-white rounded-full transition-all ${app.isEnabled ? 'left-5' : 'left-1'}`}></div>
                      </div>
                    </div>
                  ))}
               </div>

               <div className="p-6 bg-slate-900 text-white rounded-[2.5rem] mb-10">
                  <div className="flex items-start gap-4">
                     <div className="text-2xl mt-1">🛡️</div>
                     <div>
                        <p className="text-[9px] font-black uppercase tracking-widest text-indigo-400 mb-1">Privacy Guarantee</p>
                        <p className="text-[10px] font-medium leading-relaxed text-slate-300">MyFin never reads transaction data from other apps. It only monitors activity to nudge you to log transactions manually.</p>
                     </div>
                  </div>
               </div>

               <button 
                 onClick={finalizeOnboarding}
                 className="w-full py-6 bg-indigo-600 text-white font-black text-xs uppercase tracking-[0.2em] rounded-3xl shadow-2xl shadow-indigo-100 hover:bg-indigo-700 transition-all active:scale-95"
               >
                 Activate Sentinel Protocol
               </button>
            </div>
          )}
        </div>
      </div>
    );
  }

  return (
    <div className={containerClasses}>
      <div className="w-full md:max-w-2xl bg-white p-8 md:p-16 md:rounded-[3rem] md:shadow-2xl md:border md:border-slate-100 flex flex-col justify-center animate-in fade-in duration-500 overflow-y-auto">
        <div className="mb-12">
          <h2 className="text-3xl font-black text-slate-900 tracking-tighter uppercase">Vault Setup</h2>
          <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.3em] mt-3">Localization Protocols</p>
        </div>

        <form onSubmit={handleProfileSubmit} className="space-y-10">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-8 md:gap-12">
            <div className="space-y-3 border-b-2 border-slate-100 pb-3 focus-within:border-indigo-600 transition-all">
              <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Legal Name</label>
              <input required placeholder="Your Full Name" className="w-full bg-transparent outline-none font-black text-xl text-slate-900 placeholder:text-slate-200" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} />
            </div>
            <div className="space-y-3 border-b-2 border-slate-100 pb-3 focus-within:border-indigo-600 transition-all">
              <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Profession</label>
              <input required placeholder="Designation" className="w-full bg-transparent outline-none font-black text-xl text-slate-900 placeholder:text-slate-200" value={formData.designation} onChange={e => setFormData({...formData, designation: e.target.value})} />
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-8 md:gap-12">
            <div className="space-y-3 border-b-2 border-slate-100 pb-3 focus-within:border-indigo-600 transition-all">
              <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest">City</label>
              <input required placeholder="Current City" className="w-full bg-transparent outline-none font-black text-xl text-slate-900 placeholder:text-slate-200" value={formData.city} onChange={e => setFormData({...formData, city: e.target.value})} />
            </div>
            <div className="space-y-3 border-b-2 border-slate-100 pb-3 focus-within:border-indigo-600 transition-all">
              <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Currency Base</label>
              <select className="w-full bg-transparent outline-none font-black text-xl text-slate-900 cursor-pointer" value={formData.country} onChange={e => {
                const country = countries.find(c => c.name === e.target.value);
                setFormData({...formData, country: e.target.value, currency: country?.currency || 'USD'});
              }}>
                {countries.map(c => <option key={c.name} value={c.name}>{c.name}</option>)}
              </select>
            </div>
          </div>

          <div className="space-y-3 border-b-2 border-slate-100 pb-4 focus-within:border-indigo-600 transition-all">
            <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Initial Liquidity (Cash)</label>
            <div className="flex items-center">
              <span className="text-indigo-600 font-black text-2xl mr-2">{formData.currency}</span>
              <input type="number" step="any" placeholder="0.00" className="w-full bg-transparent outline-none font-black text-4xl text-slate-900" value={formData.openingCash} onChange={e => setFormData({...formData, openingCash: e.target.value})} />
            </div>
          </div>

          <button type="submit" className="w-full py-6 bg-indigo-600 text-white font-black text-xs uppercase tracking-[0.2em] rounded-3xl shadow-2xl shadow-indigo-100 hover:bg-indigo-700 transition-all active:scale-95">Initialise Profile</button>
        </form>
      </div>
    </div>
  );
};

export default Onboarding;

import React, { useState, useRef } from 'react';
import { useFinance } from '../store/FinanceContext';
import { MonitoredApp } from '../types';

const Profile: React.FC = () => {
  const { state, updateProfile, addFamilyMember, removeFamilyMember, toggleFamilyMemberTxPermission, importState, resetBoarding, updateMonitoredApps } = useFinance();
  const profile = state.profile;
  const [showAddMember, setShowAddMember] = useState(false);
  const [isLinking, setIsLinking] = useState(false);
  const [newMember, setNewMember] = useState({ name: '', relation: 'Spouse', mobile: '', canAddTransactions: true });
  const [editingCloudLabel, setEditingCloudLabel] = useState(false);
  const [cloudLabel, setCloudLabel] = useState(profile.cloudDatabaseName || '');
  const [confirmReset, setConfirmReset] = useState(false);
  const [showSentinelConfig, setShowSentinelConfig] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleAddMember = async (e: React.FormEvent) => {
    e.preventDefault();
    if (newMember.name && newMember.mobile) {
      setIsLinking(true);
      try {
        await addFamilyMember({
          id: Math.random().toString(36).substr(2, 9),
          name: newMember.name,
          relation: newMember.relation,
          mobileNumber: newMember.mobile,
          canAddTransactions: newMember.canAddTransactions
        });

        setNewMember({ name: '', relation: 'Spouse', mobile: '', canAddTransactions: true });
        setShowAddMember(false);
      } finally {
        setIsLinking(false);
      }
    }
  };

  const handleUpdateCloudLabel = () => {
    updateProfile({ ...profile, cloudDatabaseName: cloudLabel });
    setEditingCloudLabel(false);
  };

  const handleExportData = () => {
    const dataStr = JSON.stringify(state, null, 2);
    const dataUri = 'data:application/json;charset=utf-8,'+ encodeURIComponent(dataStr);
    const exportFileDefaultName = `myfin_backup_${new Date().toISOString().split('T')[0]}.json`;
    const linkElement = document.createElement('a');
    linkElement.setAttribute('href', dataUri);
    linkElement.setAttribute('download', exportFileDefaultName);
    linkElement.click();
  };

  const handleFileImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (event) => {
        try {
          const json = JSON.parse(event.target?.result as string);
          if (window.confirm("Restore this vault?")) {
            importState(json);
          }
        } catch (err) {
          alert("Invalid backup file.");
        }
      };
      reader.readAsText(file);
    }
  };

  return (
    <div className="space-y-6 md:space-y-10 max-w-4xl animate-in fade-in duration-500 pb-20 -mx-3 md:mx-0">
      {/* Main Profile Header */}
      <div className="bg-white md:rounded-3xl md:border border-slate-200 shadow-sm overflow-hidden">
        <div className="h-32 md:h-40 bg-indigo-600 p-6 md:p-8 flex items-end relative">
           <div className="absolute top-0 right-0 p-4 md:p-8 text-6xl md:text-8xl font-black text-white/10 tracking-tighter select-none">MF</div>
           <div className="w-20 h-20 md:w-24 md:h-24 bg-white p-1 translate-y-10 md:translate-y-12 z-10 shadow-xl rounded-2xl">
               <div className="w-full h-full bg-slate-100 flex items-center justify-center text-3xl md:text-4xl font-black text-indigo-600 rounded-xl uppercase">
                 {profile?.name?.charAt(0) || '?'}
               </div>
           </div>
        </div>
        <div className="px-6 md:px-8 pt-12 md:pt-16 pb-8 md:pb-10">
          <div className="flex justify-between items-start mb-6 md:mb-8">
            <div>
              <h3 className="text-2xl md:text-3xl font-black text-slate-800 tracking-tight uppercase">{profile?.name}</h3>
              <p className="text-[10px] md:text-xs font-black text-indigo-500 uppercase tracking-widest mt-1">{profile?.designation}</p>
            </div>
            <div className="text-right">
               <p className="text-[8px] font-black text-slate-300 uppercase tracking-widest mb-1">Key</p>
               <p className="text-[11px] font-black text-slate-600">+{profile?.mobileNumber}</p>
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4 p-4 md:p-6 bg-slate-50 border border-slate-100 rounded-2xl">
             <div><p className="text-[8px] font-black text-slate-400 uppercase tracking-widest mb-1">Localization</p><p className="text-xs font-black text-slate-800 uppercase truncate">{profile?.city}, {profile?.country}</p></div>
             <div><p className="text-[8px] font-black text-slate-400 uppercase tracking-widest mb-1">Base CCY</p><p className="text-xs font-black text-indigo-600 uppercase">{profile?.currency}</p></div>
          </div>
        </div>
      </div>

      {/* Primary Data Actions */}
      <div className="grid grid-cols-2 gap-3 px-3 md:px-0">
        <button onClick={handleExportData} className="p-6 bg-white border border-slate-200 rounded-3xl shadow-sm text-center space-y-2 active:bg-slate-50">
          <div className="text-2xl">💾</div>
          <p className="text-[9px] font-black uppercase tracking-widest text-slate-800">Backup</p>
        </button>
        <button onClick={() => fileInputRef.current?.click()} className="p-6 bg-indigo-600 text-white rounded-3xl shadow-xl text-center space-y-2 active:scale-95 transition-transform">
          <div className="text-2xl">📂</div>
          <p className="text-[9px] font-black uppercase tracking-widest">Restore</p>
        </button>
        <input type="file" ref={fileInputRef} className="hidden" accept=".json" onChange={handleFileImport} />
      </div>

      {/* Sentinel Protocol Section */}
      <div className="px-3 md:px-0">
        <div className="bg-white p-6 md:p-8 rounded-[2rem] border border-slate-200 shadow-sm relative overflow-hidden group">
          <div className="absolute top-0 right-0 p-4 text-4xl opacity-5 group-hover:scale-110 transition-transform">🛡️</div>
          <div className="flex justify-between items-center mb-6">
            <h4 className="text-[10px] font-black text-slate-800 uppercase tracking-[0.2em]">Smart Sentinel</h4>
            <span className={`px-3 py-1 rounded-full text-[8px] font-black uppercase tracking-widest ${profile.remindersEnabled ? 'bg-emerald-50 text-emerald-600' : 'bg-slate-50 text-slate-400'}`}>
              {profile.remindersEnabled ? 'Protocol Active' : 'Offline'}
            </span>
          </div>
          <p className="text-[10px] text-slate-500 font-medium leading-relaxed mb-6">Contextual awareness nudges you to log expenses when you use financial ecosystems.</p>
          <div className="flex items-center gap-2">
            <button 
              onClick={() => setShowSentinelConfig(true)}
              className="px-6 py-3 bg-slate-900 text-white rounded-xl text-[9px] font-black uppercase tracking-widest shadow-lg"
            >
              Configure Protocol
            </button>
            <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-4">
              {profile.monitoredApps?.length || 0} Connected Apps
            </p>
          </div>
        </div>
      </div>

      {/* Cloud & Family Sections */}
      <div className="space-y-4 px-3 md:px-0">
        <div className="bg-white p-6 md:p-8 rounded-[2rem] border border-slate-200 shadow-sm">
          <h4 className="text-[10px] font-black text-slate-800 uppercase tracking-[0.2em] mb-4">Cloud Identity</h4>
          <div className="p-4 bg-slate-50 border border-slate-100 rounded-2xl">
            {editingCloudLabel ? (
              <div className="flex gap-2">
                <input className="flex-1 p-2 bg-white border border-slate-200 rounded-xl outline-none font-bold text-xs" value={cloudLabel} onChange={e => setCloudLabel(e.target.value)} />
                <button onClick={handleUpdateCloudLabel} className="px-4 py-2 bg-indigo-600 text-white rounded-xl text-[10px] font-black uppercase">Ok</button>
              </div>
            ) : (
              <div className="flex justify-between items-center">
                <p className="text-xs font-black text-slate-800 uppercase tracking-tight">{profile.cloudDatabaseName || 'PERSONAL_VAULT'}</p>
                <button onClick={() => setEditingCloudLabel(true)} className="text-[9px] font-black text-indigo-600 uppercase">Change</button>
              </div>
            )}
          </div>
        </div>

        <div className="bg-white p-6 md:p-8 rounded-[2rem] border border-slate-200 shadow-sm">
          <div className="flex justify-between items-center mb-6">
