                        updateMonitoredApps(nextApps);
                      }}
                      className={`p-5 rounded-2xl border-2 transition-all cursor-pointer flex items-center justify-between ${isMonitored ? 'bg-indigo-50 border-indigo-600' : 'bg-slate-50 border-slate-100 hover:border-slate-200'}`}
                    >
