                      <div className={`w-10 h-6 rounded-full relative transition-colors ${isMonitored ? 'bg-indigo-600' : 'bg-slate-300'}`}>
                         <div className={`absolute top-1 w-4 h-4 bg-white rounded-full transition-all ${isMonitored ? 'left-5' : 'left-1'}`}></div>
                      </div>
                    </div>
                  );
                })}
             </div>

             <button 
               onClick={() => setShowSentinelConfig(false)}
               className="mt-10 w-full py-5 bg-slate-900 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-xl active:scale-95 transition-all"
             >
               Save Protocol State
             </button>
           </div>
        </div>
      )}
    </div>
  );
};

