      addBudget: (b) => setState(prev => ({...prev, budgets: [...prev.budgets, b]})), updateBudget: (b) => setState(prev => ({...prev, budgets: prev.budgets.map(x => x.id === b.id ? b : x)})), deleteBudget: (id) => setState(prev => ({...prev, budgets: prev.budgets.filter(b => b.id !== id)})),
      addTransactionNature: () => {}, deleteTransactionNature: () => {}, clearNotifications: () => {}, markNotificationRead: () => {}, 
      simulateSync, 
      resetBoarding, 
      loadStateFromCloud, 
      importState: () => {}, 
      updateMonitoredApps: () => {}
    }}>
      {children}
    </FinanceContext.Provider>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { useFinance } from '../store/FinanceContext';
import BulkAuditModal from './BulkAuditModal';

interface LayoutProps {
  children: React.ReactNode;
  activeTab: string;
  setActiveTab: (tab: string) => void;
}

const Layout: React.FC<LayoutProps> = ({ children, activeTab, setActiveTab }) => {
  const { state, activeMemberIds, isCloudSyncing, setActiveMemberIds, resetBoarding, simulateSync, approveTransaction, rejectTransaction } = useFinance();
  const [showNotifications, setShowNotifications] = useState(false);
  const [showMemberSelector, setShowMemberSelector] = useState(false);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [isShrunk, setIsShrunk] = useState(false);
  const [showBulkAudit, setShowBulkAudit] = useState(false);

  const mainRef = useRef<HTMLDivElement>(null);
  const familyMembers = state.profile?.familyMembers || [];

  // Get permissions for the currently active view
  const activePermissions = React.useMemo(() => {
    if (activeMemberIds.length === 0 || activeMemberIds.includes('all')) return null; // Owner or Consolidated has full access
    if (activeMemberIds.length === 1) {
      return familyMembers.find(m => m.id === activeMemberIds[0])?.permissions || null;
    }
    return null;
  }, [activeMemberIds, familyMembers]);

  useEffect(() => {
    const handleScroll = () => { if (mainRef.current) setIsShrunk(mainRef.current.scrollTop > 30); };
    const currentMain = mainRef.current;
    if (currentMain) currentMain.addEventListener('scroll', handleScroll);
    return () => currentMain?.removeEventListener('scroll', handleScroll);
  }, []);

  const rawNavItems = [
    { id: 'dashboard', label: 'Dashboard', icon: '📊', perm: 'viewDashboard' },
    { id: 'rankings', label: 'Rankings', icon: '🏆', perm: 'viewDashboard' },
    { id: 'accounts', label: 'Accounts', icon: '🏦', perm: 'viewAccounts' },
    { id: 'transactions', label: 'Transactions', icon: '💸', perm: 'viewTransactions' },
    { id: 'budget', label: 'Budget', icon: '🎯', perm: 'viewBudget' },
    { id: 'calendar', label: 'Calendar', icon: '📅', perm: 'viewCalendar' },
    { id: 'statements', label: 'Reports', icon: '📜', perm: 'viewStatements' },
    { id: 'profile', label: 'You', icon: '👤', perm: null },
  ];

  const navItems = rawNavItems.filter(item => {
    if (!activePermissions || !item.perm) return true;
    return (activePermissions as any)[item.perm];
  });

  const isAllSelected = activeMemberIds.includes('all');
  const isMeSelected = activeMemberIds.length === 0;

  const getSelectionLabel = () => {
    if (isAllSelected) return 'Entire Family';
    if (isMeSelected) return 'Mine';
    const member = familyMembers.find(m => m.id === activeMemberIds[0]);
    return member ? member.name : 'Group View';
  };

  const pendingApprovals = state.notifications.filter(n => n.type === 'approval_request');

  const handleSignOut = async () => {
    await resetBoarding();
  };

  return (
    <div className="h-[100dvh] w-full flex bg-slate-50 font-sans selection:bg-indigo-100 overflow-hidden relative">
      {isMenuOpen && <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-sm z-[60]" onClick={() => setIsMenuOpen(false)} />}

      <aside className={`fixed top-0 left-0 bottom-0 w-72 bg-slate-900 z-[70] flex flex-col text-white transition-transform duration-500 ease-out transform ${isMenuOpen ? 'translate-x-0' : '-translate-x-full'}`}>
        <div className="p-8 flex items-center justify-between border-b border-slate-800/50">
          <div className="flex items-center gap-3"><div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center font-bold">M</div><h1 className="text-xl font-bold">MyFin</h1></div>
          <button onClick={() => setIsMenuOpen(false)} className="text-slate-400 p-2">✕</button>
        </div>
        <nav className="flex-1 px-4 py-8 space-y-1 overflow-y-auto custom-scrollbar">
          {navItems.map(item => (
            <button key={item.id} onClick={() => { setActiveTab(item.id); setIsMenuOpen(false); }} className={`w-full flex items-center gap-4 px-5 py-4 rounded-2xl text-sm font-black transition-all ${activeTab === item.id ? 'bg-indigo-600 text-white' : 'text-slate-400 hover:text-white hover:bg-slate-800'}`}>
              <span className="text-xl">{item.icon}</span><span className="uppercase tracking-widest text-[11px]">{item.label}</span>
            </button>
          ))}

          <div className="my-4 mx-5 h-px bg-slate-800/50"></div>

          <button onClick={handleSignOut} className="w-full flex items-center gap-4 px-5 py-4 rounded-2xl text-sm font-black transition-all text-slate-400 hover:text-rose-400 hover:bg-slate-800/50 group">
            <span className="text-xl group-hover:scale-110 transition-transform">🚪</span><span className="uppercase tracking-widest text-[11px]">Sign Out</span>
          </button>
        </nav>
      </aside>

      <main ref={mainRef} className="flex-1 flex flex-col relative h-full overflow-y-auto custom-scrollbar">
        <header className={`sticky top-0 bg-white/90 backdrop-blur-xl border-b border-slate-200 px-4 md:px-8 z-40 flex justify-between items-center transition-all ${isShrunk ? 'h-14' : 'h-16 md:h-24'}`}>
          <div className="flex items-center gap-4">
            <button onClick={() => setIsMenuOpen(true)} className="w-10 h-10 bg-slate-900 text-white rounded-2xl flex flex-col items-center justify-center gap-1.5 shadow-lg active:scale-90 transition-all group">
              <span className="w-5 h-0.5 bg-white rounded-full group-hover:w-6 transition-all"></span>
              <span className="w-6 h-0.5 bg-indigo-400 rounded-full"></span>
              <span className="w-5 h-0.5 bg-white rounded-full group-hover:w-6 transition-all"></span>
            </button>
          </div>

          <div className="flex items-center gap-3">
            <div className="relative">
              <button onClick={() => setShowMemberSelector(!showMemberSelector)} className="flex items-center gap-2 px-4 py-2.5 bg-slate-100 rounded-2xl text-[9px] font-black uppercase tracking-widest border border-slate-200">
                <span className="text-xs">👥</span><span className="max-w-[70px] truncate">{getSelectionLabel()}</span>
              </button>
              {showMemberSelector && (
                <div className="absolute top-full right-0 mt-3 w-64 bg-white border border-slate-200 rounded-[2rem] shadow-2xl z-50 p-3 space-y-1">
                    <button onClick={() => { setActiveMemberIds([]); setShowMemberSelector(false); }} className={`w-full text-left px-5 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest ${isMeSelected ? 'bg-indigo-600 text-white shadow-lg' : 'hover:bg-slate-50 text-slate-500'}`}>👤 My Vault</button>
                    <button onClick={() => { setActiveMemberIds(['all']); setShowMemberSelector(false); }} className={`w-full text-left px-5 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest ${isAllSelected ? 'bg-indigo-600 text-white shadow-lg' : 'hover:bg-slate-50 text-slate-500'}`}>🌍 Consolidated</button>
                    <div className="h-px bg-slate-100 my-2"></div>
                    {familyMembers.map(m => (
                      <button key={m.id} onClick={() => { setActiveMemberIds([m.id]); setShowMemberSelector(false); }} className={`w-full text-left px-5 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest ${activeMemberIds.includes(m.id) ? 'bg-indigo-600 text-white shadow-lg' : 'hover:bg-slate-50 text-slate-500'}`}>
                        {m.name} {m.status === 'pending_invitation' && '⏳'}
                      </button>
                    ))}
                </div>
              )}
            </div>

            <button onClick={() => setShowNotifications(!showNotifications)} className="relative w-10 h-10 bg-slate-100 rounded-2xl text-slate-600 flex items-center justify-center border border-slate-200 transition-all">
               <span className="text-xl">🔔</span>
               {pendingApprovals.length > 0 && <span className="absolute top-2 right-2 bg-rose-500 w-2.5 h-2.5 rounded-full border-2 border-white"></span>}
            </button>
          </div>
        </header>

        <div className="flex-1 p-4 md:p-12 pb-20">{children}</div>

        {showNotifications && pendingApprovals.length > 0 && (
          <div className="fixed top-24 right-4 w-80 bg-white border border-slate-200 rounded-[2.5rem] shadow-2xl z-50 p-6 animate-in slide-in-from-right-10 flex flex-col max-h-[70vh]">
            <div className="flex justify-between items-center mb-6">
               <h4 className="text-[10px] font-black text-slate-800 uppercase tracking-widest">Action Required</h4>
               {pendingApprovals.length > 1 && (
                 <button 
                   onClick={() => { setShowBulkAudit(true); setShowNotifications(false); }}
                   className="text-[9px] font-black text-indigo-600 uppercase tracking-widest bg-indigo-50 px-2 py-1 rounded-lg"
                 >
                   Bulk Audit
                 </button>
               )}
            </div>

            <div className="space-y-4 overflow-y-auto custom-scrollbar flex-1 pr-1">
               {pendingApprovals.map(n => (
                 <div key={n.id} className="p-4 bg-slate-50 rounded-2xl border border-slate-100">
                    <p className="text-[10px] font-black text-slate-800 uppercase leading-tight">{n.title}</p>
                    <p className="text-[9px] text-slate-500 font-medium mt-1">{n.message}</p>
                    <div className="flex gap-2 mt-4">
                       <button onClick={() => approveTransaction(n.transactionId!)} className="flex-1 py-2 bg-emerald-600 text-white text-[8px] font-black uppercase rounded-lg">Approve</button>
                       <button onClick={() => rejectTransaction(n.transactionId!)} className="flex-1 py-2 bg-rose-50 text-rose-500 text-[8px] font-black uppercase rounded-lg">Reject</button>
                    </div>
                 </div>
               ))}
            </div>
          </div>
        )}

        {showBulkAudit && <BulkAuditModal onClose={() => setShowBulkAudit(false)} />}
      </main>
    </div>
  );
};

export default Layout;

import React, { useState, useMemo } from 'react';
import { useFinance } from '../store/FinanceContext';
import { calculateRates, calculateNetWorth, ANNUAL_MULTIPLIERS } from '../utils/calculations';
import { formatCurrency } from '../utils/formatters';
import { Tooltip, ResponsiveContainer, Cell, PieChart, Pie } from 'recharts';

type RateDisplayMode = 'hourly' | 'daily' | 'monthly';

const Dashboard: React.FC = () => {
  const { filteredState, state, activeMemberIds } = useFinance();
  const [displayMode, setDisplayMode] = useState<RateDisplayMode>('hourly');
  const [hoursPerDay, setHoursPerDay] = useState(24);

  const rawRates = calculateRates(filteredState);
  const netWorthData = calculateNetWorth(filteredState);
  const currency = filteredState.profile.currency;

  const familyNotifications = state.notifications.slice(0, 4);
  const isConsolidated = activeMemberIds.includes('all') || activeMemberIds.length > 1;

  // Actual "Live" Derived Calculations (Simple date-based division)
  const dailyIncome = rawRates.income / rawRates.daysPassed;
  const dailyExpense = rawRates.expense / rawRates.daysPassed;
  const dailySavings = dailyIncome - dailyExpense;

  const getDisplayValues = () => {
    switch (displayMode) {
      case 'monthly':
        return {
          income: rawRates.income,
          expense: rawRates.expense,
          savings: rawRates.monthlySurplus,
          cycle: 'mo'
        };
      case 'daily':
        return {
          income: dailyIncome,
          expense: dailyExpense,
          savings: dailySavings,
          cycle: 'day'
        };
      case 'hourly':
      default:
        return {
          income: dailyIncome / hoursPerDay,
          expense: dailyExpense / hoursPerDay,
          savings: dailySavings / hoursPerDay,
          cycle: 'hr'
        };
    }
  };

  const currentDisplay = getDisplayValues();

  // Planned "Budgeted" Derived Calculations (Simplified annual to daily/hourly/monthly)
  const budgetedAnnualIncome = (filteredState.incomes || []).reduce((acc, inc) => acc + (inc.amount * ANNUAL_MULTIPLIERS[inc.periodicity]), 0);
  const budgetedAnnualExpense = (filteredState.budgets || []).reduce((acc, bud) => acc + (bud.amount), 0);

  const getBudgetedDisplayValues = () => {
    const dailyBIncome = budgetedAnnualIncome / 365;
    const dailyBExpense = budgetedAnnualExpense / 365;
    const dailyBSavings = dailyBIncome - dailyBExpense;

    switch (displayMode) {
      case 'monthly':
        return {
          income: budgetedAnnualIncome / 12,
          expense: budgetedAnnualExpense / 12,
          savings: (budgetedAnnualIncome - budgetedAnnualExpense) / 12
        };
      case 'daily':
        return {
          income: dailyBIncome,
          expense: dailyBExpense,
          savings: dailyBSavings
        };
      case 'hourly':
      default:
        return {
          income: dailyBIncome / hoursPerDay,
          expense: dailyBExpense / hoursPerDay,
          savings: dailyBSavings / hoursPerDay
        };
    }
  };

  const budgetedDisplay = getBudgetedDisplayValues();

  const getLabel = (baseLabel: string) => {
    if (isConsolidated) return baseLabel;
    const suffix = displayMode === 'monthly' ? 'Month' : (displayMode === 'daily' ? 'Day' : 'HR');
    const prefix = baseLabel === 'Income' ? 'Earnings' : (baseLabel === 'Spend' ? 'Burn' : 'Savings');
    return `${prefix}/${suffix}`;
  };

  const isSavingsPositive = currentDisplay.savings >= 0;

  const stats = [
    { 
      label: getLabel('Income'), 
      value: formatCurrency(currentDisplay.income, currency), 
      budgetedValue: formatCurrency(budgetedDisplay.income, currency),
      color: 'text-indigo-600', 
      bg: 'bg-white',
      border: 'border-slate-200',
      cycle: currentDisplay.cycle,
      type: 'income'
    },
    { 
      label: getLabel('Spend'), 
      value: formatCurrency(currentDisplay.expense, currency), 
      budgetedValue: formatCurrency(budgetedDisplay.expense, currency),
      color: 'text-rose-600', 
      bg: 'bg-white',
      border: 'border-slate-200',
      cycle: currentDisplay.cycle,
      type: 'expense'
    },
    { 
      label: getLabel('Savings'), 
      value: formatCurrency(currentDisplay.savings, currency), 
      budgetedValue: formatCurrency(budgetedDisplay.savings, currency),
      color: 'text-white', 
      bg: isSavingsPositive ? 'bg-emerald-500' : 'bg-rose-500',
      border: isSavingsPositive ? 'border-emerald-500' : 'border-rose-500',
      cycle: currentDisplay.cycle,
      type: 'savings'
    },
    { 
      label: 'Assets', 
      value: formatCurrency(netWorthData.assets, currency), 
      color: 'text-slate-800', 
      bg: 'bg-white',
      border: 'border-slate-200',
      cycle: '' 
    },
    { 
      label: 'Net Worth', 
      value: formatCurrency(netWorthData.netWorth, currency), 
      color: 'text-white', 
      bg: 'bg-indigo-600',
      border: 'border-indigo-600',
      cycle: '' 
    },
  ];

  const pieData = [
    { name: 'Assets', value: netWorthData.assets, color: '#4f46e5' },
    { name: 'Liabilities', value: netWorthData.liabilities, color: '#cbd5e1' },
  ];

  return (
    <div className="space-y-6 md:space-y-10 animate-in fade-in duration-500 max-w-full">
      {/* Rate Metric Controls - Fixed layout for better mobile visibility */}
      <div className="flex flex-col sm:flex-row items-center justify-between gap-4 bg-white/50 p-3 rounded-[2rem] border border-slate-200 shadow-sm backdrop-blur-sm">
        <div className="flex items-center gap-1 p-1 bg-slate-100/50 rounded-2xl w-full sm:w-auto overflow-x-auto no-scrollbar">
          <button 
            onClick={() => setDisplayMode('hourly')}
            className={`flex-1 sm:flex-none px-4 md:px-6 py-2 rounded-xl text-[9px] md:text-[10px] font-black uppercase tracking-widest transition-all whitespace-nowrap ${displayMode === 'hourly' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-400 hover:text-slate-600'}`}
          >
            Hourly
          </button>
          <button 
            onClick={() => setDisplayMode('daily')}
            className={`flex-1 sm:flex-none px-4 md:px-6 py-2 rounded-xl text-[9px] md:text-[10px] font-black uppercase tracking-widest transition-all whitespace-nowrap ${displayMode === 'daily' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-400 hover:text-slate-600'}`}
          >
            Daily
          </button>
          <button 
            onClick={() => setDisplayMode('monthly')}
            className={`flex-1 sm:flex-none px-4 md:px-6 py-2 rounded-xl text-[9px] md:text-[10px] font-black uppercase tracking-widest transition-all whitespace-nowrap ${displayMode === 'monthly' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-400 hover:text-slate-600'}`}
          >
            Monthly
          </button>
        </div>

        <div className={`flex items-center gap-3 px-2 w-full sm:w-auto justify-center sm:justify-end transition-opacity duration-300 ${displayMode === 'hourly' ? 'opacity-100' : 'opacity-30 pointer-events-none'}`}>
          <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest whitespace-nowrap">Cycle Base</label>
          <select 
            value={hoursPerDay} 
            onChange={(e) => setHoursPerDay(Number(e.target.value))}
            disabled={displayMode !== 'hourly'}
            className="bg-white border border-slate-200 rounded-xl px-2 py-2 text-[9px] font-black outline-none focus:ring-4 focus:ring-indigo-500/10 disabled:opacity-30 cursor-pointer min-w-[100px]"
          >
            {[4, 6, 8, 10, 12, 16, 20, 24].map(h => (
              <option key={h} value={h}>{h} HR / Day</option>
            ))}
          </select>
        </div>
      </div>

      {/* Dynamic Grid - Removed flex overflow, now wraps to ensure visibility */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-5 gap-4 md:gap-6">
        {stats.map((stat, i) => {
          const isDark = stat.bg !== 'bg-white';
          return (
            <div key={i} className={`p-5 md:p-6 lg:p-8 rounded-[2rem] border transition-all shadow-sm flex flex-col justify-between h-auto min-h-[14rem] md:min-h-[16rem] ${stat.bg} ${stat.border} hover:shadow-md ${isDark ? 'hover:border-white/20' : 'hover:border-indigo-100'} group`}>
              <p className={`text-[9px] font-black uppercase tracking-[0.2em] ${isDark ? 'text-white/60' : 'text-slate-400 group-hover:text-indigo-400'} transition-colors`}>{stat.label}</p>
              <div className="mt-4">
                 <div className="flex items-baseline flex-wrap gap-1">
                    <h3 className={`text-xl md:text-2xl xl:text-2xl font-black tracking-tight ${stat.color}`}>{stat.value}</h3>
                    {stat.cycle && <span className={`text-[9px] font-bold ${isDark ? 'text-white/60' : 'text-slate-400'}`}>/ {stat.cycle}</span>}
                 </div>

                 <div className="mt-4 flex flex-col gap-2">
                   <div className={`inline-flex items-center self-start px-2 py-1 rounded-full text-[8px] font-black uppercase tracking-widest ${isDark ? 'bg-white/20 text-white' : 'bg-slate-50 text-slate-500'}`}>
                     Live Impact
                   </div>

                   {stat.budgetedValue && (
                     <div className={`p-2 md:p-3 rounded-2xl border ${isDark ? 'bg-white/5 border-white/10' : 'bg-slate-50 border-slate-100'}`}>
                       <p className={`text-[7px] font-black uppercase tracking-widest ${isDark ? 'text-white/40' : 'text-slate-400'}`}>
                         Budgeted {stat.type === 'income' ? 'Earnings' : stat.type === 'expense' ? 'Burn' : 'Savings'}
                       </p>
                       <p className={`text-[10px] font-black mt-0.5 ${isDark ? 'text-white' : 'text-slate-600'}`}>
                         {stat.budgetedValue} <span className="text-[7px] opacity-60">/ {stat.cycle}</span>
                       </p>
                     </div>
                   )}
                 </div>
              </div>
            </div>
          );
        })}
      </div>

      {/* Main Charts Area */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 md:gap-8">
        <div className="lg:col-span-2 bg-white p-6 md:p-10 rounded-[2.5rem] border border-slate-200 shadow-sm relative overflow-hidden">
           <div className="flex justify-between items-center mb-6 md:mb-10">
             <h4 className="text-[10px] md:text-xs font-black text-slate-800 uppercase tracking-widest">Wealth Composition</h4>
             <span className="text-[8px] md:text-[9px] font-black bg-indigo-50 text-indigo-600 px-3 py-1 rounded-full uppercase tracking-widest border border-indigo-100">Audit Ready</span>
           </div>

           <div className="grid grid-cols-1 md:grid-cols-2 gap-6 lg:gap-12 items-center">
              <div className="h-60 md:h-72 lg:h-80 relative">
                <ResponsiveContainer width="100%" height="100%">
                  <PieChart>
                    <Pie data={pieData} cx="50%" cy="50%" innerRadius="65%" outerRadius="85%" paddingAngle={4} dataKey="value" stroke="none">
                      {pieData.map((entry, index) => <Cell key={`cell-${index}`} fill={entry.color} />)}
                    </Pie>
                    <Tooltip contentStyle={{ borderRadius: '20px', border: 'none', boxShadow: '0 20px 25px -5px rgb(0 0 0 / 0.1)', padding: '12px' }} />
                  </PieChart>
                </ResponsiveContainer>
                <div className="absolute top-[50%] left-[50%] -translate-x-1/2 -translate-y-1/2 text-center pointer-events-none">
                   <p className="text-[8px] md:text-[9px] font-black text-slate-400 uppercase tracking-widest">Equity</p>
                   <p className="text-lg md:text-2xl font-black text-slate-800 tracking-tight leading-none mt-1">{formatCurrency(netWorthData.netWorth, currency)}</p>
                </div>
              </div>

              <div className="space-y-4 md:space-y-6">
                <div className="p-4 md:p-6 bg-slate-50 border border-slate-100 rounded-[2rem]">
                  <div className="flex justify-between items-center mb-1">
                    <span className="text-[9px] md:text-[10px] font-black text-slate-400 uppercase tracking-widest">Assets</span>
                    <span className="text-base md:text-lg font-black text-indigo-600">{formatCurrency(netWorthData.assets, currency)}</span>
                  </div>
                  <div className="w-full h-1.5 bg-slate-200 rounded-full overflow-hidden mt-3">
                    <div className="bg-indigo-600 h-full w-full transition-all duration-1000"></div>
                  </div>
                </div>

                <div className="p-4 md:p-6 bg-slate-50 border border-slate-100 rounded-[2rem]">
                  <div className="flex justify-between items-center mb-1">
                    <span className="text-[9px] md:text-[10px] font-black text-slate-400 uppercase tracking-widest">Liabilities</span>
                    <span className="text-base md:text-lg font-black text-slate-600">{formatCurrency(netWorthData.liabilities, currency)}</span>
                  </div>
                  <div className="w-full h-1.5 bg-slate-200 rounded-full overflow-hidden mt-3">
                    <div className="bg-rose-400 h-full transition-all duration-1000" style={{ width: `${Math.min(100, (netWorthData.liabilities / Math.max(1, netWorthData.assets)) * 100)}%` }}></div>
