            </div>

            <button onClick={() => setShowNotifications(!showNotifications)} className="relative w-10 h-10 bg-slate-100 rounded-2xl text-slate-600 flex items-center justify-center border border-slate-200 transition-all">
               <span className="text-xl">🔔</span>
               {pendingApprovals.length > 0 && <span className="absolute top-2 right-2 bg-rose-500 w-2.5 h-2.5 rounded-full border-2 border-white"></span>}
            </button>
          </div>
        </header>

        <div className="flex-1 p-4 md:p-12 pb-20">{children}</div>

        {showNotifications && pendingApprovals.length > 0 && (
          <div className="fixed top-24 right-4 w-80 bg-white border border-slate-200 rounded-[2.5rem] shadow-2xl z-50 p-6 animate-in slide-in-from-right-10 flex flex-col max-h-[70vh]">
            <div className="flex justify-between items-center mb-6">
               <h4 className="text-[10px] font-black text-slate-800 uppercase tracking-widest">Action Required</h4>
               {pendingApprovals.filter(n => n.type === 'approval_request').length > 1 && (
                 <button 
                   onClick={() => { setShowBulkAudit(true); setShowNotifications(false); }}
                   className="text-[9px] font-black text-indigo-600 uppercase tracking-widest bg-indigo-50 px-2 py-1 rounded-lg"
                 >
                   Bulk Audit
                 </button>
               )}
            </div>

            <div className="space-y-4 overflow-y-auto custom-scrollbar flex-1 pr-1">
               {pendingApprovals.map(n => {
                 const isFamilyRequest = n.type === 'family_request';
                 return (
                   <div key={n.id} className={`p-4 rounded-2xl border ${isFamilyRequest ? 'bg-indigo-50 border-indigo-200 shadow-sm' : 'bg-slate-50 border-slate-100'}`}>
                      {isFamilyRequest && <span className="inline-block bg-indigo-600 text-white text-[7px] font-black px-2 py-0.5 rounded-full uppercase tracking-widest mb-2">Priority Request</span>}
                      <p className="text-[10px] font-black text-slate-800 uppercase leading-tight">{n.title}</p>
                      <p className="text-[9px] text-slate-500 font-medium mt-1">{n.message}</p>
                      <div className="flex gap-2 mt-4">
                         {isFamilyRequest ? (
                           <>
                              <button onClick={() => handleFamilyRequest(n.id, true)} className="flex-1 py-2 bg-indigo-600 text-white text-[8px] font-black uppercase rounded-lg shadow-lg shadow-indigo-200">Verify & Link</button>
                              <button onClick={() => handleFamilyRequest(n.id, false)} className="flex-1 py-2 bg-white text-slate-400 border border-slate-200 text-[8px] font-black uppercase rounded-lg">Ignore</button>
                           </>
                         ) : (
                           <>
                              <button onClick={() => approveTransaction(n.transactionId!)} className="flex-1 py-2 bg-emerald-600 text-white text-[8px] font-black uppercase rounded-lg">Approve</button>
                              <button onClick={() => rejectTransaction(n.transactionId!)} className="flex-1 py-2 bg-rose-50 text-rose-500 text-[8px] font-black uppercase rounded-lg">Reject</button>
                           </>
                         )}
                      </div>
                   </div>
                 );
               })}
            </div>
          </div>
        )}

        {showBulkAudit && <BulkAuditModal onClose={() => setShowBulkAudit(false)} />}
      </main>
    </div>
  );
};

