  id: string;
  name: string;
  icon: string;
  isEnabled: boolean;
  category: 'Banking' | 'UPI' | 'Investment' | 'Wallet';
}

export interface MemberPermissions {
  viewDashboard: boolean;
  viewStatements: boolean;
  viewBudget: boolean;
  viewTransactions: boolean;
  viewCalendar: boolean;
  viewAccounts: boolean;
  canCreateTransactions: boolean;
}

export interface FamilyMember {
  id: string;
  name: string;
  relation: string;
  mobileNumber: string;
  status: 'pending_invitation' | 'verified';
  permissions: MemberPermissions;
}

export interface GoogleDriveConfig {
  folderName: string;
  folderId: string;
  isConnected: boolean;
  linkedEmail?: string;
}

export interface UserProfile {
  name: string;
  designation: string;
  age: number;
  city: string;
  country: string;
  currency: string;
  mobileNumber?: string;
  isBoarded: boolean;
  familyMembers: FamilyMember[];
  cloudDatabaseName?: string;
  monitoredApps: MonitoredApp[];
  remindersEnabled: boolean;
  googleDriveConfig?: GoogleDriveConfig;
}

export interface Notification {
  id: string;
  title: string;
  message: string;
  timestamp: string;
  type: 'transaction' | 'system' | 'sync' | 'reminder' | 'approval_request' | 'family_request';
  isRead: boolean;
  transactionId?: string;
  requestData?: {
    name: string;
    mobile: string;
    relation: string;
  };
}

export interface BankAccount {
  id: string;
  name: string;
  accountNumber?: string;
  balance: number;
  ownerId?: string;
  accountType?: 'Savings' | 'Current' | 'Salary' | 'Others';
  customAccountType?: string;
  classification?: AccountClassification;
}

export interface CreditCardOtherBenefit {
  condition: string;
  benefitName: string;
  linkedNatures: string[];
}

export interface CreditCard {
  id: string;
  lenderName: string;
  balance: number;
  last4: string;
  limit?: number;
  annualLimit?: number; 
  anniversaryDate?: string;
  billingDay?: number;
  dueDate?: string;
  offers: {
    movie: boolean;
    dining: boolean;
    concierge: boolean;
    lounge: boolean;
  };
  ownerId?: string;
  classification?: AccountClassification;
  cashbackPct?: number;
  movieOffers?: {
    onePlusOne: boolean;
    amountBased: number;
  };
  loungeAccess?: {
    count: number;
    spendLimit: number;
    period: string;
  };
  fuelSurchargeWaiver?: boolean;
  forexMarkup?: number;
  pointsConversion?: string;
  otherBenefits?: CreditCardOtherBenefit[];
}

export interface Wallet {
  id: string;
  name: string;
  balance: number;
  ownerId?: string;
  classification?: AccountClassification;
}

export interface IncomeStream {
  id: string;
  name: string;
  amount: number;
  periodicity: Periodicity;
  dateOfReceipt: string;
  ownerId?: string;
}

export interface Expense {
  id: string;
  category: string;
  amount: number;
  periodicity: Periodicity;
  date: string;
  ownerId?: string;
}

export interface Asset {
  id: string;
  name: string;
  value: number;
  type?: 'Physical' | 'Receivable';
  ownerId?: string;
  classification?: AccountClassification;
  isin?: string;
  units?: number;
}

export interface Liability {
  id: string;
  name: string;
  amount: number;
  type?: 'Debt' | 'Payable';
  ownerId?: string;
  classification?: AccountClassification;
}

export type TransactionType = 'Income' | 'Expense' | 'Asset' | 'Liability';

export interface SharedContact {
  name: string;
  mobile: string;
  amount: number;
}

export interface TransactionAttachment {
  id: string;
  name: string;
  url: string;
  mimeType: string;
  uploadDate: string;
}

export interface Transaction {
  id: string;
  type: TransactionType;
  amount: number;
  nature: string; 
  description: string;
  accountId: string;
  accountType: 'bank' | 'card' | 'wallet' | 'liability';
  date: string;
  category?: string;
  status: 'active' | 'pending_approval';
  createdBy?: string; 
  isShared?: boolean;
  sharedAmount?: number;
  numberOfPeople?: number;
  includeSelf?: boolean;
  sharedContacts?: SharedContact[];
  ownerId?: string; 
  isin?: string;
  stockName?: string;
  units?: number; 
  stt?: number; 
  brokerage?: number; 
  billingPeriod?: string; 
  isSettled?: boolean;
  estimatedLife?: number;
  attachments?: TransactionAttachment[];
}

export interface HoldingItem {
  isin: string;
  name: string;
  value: number;
  units: number;
  count: number;
}

export interface Budget {
  id: string;
  category: string;
  amount: number;
  frequency: Periodicity;
  startDate: string;
  endDate: string;
  dueDate?: string;
  periodType: 'Financial' | 'Calendar' | 'Custom';
  ownerId?: string;
}

export interface FinancialState {
  profile: UserProfile;
  banks: BankAccount[];
  cards: CreditCard[];
  wallets: Wallet[];
  incomes: IncomeStream[];
  expenses: Expense[];
  assets: Asset[];
  liabilities: Liability[];
  transactions: Transaction[];
  budgets: Budget[]; 
  notifications: Notification[];
  transactionNatures: string[]; 
  capital: number; 
}

import React, { createContext, useContext, useState, useEffect, ReactNode, useMemo } from 'react';
import { FinancialState, UserProfile, BankAccount, CreditCard, Wallet, IncomeStream, Expense, Asset, Liability, Transaction, FamilyMember, Notification, Budget, MonitoredApp, MemberPermissions, TransactionAttachment } from '../types';
import { supabase } from '../lib/supabase';

interface FinanceContextType {
  state: FinancialState;
  filteredState: FinancialState;
  isAuthenticated: boolean;
  activeMemberIds: string[];
  isCloudSyncing: boolean;
  setActiveMemberIds: (ids: string[]) => void;
  setAuthenticated: (value: boolean) => void;
  updateProfile: (profile: UserProfile) => void;
  addFamilyMember: (member: FamilyMember) => Promise<{ success: boolean; syncedCount: number; error?: string }>;
  removeFamilyMember: (id: string) => void;
  updateMemberPermissions: (id: string, permissions: MemberPermissions) => void;
  verifyFamilyMember: (id: string) => void;
  approveTransaction: (id: string) => void;
  approveTransactions: (ids: string[]) => void;
  rejectTransaction: (id: string) => void;
  rejectTransactions: (ids: string[]) => void;
  addBank: (bank: BankAccount) => void;
  updateBank: (bank: BankAccount) => void;
  deleteBank: (id: string) => void;
  addCard: (card: CreditCard) => void;
  updateCard: (card: CreditCard) => void;
  deleteCard: (id: string) => void;
  addWallet: (wallet: Wallet) => void;
  updateWallet: (wallet: Wallet) => void;
  deleteWallet: (id: string) => void;
  addIncome: (income: IncomeStream) => void;
  addExpense: (expense: Expense) => void;
  addAsset: (asset: Asset) => void;
  updateAsset: (asset: Asset) => void;
  deleteAsset: (id: string) => void;
  addLiability: (liability: Liability) => void;
  updateLiability: (liability: Liability) => void;
  deleteLiability: (id: string) => void;
  addTransaction: (transaction: Transaction) => void;
  updateTransaction: (transaction: Transaction) => void;
  deleteTransaction: (id: string) => void;
  addBudget: (budget: Budget) => void;
  updateBudget: (budget: Budget) => void;
  deleteBudget: (id: string) => void;
  addTransactionNature: (nature: string) => void;
  deleteTransactionNature: (nature: string) => void;
  clearNotifications: () => void;
  markNotificationRead: (id: string) => void;
  simulateSync: () => Promise<void>;
  resetBoarding: () => Promise<void>;
  loadStateFromCloud: (mobile: string) => Promise<boolean>;
  importState: (newState: FinancialState) => void;
  updateMonitoredApps: (apps: MonitoredApp[]) => void;
  simulateIncomingRequest: (name: string, mobile: string, relation: string) => void;
  handleFamilyRequest: (notificationId: string, accepted: boolean) => void;
  uploadToDrive: (file: File) => Promise<TransactionAttachment>;
}

const GLOBAL_SESSION_KEY = 'myfin_active_session';
const STATE_PREFIX = 'myfin_state_';

const DEFAULT_PERMISSIONS: MemberPermissions = {
  viewDashboard: true,
  viewStatements: true,
  viewBudget: true,
  viewTransactions: true,
  viewCalendar: true,
  viewAccounts: true,
  canCreateTransactions: true
};

const initialState: FinancialState = {
  profile: { 
    name: '', designation: '', age: 0, city: '', country: 'India', currency: 'INR', mobileNumber: '',
    isBoarded: false, familyMembers: [], cloudDatabaseName: 'Default_Vault', monitoredApps: [], remindersEnabled: false,
    googleDriveConfig: { folderId: '', folderName: '', isConnected: false, linkedEmail: '' }
  },
  banks: [{ id: 'def-bank-1', name: 'Primary Savings Bank', balance: 0, accountType: 'Savings', classification: 'Current Asset' }],
  cards: [{ id: 'def-card-1', lenderName: 'Main Credit Card', balance: 0, last4: '0000', billingDay: 1, dueDate: '2024-01-15', offers: { movie: true, dining: true, concierge: false, lounge: true }, classification: 'Current Liability' }],
  wallets: [{ id: 'def-wallet-1', name: 'Cash', balance: 0, classification: 'Current Asset' }],
  incomes: [], expenses: [], assets: [], liabilities: [], transactions: [], budgets: [], notifications: [], transactionNatures: ['Salary', 'Rent', 'Food', 'Investment'], capital: 0
};

const FinanceContext = createContext<FinanceContextType | undefined>(undefined);

export const useFinance = () => {
  const context = useContext(FinanceContext);
  if (!context) throw new Error('useFinance must be used within a FinanceProvider');
  return context;
};

export const FinanceProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [isAuthenticated, setAuthenticated] = useState(false);
  const [activeMemberIds, setActiveMemberIds] = useState<string[]>([]);
  const [isCloudSyncing, setIsCloudSyncing] = useState(false);
  const [state, setState] = useState<FinancialState>(() => {
    const mobile = localStorage.getItem(GLOBAL_SESSION_KEY);
    if (mobile) {
      const saved = localStorage.getItem(`${STATE_PREFIX}${mobile}`);
      if (saved) return { ...initialState, ...JSON.parse(saved) };
    }
    return initialState;
  });

  // Auto-authenticate if valid session exists
  useEffect(() => {
    const activeSession = localStorage.getItem(GLOBAL_SESSION_KEY);
    if (activeSession && state.profile.isBoarded && state.profile.mobileNumber === activeSession) {
      setAuthenticated(true);
    }
  }, []);

  // Persist state to local storage and sync to Supabase
  useEffect(() => {
    if (state.profile.mobileNumber && state.profile.isBoarded) {
      // Immediate Local Storage Save
      localStorage.setItem(GLOBAL_SESSION_KEY, state.profile.mobileNumber);
      localStorage.setItem(`${STATE_PREFIX}${state.profile.mobileNumber}`, JSON.stringify(state));

      // Debounced Cloud Sync
      const syncToCloud = async () => {
        setIsCloudSyncing(true);
        try {
          const { error } = await supabase.from('user_states').upsert({
            mobile_number: state.profile.mobileNumber,
            state: state,
            updated_at: new Date().toISOString()
          }, { onConflict: 'mobile_number' });

          if (error) {
            console.error('Supabase Sync Error:', error.message);
          }
        } catch (err) {
          console.error('Cloud Sync Exception:', err);
        } finally {
          setIsCloudSyncing(false);
        }
      };

      const timer = setTimeout(syncToCloud, 2000);
      return () => clearTimeout(timer);
    }
  }, [state]);

  const loadStateFromCloud = async (mobile: string): Promise<boolean> => {
    setIsCloudSyncing(true);
    try {
      const { data, error } = await supabase
        .from('user_states')
        .select('state')
        .eq('mobile_number', mobile)
        .single();

      if (error && error.code !== 'PGRST116') { // PGRST116 is Row not found
         console.error('Error fetching cloud state:', error);
         return false;
      }

      if (data && data.state) {
        setState(prev => ({ ...initialState, ...data.state }));
        return true;
      }
      return false;
    } catch (err) {
      console.error('Load state exception:', err);
      return false;
    } finally {
      setIsCloudSyncing(false);
    }
  };

  const simulateSync = async () => {
    if (state.profile.mobileNumber) {
      await loadStateFromCloud(state.profile.mobileNumber);
    }
  };

  const resetBoarding = async () => {
    try {
      if (state.profile.mobileNumber) {
        localStorage.removeItem(`${STATE_PREFIX}${state.profile.mobileNumber}`);
      }
      localStorage.removeItem(GLOBAL_SESSION_KEY);
      setAuthenticated(false);
      setState(initialState);
      setActiveMemberIds([]);
    } catch (e) {
      console.error("Logout error", e);
      setAuthenticated(false);
      setState(initialState);
    }
  };

  const uploadToDrive = async (file: File): Promise<TransactionAttachment> => {
    // This is a simulation since we can't do real OAuth in this environment.
    // In a real app, this would use the Google Drive API to upload the file to `state.profile.googleDriveConfig.folderId`.

    return new Promise((resolve) => {
      setTimeout(() => {
        resolve({
          id: `file_${Math.random().toString(36).substr(2, 9)}`,
          name: file.name,
          url: '#', // In real app, this would be webViewLink
          mimeType: file.type,
          uploadDate: new Date().toISOString()
        });
      }, 1500); // Simulate upload delay
    });
  };

  const applyTransactionEffect = (transaction: Transaction, newState: FinancialState, isReversing: boolean) => {
    if (transaction.status === 'pending_approval') return; 

    const factor = isReversing ? -1 : 1;
    const totalAmount = transaction.amount || 0;
    const balanceDelta = (transaction.type === 'Income' || transaction.type === 'Liability') ? totalAmount : -totalAmount;
    const finalBalanceDelta = balanceDelta * factor;

    if (transaction.accountType === 'bank') {
      newState.banks = newState.banks.map(b => b.id === transaction.accountId ? { ...b, balance: b.balance + finalBalanceDelta } : b);
    } else if (transaction.accountType === 'card') {
      const cardDelta = (transaction.type === 'Income' || transaction.type === 'Liability' ? -totalAmount : totalAmount) * factor;
      newState.cards = newState.cards.map(c => c.id === transaction.accountId ? { ...c, balance: c.balance + cardDelta } : c);
    } else if (transaction.accountType === 'wallet') {
      newState.wallets = newState.wallets.map(w => w.id === transaction.accountId ? { ...w, balance: w.balance + finalBalanceDelta } : w);
    } else if (transaction.accountType === 'liability') {
      const liabilityDelta = (transaction.type === 'Income' || transaction.type === 'Liability' ? -totalAmount : totalAmount) * factor;
      newState.liabilities = newState.liabilities.map(l => l.id === transaction.accountId ? { ...l, amount: l.amount + liabilityDelta } : l);
    }
  };

  const addTransaction = (transaction: Transaction) => {
    setState(prev => {
      const isForSelf = !transaction.ownerId || transaction.ownerId === '';
      const finalStatus: 'active' | 'pending_approval' = isForSelf ? 'active' : 'pending_approval';
      const creatorName = prev.profile.name || 'System'; 
      const txWithStatus: Transaction = { ...transaction, status: finalStatus, createdBy: creatorName };
      const newState = { ...prev, transactions: [txWithStatus, ...prev.transactions] };
      applyTransactionEffect(txWithStatus, newState, false);

      if (finalStatus === 'pending_approval') {
        const ownerName = prev.profile.familyMembers.find(m => m.id === transaction.ownerId)?.name || 'Member';
        newState.notifications = [{
          id: `approval_${txWithStatus.id}`,
          title: 'Pending Audit Sign-off',
          message: `A transaction of ${txWithStatus.amount} for ${ownerName} requires their verification.`,
          timestamp: new Date().toLocaleTimeString(),
          type: 'approval_request',
          isRead: false,
          transactionId: txWithStatus.id
        }, ...newState.notifications];
      }
      return newState;
    });
  };

  const approveTransaction = (id: string) => {
    setState(prev => {
      const tx = prev.transactions.find(t => t.id === id);
      if (!tx) return prev;
      const updatedTx = { ...tx, status: 'active' as const };
      const newState = { ...prev, transactions: prev.transactions.map(t => t.id === id ? updatedTx : t) };
      applyTransactionEffect(updatedTx, newState, false);
      newState.notifications = prev.notifications.filter(n => n.transactionId !== id);
      return newState;
    });
  };

  const approveTransactions = (ids: string[]) => {
    setState(prev => {
      let newState = { ...prev };
      const pendingTxs = prev.transactions.filter(t => ids.includes(t.id) && t.status === 'pending_approval');
      if (pendingTxs.length === 0) return prev;
      newState.transactions = prev.transactions.map(t => {
        if (ids.includes(t.id) && t.status === 'pending_approval') return { ...t, status: 'active' as const };
        return t;
      });
      pendingTxs.forEach(tx => {
         applyTransactionEffect({ ...tx, status: 'active' }, newState, false);
      });
      newState.notifications = prev.notifications.filter(n => !n.transactionId || !ids.includes(n.transactionId));
      return newState;
    });
  };

  const rejectTransaction = (id: string) => {
    setState(prev => ({
      ...prev,
      transactions: prev.transactions.filter(t => t.id !== id),
      notifications: prev.notifications.filter(n => n.transactionId !== id)
    }));
  };

  const rejectTransactions = (ids: string[]) => {
    setState(prev => ({
      ...prev,
      transactions: prev.transactions.filter(t => !ids.includes(t.id)),
      notifications: prev.notifications.filter(n => !n.transactionId || !ids.includes(n.transactionId))
    }));
  };

  const addFamilyMember = async (member: FamilyMember) => {
    setState(prev => ({ ...prev, profile: { ...prev.profile, familyMembers: [...prev.profile.familyMembers, { ...member, permissions: DEFAULT_PERMISSIONS, status: 'pending_invitation' }] } }));
    return { success: true, syncedCount: 0 };
  };

  const verifyFamilyMember = (id: string) => {
    setState(prev => ({
      ...prev,
      profile: {
        ...prev.profile,
        familyMembers: prev.profile.familyMembers.map(m => m.id === id ? { ...m, status: 'verified' as const } : m)
      }
    }));
  };

  const updateMemberPermissions = (id: string, permissions: MemberPermissions) => {
    setState(prev => ({
      ...prev,
      profile: {
        ...prev.profile,
        familyMembers: prev.profile.familyMembers.map(m => m.id === id ? { ...m, permissions } : m)
      }
    }));
  };

  const simulateIncomingRequest = (name: string, mobile: string, relation: string) => {
    const newNotif: Notification = {
      id: `req_${Date.now()}`,
      title: 'Priority: Family Link Request',
      message: `${name} (${relation}) is requesting to link vaults with you. Accept to grant access based on their settings.`,
      timestamp: new Date().toLocaleTimeString(),
      type: 'family_request',
      isRead: false,
      requestData: { name, mobile, relation }
    };
    setState(prev => ({ ...prev, notifications: [newNotif, ...prev.notifications] }));
  };

  const handleFamilyRequest = (notificationId: string, accepted: boolean) => {
    setState(prev => {
      let newState = { ...prev };
      const notif = prev.notifications.find(n => n.id === notificationId);

      // Remove the notification regardless of acceptance
      newState.notifications = prev.notifications.filter(n => n.id !== notificationId);

      if (accepted && notif && notif.requestData) {
        // Link the family member
        const newMember: FamilyMember = {
          id: `mem_${Date.now()}`,
          name: notif.requestData.name,
          mobileNumber: notif.requestData.mobile,
          relation: notif.requestData.relation,
          status: 'verified',
          permissions: DEFAULT_PERMISSIONS
        };

        // Check for duplicates before adding
        if (!prev.profile.familyMembers.some(m => m.mobileNumber === newMember.mobileNumber)) {
          newState.profile.familyMembers = [...prev.profile.familyMembers, newMember];
        } else {
           // If exists but was pending, verify it
           newState.profile.familyMembers = prev.profile.familyMembers.map(m => 
             m.mobileNumber === newMember.mobileNumber ? { ...m, status: 'verified' } : m
           );
        }
      }
      return newState;
    });
  };

  const filteredState = useMemo(() => {
    if (activeMemberIds.includes('all')) return state;
    const filterIds = activeMemberIds.length > 0 ? activeMemberIds : [undefined, ''];
    const filterFn = (item: any) => filterIds.includes(item.ownerId || '');
    return {
      ...state,
      banks: state.banks.filter(filterFn),
      cards: state.cards.filter(filterFn),
      wallets: state.wallets.filter(filterFn),
      transactions: state.transactions.filter(filterFn),
    };
  }, [state, activeMemberIds]);

  return (
    <FinanceContext.Provider value={{ 
      state, filteredState, isAuthenticated, activeMemberIds, isCloudSyncing, setActiveMemberIds, setAuthenticated, updateProfile: (p) => setState(prev => ({...prev, profile: {...p, isBoarded: true}})), 
      addFamilyMember, removeFamilyMember: (id) => setState(prev => ({...prev, profile: {...prev.profile, familyMembers: prev.profile.familyMembers.filter(m => m.id !== id)}})), 
      updateMemberPermissions, verifyFamilyMember, approveTransaction, approveTransactions, rejectTransaction, rejectTransactions,
      addBank: (b) => setState(prev => ({...prev, banks: [...prev.banks, b]})), updateBank: (b) => setState(prev => ({...prev, banks: prev.banks.map(x => x.id === b.id ? b : x)})), deleteBank: (id) => setState(prev => ({...prev, banks: prev.banks.filter(b => b.id !== id)})),
      addCard: (c) => setState(prev => ({...prev, cards: [...prev.cards, c]})), updateCard: (c) => setState(prev => ({...prev, cards: prev.cards.map(x => x.id === c.id ? c : x)})), deleteCard: (id) => setState(prev => ({...prev, cards: prev.cards.filter(c => c.id !== id)})),
      addWallet: (w) => setState(prev => ({...prev, wallets: [...prev.wallets, w]})), updateWallet: (w) => setState(prev => ({...prev, wallets: prev.wallets.map(x => x.id === w.id ? w : x)})), deleteWallet: (id) => setState(prev => ({...prev, wallets: prev.wallets.filter(w => w.id !== id)})),
      addIncome: () => {}, addExpense: () => {}, addAsset: (a) => setState(prev => ({...prev, assets: [...prev.assets, a]})), updateAsset: (a) => setState(prev => ({...prev, assets: prev.assets.map(x => x.id === a.id ? a : x)})), deleteAsset: (id) => setState(prev => ({...prev, assets: prev.assets.filter(a => a.id !== id)})),
      addLiability: (l) => setState(prev => ({...prev, liabilities: [...prev.liabilities, l]})), updateLiability: (l) => setState(prev => ({...prev, liabilities: prev.liabilities.map(x => x.id === l.id ? l : x)})), deleteLiability: (id) => setState(prev => ({...prev, liabilities: prev.liabilities.filter(l => l.id !== id)})),
      addTransaction, updateTransaction: () => {}, deleteTransaction: (id) => setState(prev => ({...prev, transactions: prev.transactions.filter(t => t.id !== id)})),
      addBudget: (b) => setState(prev => ({...prev, budgets: [...prev.budgets, b]})), updateBudget: (b) => setState(prev => ({...prev, budgets: prev.budgets.map(x => x.id === b.id ? b : x)})), deleteBudget: (id) => setState(prev => ({...prev, budgets: prev.budgets.filter(b => b.id !== id)})),
      addTransactionNature: () => {}, deleteTransactionNature: () => {}, clearNotifications: () => {}, markNotificationRead: () => {}, 
      simulateSync, 
      resetBoarding, 
      loadStateFromCloud, 
      importState: () => {}, 
      updateMonitoredApps: () => {},
      simulateIncomingRequest,
      handleFamilyRequest,
      uploadToDrive
    }}>
      {children}
    </FinanceContext.Provider>
  );
};

import React, { useState, useRef } from 'react';
import { useFinance } from '../store/FinanceContext';
import { MonitoredApp, MemberPermissions } from '../types';

const Profile: React.FC = () => {
  const { state, updateProfile, addFamilyMember, removeFamilyMember, updateMemberPermissions, verifyFamilyMember, importState, resetBoarding, updateMonitoredApps, simulateIncomingRequest } = useFinance();
  const profile = state.profile;
  const [showAddMember, setShowAddMember] = useState(false);
  const [showPermissions, setShowPermissions] = useState<string | null>(null);
  const [newMember, setNewMember] = useState({ name: '', relation: 'Spouse', mobile: '' });

  // Simulated Auth State
  const [isConnecting, setIsConnecting] = useState(false);
  const [showFolderSelection, setShowFolderSelection] = useState(false);

  // Mock Folders for Selection
  const MOCK_FOLDERS = [
    { id: 'folder_123', name: 'MyFin Vault' },
    { id: 'folder_456', name: 'Finance Documents' },
    { id: 'folder_789', name: 'Receipts & Invoices' }
  ];

  const handleAddMember = async (e: React.FormEvent) => {
    e.preventDefault();
    if (newMember.name && newMember.mobile) {
      await addFamilyMember({
        id: Math.random().toString(36).substr(2, 9),
        name: newMember.name,
        relation: newMember.relation,
        mobileNumber: newMember.mobile,
        status: 'pending_invitation',
        permissions: { viewDashboard: true, viewStatements: true, viewBudget: true, viewTransactions: true, viewCalendar: true, viewAccounts: true, canCreateTransactions: true }
      });
      setNewMember({ name: '', relation: 'Spouse', mobile: '' });
      setShowAddMember(false);
    }
  };

  const handleGoogleLogin = () => {
    setIsConnecting(true);
    // Simulate OAuth Delay
    setTimeout(() => {
      setIsConnecting(false);
      setShowFolderSelection(true);
    }, 2000);
  };

  const confirmFolderSelection = (folderId: string, folderName: string) => {
    updateProfile({
      ...profile,
      googleDriveConfig: {
        isConnected: true,
        linkedEmail: 'user.demo@gmail.com', // Mocked user email
        folderId: folderId,
        folderName: folderName
      }
    });
    setShowFolderSelection(false);
  };

  const handleDisconnect = () => {
    if (confirm('Disconnect Google Drive? Evidence syncing will stop immediately.')) {
      updateProfile({
        ...profile,
        googleDriveConfig: {
          isConnected: false,
          linkedEmail: '',
          folderId: '',
          folderName: ''
        }
      });
    }
  };

  const togglePermission = (id: string, key: keyof MemberPermissions) => {
    const member = profile.familyMembers.find(m => m.id === id);
    if (member) {
      updateMemberPermissions(id, { ...member.permissions, [key]: !member.permissions[key] });
    }
  };

  return (
    <div className="space-y-6 md:space-y-10 max-w-4xl animate-in fade-in duration-500 pb-20 px-3 md:px-0 mx-auto">
      <div className="bg-white md:rounded-[3rem] border border-slate-200 shadow-sm overflow-hidden">
        <div className="h-40 bg-indigo-600 p-8 flex items-end relative">
           <div className="absolute top-0 right-0 p-8 text-8xl font-black text-white/10 tracking-tighter uppercase">MF</div>
           <div className="w-24 h-24 bg-white p-1 translate-y-12 z-10 shadow-xl rounded-[2rem]">
               <div className="w-full h-full bg-slate-100 flex items-center justify-center text-4xl font-black text-indigo-600 rounded-2xl uppercase">{profile?.name?.charAt(0) || '?'}</div>
           </div>
        </div>
        <div className="px-8 pt-16 pb-10">
          <div className="flex justify-between items-start mb-8">
            <div>
              <h3 className="text-3xl font-black text-slate-800 tracking-tight uppercase">{profile?.name}</h3>
              <p className="text-xs font-black text-indigo-500 uppercase tracking-widest mt-1">{profile?.designation}</p>
            </div>
          </div>
          <div className="grid grid-cols-2 gap-4 p-6 bg-slate-50 border border-slate-100 rounded-[2rem]">
             <div><p className="text-[8px] font-black text-slate-400 uppercase tracking-widest mb-1">Local Identity</p><p className="text-xs font-black text-slate-800 uppercase">{profile?.city}, {profile?.country}</p></div>
             <div><p className="text-[8px] font-black text-slate-400 uppercase tracking-widest mb-1">Audit Currency</p><p className="text-xs font-black text-indigo-600 uppercase">{profile?.currency}</p></div>
          </div>
        </div>
      </div>

      {/* Google Drive Configuration Card (Updated Flow) */}
      <div className="bg-white p-8 rounded-[3rem] border border-slate-200 shadow-sm relative overflow-hidden group">
         <div className="absolute top-0 right-0 p-4 text-6xl opacity-5 font-black text-indigo-600">CLOUD</div>

         <div className="flex justify-between items-center mb-6 relative z-10">
