/// <reference types="vite/client" />

declare namespace NodeJS {
  interface ProcessEnv {
    API_KEY: string;
    [key: string]: string | undefined;
  }
}

import { GoogleGenAI, Type } from "@google/genai";
import React, { useEffect, useMemo, useRef, useState } from 'react';
import { useFinance } from '../store/FinanceContext';
import { Transaction, TransactionType, TransactionAttachment } from '../types';
import { formatCurrency } from '../utils/formatters';

type SplitType = 'equal' | 'exact' | 'percentage' | 'shares';

interface Participant {
  id: string; 
  name: string;
  mobile: string;
  value: string; 
  result: number; 
  isSelf: boolean;
}

interface ExtractedTrade {
  scrip: string;
  type: 'BUY' | 'SELL';
  grossValue: number;
  netTotal: number;
  units: number;
  date: string;
  isin: string;
  stt: number;
  allocatedCharges: number;
}

const Transactions: React.FC = () => {
  const { filteredState, state, addTransaction, updateTransaction, deleteTransaction, addTransactionNature, addWallet, approveTransaction, rejectTransaction, uploadToDrive } = useFinance();
  const familyMembers = (state.profile?.familyMembers || []).filter(m => m.status === 'verified');
  const natures = state.transactionNatures || [];
  const [showModal, setShowModal] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [confirmDeleteTx, setConfirmDeleteTx] = useState<Transaction | null>(null);
  const [isScanning, setIsScanning] = useState(false);
  const [pendingFiles, setPendingFiles] = useState<File[]>([]);
  const [isUploading, setIsUploading] = useState(false);
  const [importOwnerId, setImportOwnerId] = useState<string>('');
  const [importAccountId, setImportAccountId] = useState<string>('');
  const [viewingAttachments, setViewingAttachments] = useState<Transaction | null>(null);

  const [scanResult, setScanResult] = useState<{ 
    date: string; 
    trades: ExtractedTrade[];
    otherCharges: number;
  } | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const uploadInputRef = useRef<HTMLInputElement>(null);
  const currency = state.profile.currency;

  const initialFormState = {
    type: 'Expense' as TransactionType,
    amount: '', 
    nature: natures[0] || '',
    description: '',
    accountId: '',
    date: new Date().toISOString().split('T')[0],
    isShared: false,
    includeSelf: true,
    numberOfPeople: 2,
    splitType: 'equal' as SplitType,
    participants: [] as Participant[],
    ownerId: '',
    isin: '',
    stockName: '',
    units: '',
    billingPeriod: '',
    estimatedLife: '1' 
  };

  const [formData, setFormData] = useState(initialFormState);

  const allAccounts = useMemo(() => {
    const banks = (state.banks || []).map(b => ({ id: b.id, name: b.name, type: 'bank' as const, ownerId: b.ownerId }));
    const cards = (state.cards || []).map(c => ({ id: c.id, name: c.lenderName, type: 'card' as const, ownerId: c.ownerId }));
    const liabilities = (state.liabilities || []).filter(l => l.type === 'Debt').map(l => ({ id: l.id, name: l.name, type: 'liability' as const, ownerId: l.ownerId }));
    const wallets = (state.wallets || []).map(w => ({ id: w.id, name: w.name, type: 'wallet' as const, ownerId: w.ownerId }));
    return [...banks, ...cards, ...wallets, ...liabilities];
  }, [state.banks, state.cards, state.wallets, state.liabilities]);

  useEffect(() => {
    if (scanResult) {
      const zerodha = allAccounts.find(a => a.name.toLowerCase().includes('zerodha') && (a.ownerId === importOwnerId || !a.ownerId));
      setImportAccountId(zerodha?.id || 'equity-protocol');
    }
  }, [scanResult, importOwnerId, allAccounts]);

  const fileToBase64 = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.onload = () => resolve((reader.result as string).split(',')[1]);
      reader.onerror = reject;
      reader.readAsDataURL(file);
    });
  };

  const processDocumentWithAI = async (file: File) => {
    // Only process images/pdfs if possible, for now simplistic check
    if (!file.type.startsWith('image/') && file.type !== 'application/pdf') return;

    setIsScanning(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const base64Data = await fileToBase64(file);

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: {
          parts: [
            { inlineData: { mimeType: file.type, data: base64Data } },
            { text: "Analyze this financial document. Extract: netTotal (number), date (YYYY-MM-DD), merchant (string), description (string). If it looks like a stock trade note, extract trades array with scrip, type, units, netTotal." }
          ]
        },
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              netTotal: { type: Type.NUMBER },
              date: { type: Type.STRING },
              merchant: { type: Type.STRING },
              description: { type: Type.STRING },
              trades: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    scrip: { type: Type.STRING },
                    type: { type: Type.STRING },
                    units: { type: Type.NUMBER },
                    netTotal: { type: Type.NUMBER },
                  }
                }
              }
            }
          }
        }
      });

      const text = response.text;
      if (text) {
        const data = JSON.parse(text);
        setFormData(prev => ({
          ...prev,
          amount: data.netTotal ? String(data.netTotal) : prev.amount,
          date: data.date || prev.date,
          description: data.description || (data.merchant ? `Payment to ${data.merchant}` : prev.description),
          nature: (data.trades && data.trades.length > 0) ? 'Investment' : prev.nature
        }));
        // Map simplified AI result to ExtractedTrade structure roughly
        if (data.trades) {
           setScanResult({
             date: data.date,
             otherCharges: 0,
             trades: data.trades.map((t: any) => ({
               scrip: t.scrip,
               type: t.type,
               units: t.units,
               netTotal: t.netTotal,
               grossValue: t.netTotal,
               date: data.date,
               isin: '',
               stt: 0,
               allocatedCharges: 0
             }))
           });
        }
      }
    } catch (e) {
      console.error("AI Scan failed", e);
    } finally {
      setIsScanning(false);
    }
  };

  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      const files = Array.from(e.target.files);
      setPendingFiles(prev => [...prev, ...files]);
      // Auto-scan the first file
      if (files.length > 0) {
        processDocumentWithAI(files[0]);
      }
    }
  };

  const removeFile = (index: number) => {
    setPendingFiles(prev => prev.filter((_, i) => i !== index));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.nature) return;
    const account = allAccounts.find(a => a.id === formData.accountId);
    if (!account) return alert("Select target account.");

    setIsUploading(true);

    // Handle File Uploads
    const uploadedAttachments: TransactionAttachment[] = [];
    if (pendingFiles.length > 0) {
      for (const file of pendingFiles) {
        try {
          const attachment = await uploadToDrive(file as any);
          uploadedAttachments.push(attachment);
        } catch (error) {
          console.error("Upload failed for file", file.name, error);
        }
      }
    }

    const transactionData: Transaction = {
      id: editingId || Math.random().toString(36).substr(2, 9),
      type: formData.type, amount: Number(formData.amount), nature: formData.nature,
      description: formData.description, accountId: formData.accountId, accountType: account.type as any,
      date: formData.date, ownerId: formData.ownerId, isin: formData.isin, stockName: formData.stockName,
      units: formData.units ? Number(formData.units) : undefined, billingPeriod: formData.billingPeriod,
      estimatedLife: Number(formData.estimatedLife), status: 'active', // status will be overridden in FinanceContext logic
      attachments: uploadedAttachments
    };

    if (editingId) updateTransaction(transactionData);
    else addTransaction(transactionData);

    setIsUploading(false);
    setPendingFiles([]);
    setShowModal(false);
  };

  const transactionList = filteredState.transactions || [];

  return (
    <div className="space-y-6 md:space-y-10 animate-in fade-in duration-500 pb-20">
      <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-6 px-4 md:px-0">
        <div>
          <h3 className="text-xl md:text-2xl font-black text-slate-800 tracking-tight uppercase">Audit Ledger</h3>
          <p className="text-[10px] text-slate-400 font-black uppercase tracking-[0.2em] mt-2">Verified Transaction History</p>
        </div>
        <div className="grid grid-cols-2 md:grid-cols-3 lg:flex lg:flex-wrap items-center gap-2 md:gap-3">
          <button onClick={() => setShowModal(true)} className="px-6 py-4 bg-indigo-600 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-xl transition-all">+ New Entry</button>
        </div>
      </div>

      <div className="bg-white rounded-[2.5rem] border border-slate-200 shadow-sm overflow-hidden flex flex-col">
        <div className="overflow-x-auto custom-scrollbar">
          <table className="w-full text-left border-collapse min-w-[800px]">
            <thead className="bg-slate-50/50 text-slate-400 text-[9px] font-black uppercase tracking-[0.3em] border-b border-slate-100">
              <tr>
                <th className="px-8 py-6">Timeline</th>
                <th className="px-8 py-6">Audit Nature</th>
                <th className="px-8 py-6">Entity Claims</th>
                <th className="px-8 py-6 text-right">Settlement</th>
                <th className="px-8 py-6 text-center">Evidence</th>
                <th className="px-8 py-6 text-center">Status</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {transactionList.map(t => (
                <tr key={t.id} className="hover:bg-slate-50/30 transition-colors group">
                  <td className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase tracking-tighter">{t.date}</td>
                  <td className="px-8 py-6">
                    <p className="text-sm font-black text-slate-800 tracking-tight">{t.description || t.nature}</p>
                    <span className="text-[9px] text-slate-400 font-black uppercase tracking-widest mt-1">{t.nature}</span>
                  </td>
                  <td className="px-8 py-6"><span className="text-[10px] font-black text-slate-600 bg-slate-100/50 border border-slate-100 px-3 py-1.5 rounded-xl uppercase tracking-widest">{t.ownerId ? (familyMembers.find(m => m.id === t.ownerId)?.name || 'Member') : 'Me'}</span></td>
                  <td className="px-8 py-6 text-right font-black tracking-tight">
                    <span className={t.type === 'Income' ? 'text-emerald-600' : 'text-rose-500'}>
                      {t.type === 'Income' ? '+' : '-'} {formatCurrency(t.amount, currency)}
                    </span>
                  </td>
                  <td className="px-8 py-6 text-center">
                    {(t.attachments && t.attachments.length > 0) ? (
                      <button onClick={() => setViewingAttachments(t)} className="w-8 h-8 rounded-full bg-indigo-50 text-indigo-600 flex items-center justify-center hover:bg-indigo-100 transition-colors">
                        📎
                      </button>
                    ) : (
                      <span className="text-slate-200 text-lg">•</span>
                    )}
                  </td>
                  <td className="px-8 py-6 text-center">
                    {t.status === 'pending_approval' ? (
                      <div className="inline-flex items-center gap-2 px-3 py-1.5 bg-amber-50 text-amber-600 border border-amber-100 rounded-full animate-pulse">
                         <span className="text-[8px] font-black uppercase tracking-widest">Escrow</span>
                      </div>
                    ) : (
                      <span className="text-[8px] font-black text-emerald-500 uppercase tracking-widest">Verified</span>
                    )}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {showModal && (
        <div className="fixed inset-0 z-50 flex justify-center items-center bg-slate-900/60 backdrop-blur-xl p-4 overflow-y-auto">
          <div className="bg-white w-full max-w-2xl rounded-[3rem] p-8 md:p-12 border border-slate-200 shadow-2xl animate-in zoom-in-95 duration-200">
            <h3 className="text-xl font-black text-slate-800 uppercase tracking-tight mb-10">Record Protocol</h3>
            <form onSubmit={handleSubmit} className="space-y-8">

              <div className="space-y-2">
                <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Capital Flow Direction</label>
                <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
                  {(['Income', 'Expense', 'Asset', 'Liability'] as TransactionType[]).map((tType) => (
                    <button
                      key={tType}
                      type="button"
                      onClick={() => setFormData({ ...formData, type: tType })}
                      className={`py-4 rounded-2xl text-[10px] font-black uppercase tracking-widest border transition-all ${
                        formData.type === tType
                          ? (tType === 'Income' ? 'bg-emerald-600 border-emerald-600 text-white shadow-xl shadow-emerald-100' :
                             tType === 'Expense' ? 'bg-rose-600 border-rose-600 text-white shadow-xl shadow-rose-100' :
                             'bg-slate-800 border-slate-800 text-white shadow-xl shadow-slate-200')
                          : 'bg-slate-50 text-slate-400 border-slate-200 hover:bg-white hover:border-slate-300'
                      }`}
                    >
                      {tType}
                    </button>
                  ))}
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Reporting Entity</label>
                  <select className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-black text-xs cursor-pointer" value={formData.ownerId} onChange={e => setFormData({ ...formData, ownerId: e.target.value })}>
                    <option value="">Me (Primary Vault)</option>
                    {familyMembers.map(m => <option key={m.id} value={m.id}>{m.name}</option>)}
                  </select>
                </div>
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Audit Timeline</label>
                  <input required type="date" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-black text-xs uppercase cursor-pointer" value={formData.date} onChange={e => setFormData({ ...formData, date: e.target.value })} />
                </div>
              </div>

              <div className="space-y-2">
                <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Net Settlement Amount ({currency})</label>
                <div className="relative">
                  <input required type="number" step="any" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-black text-2xl" value={formData.amount} onChange={e => setFormData({ ...formData, amount: e.target.value })} />
                  {isScanning && <div className="absolute right-4 top-1/2 -translate-y-1/2 text-xs font-black text-indigo-500 animate-pulse">AI Scanning...</div>}
                </div>
              </div>

              {formData.ownerId !== '' && (
                <div className="p-4 bg-amber-50 border border-amber-100 rounded-2xl">
                   <p className="text-[9px] font-black text-amber-600 uppercase tracking-widest flex items-center gap-2">
                     ⚠️ Security Notice: Digital Escrow
                   </p>
                   <p className="text-[10px] text-amber-800 mt-1">This transaction will be held in escrow until the selected participant signs off on the entry.</p>
                </div>
              )}

              <div className="space-y-2">
                <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Account Instrument</label>
                <select required className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-black text-xs appearance-none cursor-pointer" value={formData.accountId} onChange={e => setFormData({ ...formData, accountId: e.target.value })}>
                  <option value="">Select Target Account</option>
                  {allAccounts.filter(a => (a.ownerId || '') === (formData.ownerId || '')).map(acc => (<option key={acc.id} value={acc.id}>{acc.name}</option>))}
                </select>
              </div>

              {/* Evidence Upload Section */}
              <div className="space-y-2">
                <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Supporting Evidence (AI Scan)</label>
                <div 
                  className={`border-2 border-dashed rounded-2xl p-6 text-center transition-all ${state.profile.googleDriveConfig?.isConnected ? 'border-slate-200 hover:border-indigo-400 cursor-pointer bg-slate-50' : 'border-slate-100 bg-slate-50 opacity-60 cursor-not-allowed'}`}
                  onClick={() => state.profile.googleDriveConfig?.isConnected && uploadInputRef.current?.click()}
                >
                   {state.profile.googleDriveConfig?.isConnected ? (
                     <>
                        <input type="file" ref={uploadInputRef} className="hidden" multiple onChange={handleFileSelect} />
                        <div className="text-2xl mb-2">☁️</div>
                        <p className="text-[10px] font-black text-slate-600 uppercase tracking-tight">Click to upload & scan</p>
                        <p className="text-[8px] font-bold text-slate-400 uppercase mt-1">
                           {state.profile.googleDriveConfig.linkedEmail} • {state.profile.googleDriveConfig.folderName}
                        </p>
                     </>
                   ) : (
                     <div className="py-2">
                       <div className="text-2xl mb-2 grayscale opacity-50">☁️</div>
                       <p className="text-[10px] font-black text-slate-400 uppercase tracking-tight">Cloud Storage Not Linked</p>
                       <p className="text-[8px] font-bold text-rose-400 uppercase mt-1">Login to Google Drive in Profile to enable uploads</p>
                     </div>
                   )}
                </div>

                {/* File List */}
                {pendingFiles.length > 0 && (
                  <div className="space-y-2 mt-4">
                     {pendingFiles.map((file, idx) => (
                       <div key={idx} className="flex justify-between items-center p-3 bg-white border border-slate-100 rounded-xl">
                          <div className="flex items-center gap-3 overflow-hidden">
                             <div className="w-8 h-8 bg-slate-100 rounded-lg flex items-center justify-center text-xs">📄</div>
                             <p className="text-[10px] font-black text-slate-700 truncate">{file.name}</p>
                          </div>
                          <button type="button" onClick={() => removeFile(idx)} className="text-slate-400 hover:text-rose-500 transition-colors">✕</button>
                       </div>
                     ))}
                  </div>
                )}
              </div>

              <div className="flex gap-4 pt-8">
                <button type="button" onClick={() => setShowModal(false)} className="flex-1 py-5 bg-slate-100 text-slate-500 font-black text-[10px] uppercase rounded-2xl">Abort</button>
                <button type="submit" disabled={isUploading} className="flex-[2] py-5 bg-indigo-600 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-xl flex items-center justify-center gap-2">
                  {isUploading ? <span className="animate-spin">⏳</span> : 'Commit Audit'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Attachment Viewer Modal */}
      {viewingAttachments && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center bg-slate-900/80 backdrop-blur-md p-4">
           <div className="bg-white w-full max-w-md rounded-[2.5rem] p-8 border border-slate-200 shadow-2xl animate-in zoom-in duration-200">
              <div className="flex justify-between items-center mb-6">
                <div>
                  <h3 className="text-lg font-black text-slate-800 uppercase tracking-tight">Digital Evidence</h3>
                  <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mt-1">Stored in Secure Vault</p>
                </div>
                <button onClick={() => setViewingAttachments(null)} className="text-slate-300 hover:text-slate-800 text-2xl font-black">✕</button>
              </div>

              <div className="space-y-3">
                 {viewingAttachments.attachments?.map((att, idx) => (
                   <a 
                     key={idx} 
                     href={att.url} 
                     target="_blank" 
                     rel="noopener noreferrer"
                     className="flex items-center justify-between p-4 bg-slate-50 border border-slate-100 rounded-2xl hover:bg-indigo-50 hover:border-indigo-100 transition-all group"
                   >
                      <div className="flex items-center gap-4 overflow-hidden">
                         <div className="w-10 h-10 bg-white rounded-xl flex items-center justify-center text-lg shadow-sm">📄</div>
                         <div>
                            <p className="text-[10px] font-black text-slate-800 uppercase truncate max-w-[150px]">{att.name}</p>
                            <p className="text-[8px] font-bold text-slate-400 uppercase">{new Date(att.uploadDate).toLocaleDateString()}</p>
                         </div>
                      </div>
                      <span className="text-xs text-slate-300 group-hover:text-indigo-500">↗</span>
                   </a>
                 ))}
                 {(viewingAttachments.attachments || []).length === 0 && <p className="text-center text-[10px] font-black text-slate-400 py-8">No files attached.</p>}
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

export default Transactions;
